          <el-option\r\n                        key=\"between_months\"\r\n                        value=\"between_months\"\r\n                        label=\"Entre meses\"\r\n                    ></el-option>\r\n                    <el-option\r\n                        key=\"date\"\r\n                        value=\"date\"\r\n                        label=\"Por fecha\"\r\n                    ></el-option>\r\n                    <el-option\r\n                        key=\"between_dates\"\r\n                        value=\"between_dates\"\r\n                        label=\"Entre fechas\"\r\n                    ></el-option>\r\n                </el-select>\r\n            </div>\r\n            <template\r\n                v-if=\"\r\n                    form.period === 'month' || form.period === 'between_months'\r\n                \"\r\n            >\r\n                <div class=\"col-md-2\">\r\n                    <label class=\"w-100 control-label\">Mes de</label>\r\n                    <el-date-picker\r\n                        v-model=\"form.month_start\"\r\n                        type=\"month\"\r\n                        class=\"w-100\"\r\n                        @change=\"changeDisabledMonths\"\r\n                        value-format=\"yyyy-MM\"\r\n                        format=\"MM/yyyy\"\r\n                        :clearable=\"false\"\r\n                    ></el-date-picker>\r\n                </div>\r\n            </template>\r\n            <template v-if=\"form.period === 'between_months'\">\r\n                <div class=\"col-md-2\">\r\n                    <label class=\"w-100 control-label\">Mes al</label>\r\n                    <el-date-picker\r\n                        class=\"w-100\"\r\n                        v-model=\"form.month_end\"\r\n                        type=\"month\"\r\n                        :picker-options=\"pickerOptionsMonths\"\r\n                        value-format=\"yyyy-MM\"\r\n                        format=\"MM/yyyy\"\r\n                        :clearable=\"false\"\r\n                    ></el-date-picker>\r\n                </div>\r\n            </template>\r\n            <template\r\n                v-if=\"form.period === 'date' || form.period === 'between_dates'\"\r\n            >\r\n                <div class=\"col-md-2\">\r\n                    <label class=\"w-100 control-label\">Fecha del</label>\r\n                    <el-date-picker\r\n                        class=\"w-100\"\r\n                        v-model=\"form.date_start\"\r\n                        type=\"date\"\r\n                        @change=\"changeDisabledDates\"\r\n                        value-format=\"yyyy-MM-dd\"\r\n                        format=\"dd/MM/yyyy\"\r\n                        :clearable=\"false\"\r\n                    ></el-date-picker>\r\n                </div>\r\n            </template>\r\n            <template v-if=\"form.period === 'between_dates'\">\r\n                <div class=\"col-md-2\">\r\n                    <label class=\"w-100 control-label\">Fecha al</label>\r\n                    <el-date-picker\r\n                        class=\"w-100\"\r\n                        v-model=\"form.date_end\"\r\n                        type=\"date\"\r\n                        :picker-options=\"pickerOptionsDates\"\r\n                        value-format=\"yyyy-MM-dd\"\r\n                        format=\"dd/MM/yyyy\"\r\n                        :clearable=\"false\"\r\n                    ></el-date-picker>\r\n                </div>\r\n            </template>\r\n\r\n            <div class=\"col-lg-4 col-md-4\">\r\n                <div class=\"form-group\">\r\n                    <label class=\"w-100 control-label\">\r\n                        Clientes\r\n                    </label>\r\n\r\n                    <el-select\r\n                        class=\"w-100\"\r\n                        v-model=\"form.person_id\"\r\n                        filterable\r\n                        remote\r\n                        popper-class=\"el-select-customers\"\r\n                        clearable\r\n                        placeholder=\"Nombre o número de documento\"\r\n                        :remote-method=\"searchRemotePersons\"\r\n                        :loading=\"loading_search\"\r\n                    >\r\n                        <el-option\r\n                            v-for=\"option in persons\"\r\n                            :key=\"option.id\"\r\n                            :value=\"option.id\"\r\n                            :label=\"option.description\"\r\n                        ></el-option>\r\n                    </el-select>\r\n                </div>\r\n            </div>\r\n\r\n            <div class=\"d-flex\" style=\"margin-top:29px\">\r\n                <el-button\r\n                    class=\"submit\"\r\n                    type=\"primary\"\r\n                    @click.prevent=\"getRecordsByFilter\"\r\n                    :loading=\"loading_submit\"\r\n                    icon=\"el-icon-search\"\r\n                    >Buscar</el-button\r\n                >\r\n\r\n                <template\r\n                    v-if=\"\r\n                        records.length > 0 &&\r\n                            resource !== 'reports/document-detractions'\r\n                    \"\r\n                >\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"danger\"\r\n                        icon=\"el-icon-tickets\"\r\n                        @click.prevent=\"clickDownload('pdf')\"\r\n                        >Exportar PDF</el-button\r\n                    >\r\n\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"success\"\r\n                        @click.prevent=\"clickDownload('excel')\"\r\n                        ><i class=\"fa fa-file-excel\"></i> Exportal\r\n                        Excel</el-button\r\n                    >\r\n                    <el-button class=\"submit\" @click.prevent=\"clickOpenWhatsapp\"\r\n                        ><i class=\"fa fa-whatsapp\"></i> Enviar\r\n                        whatsapp</el-button\r\n                    >\r\n                </template>\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <table\r\n                class=\"table table-responsive table-striped \r\n        \"\r\n            >\r\n                <thead>\r\n                    <tr>\r\n                        <th>#</th>\r\n                        <th class=\"text-center\">N/V</th>\r\n                        <th class=\"text-center\">Fecha de emisión</th>\r\n                        <th class=\"text-center\">DNI</th>\r\n                        <th class=\"text-center\">Nombres</th>\r\n                        <th class=\"text-center\">N° Cuotas Vencidas</th>\r\n                        <th class=\"text-end\">Fecha de cobro</th>\r\n                        <th class=\"text-end\">Monto</th>\r\n                        <th class=\"text-end\">Días de atraso</th>\r\n                        <th class=\"text-end\">Acciones</th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(row, idx) in records\" :key=\"idx\">\r\n                        <td>{{ customIndex(idx) }}</td>\r\n\r\n                        <td class=\"text-center\">{{ row.number }}</td>\r\n                        <td class=\"text-center\">{{ row.date_of_issue }}</td>\r\n                        <td class=\"text-center\">{{ row.customer.number }}</td>\r\n                        <td class=\"text-center\">{{ row.customer.name }}</td>\r\n                        <td class=\"text-center\">{{ row.dues }}</td>\r\n                        <td class=\"text-end\">{{ row.date_of_due }}</td>\r\n                        <td class=\"text-end\">{{ row.amount_due }}</td>\r\n                        <td class=\"text-end\">{{ row.differenc_days }}</td>\r\n                        <td class=\"text-center\">\r\n                            <template v-if=\"row.is_credit\">\r\n                                <el-tooltip\r\n                                    class=\"item\"\r\n                                    effect=\"dark\"\r\n                                    content=\"Registrar Pagos\"\r\n                                    placement=\"bottom-end\"\r\n                                >\r\n                                    <button\r\n                                        type=\"button\"\r\n                                        class=\"btn waves-effect waves-light btn-sm btn-primary\"\r\n                                        v-if=\"row.state_type_id != '11'\"\r\n                                        @click.prevent=\"clickPayment(row.id)\"\r\n                                    >\r\n                                        <i class=\"fas fa-money-bill-alt\"></i>\r\n                                    </button>\r\n                                </el-tooltip>\r\n\r\n                                <el-tooltip\r\n                                    class=\"item\"\r\n                                    effect=\"dark\"\r\n                                    content=\"Imprimir Contrato\"\r\n                                    placement=\"bottom-end\"\r\n                                >\r\n                                    <button\r\n                                        type=\"button\"\r\n                                        class=\"btn waves-effect waves-light btn-sm btn-info\"\r\n                                        @click.prevent=\"clickContract(row.id)\"\r\n                                    >\r\n                                        <i class=\"fas fa-file-alt\"></i>\r\n                                    </button>\r\n                                </el-tooltip>\r\n                                <el-tooltip\r\n                                    class=\"item\"\r\n                                    effect=\"dark\"\r\n                                    content=\"Imprimir Cronograma de Pagos\"\r\n                                    placement=\"bottom-end\"\r\n                                >\r\n                                    <button\r\n                                        type=\"button\"\r\n                                        class=\"btn waves-effect waves-light btn-sm btn-success\"\r\n                                        @click.prevent=\"clickSchedule(row.id)\"\r\n                                    >\r\n                                        <i class=\"fas fa-file-alt\"></i>\r\n                                    </button>\r\n                                </el-tooltip>\r\n                            </template>\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n        </div>\r\n\r\n        <div>\r\n            <el-pagination\r\n                @current-change=\"getRecords\"\r\n                layout=\"total, prev, pager, next\"\r\n                :total=\"pagination.total\"\r\n                :current-page.sync=\"pagination.current_page\"\r\n                :page-size=\"pagination.per_page\"\r\n            >\r\n            </el-pagination>\r\n        </div>\r\n        <whatsapp-form-report\r\n            :message.sync=\"messageReport\"\r\n            :resource=\"resourceReport\"\r\n            :showWhatsappForm.sync=\"showWhatsappForm\"\r\n        >\r\n        </whatsapp-form-report>\r\n        <sale-note-payments\r\n            :showDialog.sync=\"showDialogPayments\"\r\n            :documentId=\"recordId\"\r\n        ></sale-note-payments>\r\n\r\n        <sale-note-generate\r\n            :showDialog.sync=\"showDialogGenerate\"\r\n            :recordId=\"recordId\"\r\n            :showGenerate=\"true\"\r\n            :showClose=\"false\"\r\n        ></sale-note-generate>\r\n        <sale-note-detail\r\n            :number=\"currentNumber\"\r\n            :saleNoteId=\"recordId\"\r\n            :showDialog.sync=\"showDialogDetail\"\r\n            :boxes=\"boxes\"\r\n        >\r\n        </sale-note-detail>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport SaleNotePayments from \"../../../../../../../../resources/js/views/sale_notes/partials/payments.vue\";\r\nimport SaleNoteGenerate from \"../../../../../../../../resources/js/views/sale_notes/partials/option_documents\";\r\nimport SaleNoteDetail from \"../../../../../../../../resources/js/views/sale_notes/partials/detail.vue\";\r\nimport queryString from \"query-string\";\r\nimport WhatsappFormReport from \"../../../../../../../../resources/js/components/WhatsappModalReports.vue\";\r\n\r\nexport default {\r\n    components: {\r\n        WhatsappFormReport,\r\n        SaleNotePayments,\r\n        SaleNoteGenerate,\r\n        SaleNoteDetail\r\n    },\r\n    props: [\"showDialog\"],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            showWhatsappForm: false,\r\n            messageReport: \"\",\r\n            resourceReport: \"\",\r\n            loading_search: false,\r\n            pickerOptionsDates: {\r\n                disabledDate: time => {\r\n                    time = moment(time).format(\"YYYY-MM-DD\");\r\n                    return this.form.date_start > time;\r\n                }\r\n            },\r\n            pickerOptionsMonths: {\r\n                disabledDate: time => {\r\n                    time = moment(time).format(\"YYYY-MM\");\r\n                    return this.form.month_start > time;\r\n                }\r\n            },\r\n            resource: \"reports/credits\",\r\n            loading: false,\r\n            pagination: {},\r\n            records: [],\r\n            form: {},\r\n            persons: [],\r\n            saleNotesNewId: null,\r\n            showDialogOptions: false,\r\n            recordId: null,\r\n            currentNumber: null,\r\n            boxes: [],\r\n            showDialogDetail: false,\r\n            showDialogGenerate: false,\r\n            showDialogPayments: false\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.$eventHub.$on(\"reloadData\", () => {\r\n            this.getRecords();\r\n        });\r\n    },\r\n    methods: {\r\n        clickDetail(record) {\r\n            this.recordId = record.id;\r\n            this.currentNumber = record.full_number;\r\n            this.boxes = record.boxes;\r\n            this.showDialogDetail = true;\r\n        },\r\n        clickGenerate(recordId) {\r\n            this.recordId = recordId;\r\n            this.showDialogGenerate = true;\r\n        },\r\n        clickPayment(recordId) {\r\n            this.recordId = recordId;\r\n            this.showDialogPayments = true;\r\n        },\r\n        clickSchedule(recordId) {\r\n            window.open(`/sale-notes/schedule/${recordId}`, \"_blank\");\r\n        },\r\n        clickContract(recordId) {\r\n            window.open(`/sale-notes/contract/${recordId}`, \"_blank\");\r\n        },\r\n        clickCreate(id = \"\") {\r\n            location.href = `/${this.resource}/create/${id}`;\r\n        },\r\n        initForm() {\r\n            this.form = {\r\n                establishment_id: null,\r\n                person_id: null,\r\n                type_person: null,\r\n                document_type_id: null,\r\n                period: \"month\",\r\n                date_start: moment().format(\"YYYY-MM-DD\"),\r\n                date_end: moment().format(\"YYYY-MM-DD\"),\r\n                month_start: moment().format(\"YYYY-MM\"),\r\n                month_end: moment().format(\"YYYY-MM\"),\r\n                seller_id: null,\r\n                state_type_id: null,\r\n                typeresult: \"Detallado\"\r\n            };\r\n        },\r\n        changePeriod() {\r\n            if (this.form.period === \"month\") {\r\n                this.form.month_start = moment().format(\"YYYY-MM\");\r\n                this.form.month_end = moment().format(\"YYYY-MM\");\r\n            }\r\n            if (this.form.period === \"between_months\") {\r\n                this.form.month_start = moment()\r\n                    .startOf(\"year\")\r\n                    .format(\"YYYY-MM\"); //'2019-01';\r\n                this.form.month_end = moment()\r\n                    .endOf(\"year\")\r\n                    .format(\"YYYY-MM\");\r\n            }\r\n            if (this.form.period === \"date\") {\r\n                this.form.date_start = moment().format(\"YYYY-MM-DD\");\r\n                this.form.date_end = moment().format(\"YYYY-MM-DD\");\r\n            }\r\n            if (this.form.period === \"between_dates\") {\r\n                this.form.date_start = moment()\r\n                    .startOf(\"month\")\r\n                    .format(\"YYYY-MM-DD\");\r\n                this.form.date_end = moment()\r\n                    .endOf(\"month\")\r\n                    .format(\"YYYY-MM-DD\");\r\n            }\r\n            // this.loadAll();\r\n        },\r\n        clickOpenWhatsapp() {\r\n            let query = queryString.stringify({\r\n                ...this.form\r\n            });\r\n            this.resourceReport = `/${this.resource}/pdf?${query}`;\r\n            this.messageReport = `Reporte de creditos a la fecha ${moment().format(\r\n                \"DD-MM-YYYY\"\r\n            )}`;\r\n            this.showWhatsappForm = true;\r\n        },\r\n        clickDownload(type) {\r\n            let query = queryString.stringify({\r\n                ...this.form\r\n            });\r\n            window.open(`/${this.resource}/${type}/?${query}`, \"_blank\");\r\n        },\r\n        searchRemotePersons(input) {\r\n            if (input.length > 0) {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}`;\r\n\r\n                this.form.type_person = \"customers\";\r\n\r\n                this.$http\r\n                    .get(\r\n                        `/reports/data-table/persons/${this.form.type_person}?${parameters}`\r\n                    )\r\n                    .then(response => {\r\n                        this.persons = response.data.persons;\r\n                        this.loading_search = false;\r\n\r\n                        if (this.persons.length == 0) {\r\n                            this.filterPersons();\r\n                        }\r\n                    });\r\n            } else {\r\n                this.filterPersons();\r\n            }\r\n        },\r\n        async getRecordsByFilter() {\r\n            this.loading_submit = await true;\r\n            await this.getRecords();\r\n            this.loading_submit = await false;\r\n        },\r\n        filterPersons() {\r\n            this.persons = this.all_persons;\r\n        },\r\n        searchRemotePersons(input) {\r\n            if (input.length > 0) {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}`;\r\n\r\n                this.form.type_person = \"customers\";\r\n\r\n                this.$http\r\n                    .get(\r\n                        `/reports/data-table/persons/${this.form.type_person}?${parameters}`\r\n                    )\r\n                    .then(response => {\r\n                        this.persons = response.data.persons;\r\n                        this.loading_search = false;\r\n\r\n                        if (this.persons.length == 0) {\r\n                            this.filterPersons();\r\n                        }\r\n                    });\r\n            } else {\r\n                this.filterPersons();\r\n            }\r\n        },\r\n        changeDisabledMonths() {\r\n            if (this.form.month_end < this.form.month_start) {\r\n                this.form.month_end = this.form.month_start;\r\n            }\r\n            // this.loadAll();\r\n        },\r\n        customIndex(index) {\r\n            return (\r\n                this.pagination.per_page * (this.pagination.current_page - 1) +\r\n                index +\r\n                1\r\n            );\r\n        },\r\n        open() {\r\n            this.getRecords();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        getRecords() {\r\n            this.loading = true;\r\n            this.$http\r\n                .get(`/${this.resource}/records?${this.getQueryParameters()}`)\r\n                .then(response => {\r\n                    this.records = response.data.data;\r\n                    //sort records by dues property (int) in descending order\r\n                    this.records.sort(function(a, b) {\r\n                        return b.dues - a.dues;\r\n                    });\r\n\r\n                    this.pagination = response.data.meta;\r\n                    this.pagination.per_page = parseInt(\r\n                        response.data.meta.per_page\r\n                    );\r\n                    this.loading = false;\r\n                });\r\n        },\r\n        getQueryParameters() {\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                limit: this.limit,\r\n                ...this.form\r\n            });\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/credits_list.vue","<template>\r\n    <el-dialog\r\n        @close=\"close\"\r\n        @open=\"open\"\r\n        append-to-body\r\n        width=\"40%\"\r\n        title=\"Enviar reporte por whatsapp\"\r\n        :visible=\"showWhatsappForm\"\r\n    >\r\n        <div class=\"p-3\" v-loading=\"loading\" element-loading-text=\"Enviando..\">\r\n            <label for=\"\">Número</label>\r\n            <el-input v-model=\"number\" style=\"width:100%\"></el-input>\r\n            <div class=\"d-flex justify-content-end p-1\">\r\n                <!-- <el-button @click=\"sendWhatsapp\">Enviar</el-button> -->\r\n                <el-button @click=\"send\">Enviar</el-button>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"resource\", \"message\", \"showWhatsappForm\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            number: null,\r\n            configuration: {}\r\n        };\r\n    },\r\n    async created() {\r\n        this.socketWhatsappConfig();\r\n        await this.getConfiguration();\r\n    },\r\n\r\n    methods: {\r\n        async send() {\r\n            if (this.sender == \"sdrimsac\") {\r\n                await this.sendWhatsapp();\r\n            } else {\r\n                await this.sendFile();\r\n            }\r\n        },\r\n        async getConfiguration() {\r\n            try {\r\n                const response = await this.$http(\"/configurations/record\");\r\n                const {\r\n                    data: { data }\r\n                } = response;\r\n                this.configuration = data;\r\n            } catch (e) {\r\n                this.$toast.error(\"No se pudo obtener la configuración\");\r\n            }\r\n        },\r\n        open() {},\r\n        socketWhatsappConfig() {\r\n            let hostName = window.location.hostname;\r\n            let url = `https://${hostName}`;\r\n            this.sender = hostName\r\n                .replace(/https?\\:\\/\\//, \"\")\r\n                .replace(\"/\", \"\")\r\n                .split(\".\")\r\n                .join(\"\");\r\n            try {\r\n                this.socket = io.connect(this.$socketUrl);\r\n            } catch (e) {\r\n                console.log(e);\r\n            }\r\n            this.socket.on(\"ready\", message => {\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"authenticated\", ({ message, sender }) => {\r\n                this.sender = sender;\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"connected\", ({ message }) => {\r\n                this.$message.success(message);\r\n\r\n                this.socket.emit(\"getStatus\", url);\r\n            });\r\n            this.socket.on(\"setStatus\", ({ status, sender }) => {\r\n                if (!status) {\r\n                    this.sender = \"sdrimsac\";\r\n                    this.$message.warning(\"Sesión iniciada con SDRIMSAC\");\r\n                } else {\r\n                    this.sender = sender;\r\n                    this.$message.success(\"Whatsapp Listo!\");\r\n                }\r\n            });\r\n            //MessageResponse\r\n            this.socket.on(\"MessageResponse\", ({ success, message }) => {\r\n                if (success) {\r\n                    this.$message.success(message);\r\n                } else {\r\n                    this.$message.error(message);\r\n                }\r\n            });\r\n        },\r\n        async getBase64FromUrl(url) {\r\n            const data = await fetch(url);\r\n            const blob = await data.blob();\r\n            return new Promise(resolve => {\r\n                const reader = new FileReader();\r\n                reader.readAsDataURL(blob);\r\n                reader.onloadend = () => {\r\n                    const base64data = reader.result;\r\n                    resolve(base64data);\r\n                };\r\n            });\r\n        },\r\n        async sendFile() {\r\n            try {\r\n                if (\r\n                    !this.number ||\r\n                    this.number.length != 9 ||\r\n                    isNaN(this.number)\r\n                ) {\r\n                    return this.$toast.error(\"Ingrese un número válido\");\r\n                }\r\n                this.loading = true;\r\n                console.log(this.resource);\r\n                let b64 = await this.getBase64FromUrl(this.resource);\r\n                b64 = b64.split(\",\")[1];\r\n                this.socket.emit(\"sendFile\", {\r\n                    file: b64,\r\n                    name: `${this.message.split(\" \").join(\"-\")}.pdf`,\r\n                    number: `51${this.number}`,\r\n                    sender: this.sender\r\n                });\r\n                this.$toast.success(\"Se envió el mensaje\");\r\n            } catch (e) {\r\n                let msg = \"Ocurrió un error\";\r\n\r\n                console.log(e);\r\n                this.$toast.error(msg);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async sendWhatsapp() {\r\n            if (!this.number || this.number.length != 9 || isNaN(this.number)) {\r\n                return this.$toast.error(\"Ingrese un número válido\");\r\n            }\r\n            this.loading = true;\r\n            try {\r\n                const response = await this.$http.post(\"/whatsapp/historial\", {\r\n                    number: this.number,\r\n                    message: this.message,\r\n                    resource: this.resource,\r\n                    file_name: this.message.split(\" \").join(\"-\"),\r\n                    sender: this.sender\r\n                });\r\n\r\n                if (response.status == 200) {\r\n                    this.$toast.success(\"Mensaje enviado\");\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Mensaje no enviado\");\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n                this.close();\r\n            }\r\n        },\r\n        close() {\r\n            this.number = null;\r\n\r\n            this.$emit(\"update:showWhatsappForm\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/components/WhatsappModalReports.vue","<template>\r\n    <el-dialog\r\n        v-loading=\"loading_print\"\r\n        :element-loading-text=\"message\"\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @open=\"create\"\r\n        :close-on-click-modal=\"false\"\r\n        :close-on-press-escape=\"false\"\r\n        :show-close=\"false\"\r\n        append-to-body\r\n    >\r\n        <div class=\"row mb-4\" v-if=\"form.response_message\">\r\n            <div class=\"col-md-12\">\r\n                <el-alert\r\n                    :title=\"form.response_message\"\r\n                    :type=\"form.response_type\"\r\n                    show-icon\r\n                >\r\n                </el-alert>\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <div\r\n                class=\"col-lg-12 col-md-12 col-sm-12 text-center font-weight-bold\"\r\n                v-if=\"!locked_emission.success\"\r\n            >\r\n                <el-alert\r\n                    :title=\"locked_emission.message\"\r\n                    type=\"warning\"\r\n                    show-icon\r\n                >\r\n                </el-alert>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('a4')\"\r\n                >\r\n                    <i class=\"fa fa-file-alt\"></i>\r\n                </button>\r\n                <p>Imprimir A4</p>\r\n            </div>\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('a5')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir A5</p>\r\n            </div>\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('ticket')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir Ticket 80MM</p>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-3 col-md-3 col-sm-12 text-center font-weight-bold mt-3\"\r\n            >\r\n                <button\r\n                    type=\"button\"\r\n                    class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                    @click=\"clickPrint('ticket_50')\"\r\n                >\r\n                    <i class=\"fa fa-receipt\"></i>\r\n                </button>\r\n                <p>Imprimir Ticket 50MM</p>\r\n            </div>\r\n\r\n            <div\r\n                class=\"col-lg-12 col-md-12 col-sm-12 text-center font-weight-bold mt-3\"\r\n                v-if=\"form.image_detraction\"\r\n            >\r\n                <a\r\n                    :href=\"`${this.form.image_detraction}`\"\r\n                    download\r\n                    class=\"text-center font-weight-bold \"\r\n                    >Descargar constancia de pago - detracción</a\r\n                >\r\n            </div>\r\n        </div>\r\n        <!-- <div class=\"row mt-4\">\r\n            <div class=\"col-lg-6 col-md-6 col-sm-12 text-center\">\r\n                <button type=\"button\" class=\"btn btn-lg waves-effect waves-light btn-outline-secondary\" @click=\"clickDownload('a4')\">\r\n                    <i class=\"fa fa-download\"></i>&nbsp;&nbsp;Descargar A4\r\n                </button>\r\n            </div>\r\n            <div class=\"col-lg-6 col-md-6 col-sm-12 text-center\">\r\n                <button type=\"button\" class=\"btn btn-lg waves-effect waves-light btn-outline-secondary\" @click=\"clickDownload('ticket')\">\r\n                    <i class=\"fa fa-download\"></i>&nbsp;&nbsp;Descargar Ticket\r\n                </button>\r\n            </div>\r\n        </div> -->\r\n        <div class=\"row mt-3\">\r\n            <div class=\"col-md-12\">\r\n                <el-input v-model=\"form.customer_email\">\r\n                    <el-button\r\n                        slot=\"append\"\r\n                        icon=\"el-icon-message\"\r\n                        @click=\"clickSendEmail\"\r\n                        :loading=\"loading\"\r\n                        >Enviar</el-button\r\n                    >\r\n                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                ></el-input>\r\n                <small\r\n                    class=\"form-control-feedback\"\r\n                    v-if=\"errors.customer_email\"\r\n                    v-text=\"errors.customer_email[0]\"\r\n                ></small>\r\n            </div>\r\n        </div>\r\n        <div class=\"row mt-3\">\r\n            <div class=\"col-md-12\">\r\n                <el-input v-model=\"form.customer_telephone\">\r\n                    <template slot=\"prepend\">+51</template>\r\n                    <el-button slot=\"append\" @click=\"clickSendWhatsapp\"\r\n                        >Enviar\r\n                        <el-tooltip\r\n                            class=\"item\"\r\n                            effect=\"dark\"\r\n                            content=\"Es necesario tener aperturado Whatsapp web\"\r\n                            placement=\"top-start\"\r\n                        >\r\n                            <i class=\"fab fa-whatsapp\"></i>\r\n                        </el-tooltip>\r\n                    </el-button>\r\n                    <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                ></el-input>\r\n                <small\r\n                    class=\"form-control-feedback\"\r\n                    v-if=\"errors.customer_telephone\"\r\n                    v-text=\"errors.customer_telephone[0]\"\r\n                ></small>\r\n            </div>\r\n        </div>\r\n        <!-- <div class=\"row m-t-10\" >\r\n            <div class=\"col-md-12 text-center\">\r\n                <button type=\"button\" class=\"btn waves-effect waves-light btn-outline-primary\"\r\n                        @click.prevent=\"clickConsultCdr(form.id)\">Consultar CDR</button>\r\n            </div>\r\n        </div> -->\r\n        <span slot=\"footer\" class=\"dialog-footer\">\r\n            <template v-if=\"showClose\">\r\n                <el-button @click=\"clickClose\">Cerrar</el-button>\r\n            </template>\r\n            <template v-else>\r\n                <el-button class=\"list\" @click=\"clickFinalize\"\r\n                    >Ir al listado</el-button\r\n                >\r\n                <el-button type=\"primary\" @click=\"clickNewDocument\"\r\n                    >Nuevo comprobante</el-button\r\n                >\r\n            </template>\r\n        </span>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\r\n        \"company\",\r\n        \"showDialog\",\r\n        \"recordId\",\r\n        \"configuration\",\r\n        \"showClose\",\r\n        \"isContingency\",\r\n        \"generatDispatch\",\r\n        \"dispatchId\",\r\n        \"editDocument\",\r\n        \"print\"\r\n    ],\r\n    data() {\r\n        return {\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"documents\",\r\n            errors: {},\r\n            form: {},\r\n            // company: {},\r\n            locked_emission: {},\r\n            loading_print: false,\r\n            message: \"\",\r\n            sender: null\r\n        };\r\n    },\r\n    async created() {\r\n        console.log(this.company);\r\n        this.initForm();\r\n        this.socketWhatsappConfig();\r\n        // await this.$http.get(`/companies/record`).then(response => {\r\n        //     if (response.data !== \"\") {\r\n        //         this.company = response.data.data;\r\n        //     }\r\n        // });\r\n    },\r\n    mounted() {},\r\n    methods: {\r\n        socketWhatsappConfig() {\r\n            let hostName = window.location.hostname;\r\n            let url = `https://${hostName}`;\r\n            this.sender = hostName\r\n                .replace(/https?\\:\\/\\//, \"\")\r\n                .replace(\"/\", \"\")\r\n                .split(\".\")\r\n                .join(\"\");\r\n            try {\r\n                this.socket = io.connect(this.$socketUrl);\r\n            } catch (e) {\r\n                console.log(e);\r\n            }\r\n            this.socket.on(\"ready\", message => {\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"authenticated\", ({ message, sender }) => {\r\n                this.sender = sender;\r\n                this.showMessage(message);\r\n            });\r\n            this.socket.on(\"connected\", ({ message }) => {\r\n                this.$message.success(message);\r\n\r\n                this.socket.emit(\"getStatus\", url);\r\n            });\r\n            this.socket.on(\"setStatus\", ({ status, sender }) => {\r\n                console.log(sender);\r\n                if (!status) {\r\n                    this.sender = \"sdrimsac\";\r\n                    this.$message.warning(\"Sesión iniciada con SDRIMSAC\");\r\n                } else {\r\n                    this.sender = sender;\r\n                    this.$message.success(\"Whatsapp Listo!\");\r\n                }\r\n            });\r\n            //MessageResponse\r\n        },\r\n        async clickSendWhatsapp() {\r\n            if (this.form.customer_telephone != null) {\r\n                let formWhatsapp = {\r\n                    id: this.recordId,\r\n                    sender: this.sender,\r\n                    document_id: this.recordId,\r\n                    document_type_id: this.form.document_type_id,\r\n                    customer_telephone: this.form.customer_telephone,\r\n                    mensaje:\r\n                        \"Su comprobante de pago electrónico \" +\r\n                        this.form.number +\r\n                        \" de *\" +\r\n                        this.company.name +\r\n                        \"*, ha sido generado correctamente a través del facturador electrónico de *Sdrimsac Solutions*\"\r\n                };\r\n                try {\r\n                    this.loading = true;\r\n                    let response = await this.$http.post(\r\n                        `/whatsapp`,\r\n                        formWhatsapp\r\n                    );\r\n                    if (response.status == 200) {\r\n                        this.$toast.success(\"Mensaje enviado\");\r\n                        this.loading = false;\r\n                    }\r\n                    if (this.configuration.xml_whatsapp) {\r\n                        formWhatsapp.xml = true;\r\n                        response = await this.$http.post(\r\n                            `/whatsapp`,\r\n                            formWhatsapp\r\n                        );\r\n                        if (response.status == 200) {\r\n                            this.$toast.success(\"Mensaje enviado\");\r\n                            this.loading = false;\r\n                        }\r\n                    }\r\n                } catch (e) {\r\n                    console.log(e, \" error\");\r\n                } finally {\r\n                    this.loading = false;\r\n                }\r\n            }\r\n        },\r\n\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                customer_email: null,\r\n                download_pdf: null,\r\n                external_id: null,\r\n                number: null,\r\n                image_detraction: null,\r\n                id: null,\r\n                response_message: null,\r\n                response_type: null,\r\n                customer_telephone: null,\r\n                message_text: null\r\n            };\r\n            this.locked_emission = {\r\n                success: true,\r\n                message: null\r\n            };\r\n        },\r\n        async print_pdf(PrinterName, FileLink) {\r\n            try {\r\n                let config = qz.configs.create(PrinterName, {\r\n                    scaleContent: false\r\n                });\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: FileLink\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n        async create() {\r\n            this.loading_print = true;\r\n            this.message = \"Cargando la información del Comprobante\";\r\n            let printer_directo = null;\r\n            let printer = null;\r\n            let formatoPdf = null;\r\n            await this.$http\r\n                .get(`/${this.resource}/record/${this.recordId}`)\r\n                .then(response => {\r\n                    this.form = response.data.data;\r\n\r\n                    this.titleDialog = \"Comprobante: \" + this.form.number;\r\n                    this.loading_print = false;\r\n                    // }\r\n                    if (this.generatDispatch)\r\n                        window.open(\r\n                            `/dispatches/create/${this.form.id}/i/${this.dispatchId}`\r\n                        );\r\n                });\r\n\r\n            await this.$http\r\n                .get(`/${this.resource}/locked_emission`)\r\n                .then(response => {\r\n                    this.locked_emission = response.data;\r\n                });\r\n        },\r\n        async clickPrintPos(printerName, formatoPdf) {\r\n            try {\r\n                this.message =\r\n                    \"Espere imprimiendo el Comprobante \" + this.form.number;\r\n                this.loading_print = true;\r\n                let config = qz.configs.create(\r\n                    printerName,\r\n                    { scaleContent: false },\r\n                    { jobName: this.form.number }\r\n                );\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: formatoPdf\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n\r\n                this.loading_print = false;\r\n                this.clickClose();\r\n            } catch (e) {\r\n                this.$toast.error(e.message);\r\n            }\r\n        },\r\n        clickPrint(format) {\r\n            // if(this.configuration.print_direct==1){\r\n            //     if(format==\"a4\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.print_a4)\r\n            //     }\r\n            //     if(format==\"a5\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.print_a4)\r\n            //     }\r\n            //     if(format==\"ticket\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.ticket)\r\n            //     }\r\n            //     if(format==\"ticket_50\"){\r\n            //         this.clickPrintPos(this.form.printer,this.form.ticket_50)\r\n            //     }\r\n            //     }else{\r\n            window.open(\r\n                `/print/document/${this.form.external_id}/${format}`,\r\n                \"_blank\"\r\n            );\r\n            //   }\r\n        },\r\n        clickDownloadImage() {\r\n            window.open(`${this.form.image_detraction}`, \"_blank\");\r\n        },\r\n        clickDownload(format) {\r\n            window.open(`${this.form.download_pdf}/${format}`, \"_blank\");\r\n        },\r\n        clickSendEmail() {\r\n            this.loading = true;\r\n            this.$http\r\n                .post(`/${this.resource}/email`, {\r\n                    customer_email: this.form.customer_email,\r\n                    id: this.form.id\r\n                })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(\r\n                            \"El correo fue enviado satisfactoriamente\"\r\n                        );\r\n                    } else {\r\n                        this.$toast.error(\"Error al enviar el correo\");\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        this.$toast.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading = false;\r\n                });\r\n        },\r\n        clickConsultCdr(document_id) {\r\n            this.$http\r\n                .get(`/${this.resource}/consultarcdr/${document_id}`)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    this.$toast.error(error.response.data.message);\r\n                });\r\n        },\r\n        clickFinalize() {\r\n            location.href = this.isContingency\r\n                ? `/contingencies`\r\n                : `/${this.resource}`;\r\n        },\r\n        clickNewDocument() {\r\n            this.clickClose();\r\n        },\r\n        clickClose() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            if (this.editDocument == true) {\r\n                location.href = `/${this.resource}`;\r\n            }\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/documents/partials/options.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        @opened=\"opened\"\r\n        :close-on-click-modal=\"false\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <!-- <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.seller_id }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Vendedor - Asesor\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.seller_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                                popper-class=\"el-select-departments\"\r\n                                dusk=\"department_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_users\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.name\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.seller_id\"\r\n                                v-text=\"errors.seller_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div> -->\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{\r\n                                'has-danger': errors.identity_document_type_id\r\n                            }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Tipo Doc. Identidad\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.identity_document_type_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-identity_document_type\"\r\n                                dusk=\"identity_document_type_id\"\r\n                                @change=\"changeIdentityDocType\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in identity_document_types\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.identity_document_type_id\"\r\n                                v-text=\"errors.identity_document_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.number }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Número\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n\r\n                            <div v-if=\"api_service_token != false\">\r\n                                <x-input-service\r\n                                    :identity_document_type_id=\"\r\n                                        form.identity_document_type_id\r\n                                    \"\r\n                                    v-model=\"form.number\"\r\n                                    @search=\"searchNumber\"\r\n                                ></x-input-service>\r\n                            </div>\r\n                            <div v-else>\r\n                                <el-input\r\n                                    v-model=\"form.number\"\r\n                                    :maxlength=\"maxLength\"\r\n                                    dusk=\"number\"\r\n                                >\r\n                                    <template\r\n                                        v-if=\"\r\n                                            form.identity_document_type_id ===\r\n                                                '6' ||\r\n                                                form.identity_document_type_id ===\r\n                                                    '1'\r\n                                        \"\r\n                                    >\r\n                                        <el-button\r\n                                            type=\"primary\"\r\n                                            slot=\"append\"\r\n                                            :loading=\"loading_search\"\r\n                                            icon=\"el-icon-search\"\r\n                                            @click.prevent=\"searchCustomer\"\r\n                                        >\r\n                                        </el-button>\r\n                                    </template>\r\n                                    <i\r\n                                        slot=\"prefix\"\r\n                                        class=\"el-icon-edit-outline\"\r\n                                    ></i\r\n                                ></el-input>\r\n                            </div>\r\n\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.number\"\r\n                                v-text=\"errors.number[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-input v-model=\"form.name\" dusk=\"name\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.name\"\r\n                                v-text=\"errors.name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.trade_name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre comercial</label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.trade_name\"\r\n                                dusk=\"trade_name\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.trade_name\"\r\n                                v-text=\"errors.trade_name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- <div class=\"row\" v-if=\"type === 'customers'\">\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.person_type_id}\">\r\n                            <label class=\"control-label\">Tipo de cliente</label>\r\n                            <el-select v-model=\"form.person_type_id\" filterable  >\r\n                                <el-option v-for=\"option in person_types\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"text-danger\" v-if=\"errors.person_type_id\" v-text=\"errors.person_type_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div class=\"form-group\"  >\r\n                            <label class=\"control-label\">Comentario</label>\r\n                            <el-input v-model=\"form.comment\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div> -->\r\n\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select\r\n                                v-model=\"form.country_id\"\r\n                                filterable\r\n                                dusk=\"country_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.department_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Departamento</label>\r\n                            <el-select\r\n                                v-model=\"form.department_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                                popper-class=\"el-select-departments\"\r\n                                dusk=\"department_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_departments\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.department_id\"\r\n                                v-text=\"errors.department_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Provincia</label>\r\n                            <el-select\r\n                                v-model=\"form.province_id\"\r\n                                filterable\r\n                                @change=\"filterDistrict\"\r\n                                popper-class=\"el-select-provinces\"\r\n                                dusk=\"province_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in provinces\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.province_id\"\r\n                                v-text=\"errors.province_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Distrito</label>\r\n                            <el-select\r\n                                v-model=\"form.district_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-districts\"\r\n                                dusk=\"district_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in districts\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.district_id\"\r\n                                v-text=\"errors.district_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"form.address\" dusk=\"address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <!-- create a select with options of zones -->\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.client_zone_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Zona</label>\r\n                            <el-select\r\n                                v-model=\"form.client_zone_id\"\r\n                                filterable\r\n                                dusk=\"client_zone_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in zones\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.client_zone_id\"\r\n                                v-text=\"errors.client_zone_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.telephone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"form.telephone\" dusk=\"telephone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.telephone\"\r\n                                v-text=\"errors.telephone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"form.email\" dusk=\"email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\" v-if=\"form.state\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Estado del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.state == 'ACTIVO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\" v-if=\"form.condition\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Condición del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.condition == 'HABIDO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row mt-2\" v-if=\"type === 'suppliers'\">\r\n                    <div class=\"col-md-6 center-el-checkbox\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.perception_agent }\"\r\n                        >\r\n                            <el-checkbox v-model=\"form.perception_agent\"\r\n                                >¿Es agente de percepción?</el-checkbox\r\n                            ><br />\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.perception_agent\"\r\n                                v-text=\"errors.perception_agent[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-md-6\"\r\n                        v-if=\"type === 'suppliers'\"\r\n                        v-show=\"form.perception_agent\"\r\n                    >\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Porcentaje de percepción</label\r\n                            >\r\n\r\n                            <el-input v-model=\"form.percentage_perception\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div\r\n                    class=\"row m-t-10\"\r\n                    v-for=\"(row, index) in form.addresses\"\r\n                    :key=\"index\"\r\n                >\r\n                    <div class=\"col-md-12\">\r\n                        <label class=\"control-label\" v-if=\"index === 0\">\r\n                            Dirección principal\r\n                        </label>\r\n                        <label class=\"control-label\" v-else>\r\n                            Dirección secundaria # {{ index }}\r\n                            <el-button\r\n                                size=\"mini\"\r\n                                icon=\"el-icon-minus\"\r\n                                @click.prevent=\"clickRemoveAddress(index)\"\r\n                                class=\"btn-default-danger\"\r\n                                >Eliminar dirección</el-button\r\n                            >\r\n                        </label>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select v-model=\"row.country_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.location_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader\r\n                                :options=\"locations\"\r\n                                v-model=\"row.location_id\"\r\n                                :clearable=\"true\"\r\n                                filterable\r\n                            ></el-cascader>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.location_id\"\r\n                                v-text=\"errors.location_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"row.address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.phone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"row.phone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.phone\"\r\n                                v-text=\"errors.phone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"row.email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <!-- <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Llegó de</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Cat Vip</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Mensualidad</label>\r\n                        <el-input clearable v-model=\"form.vip_amount\" />\r\n                    </div>\r\n                </div> -->\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport { serviceNumber } from \"../../mixins/functions\";\r\n\r\nexport default {\r\n    mixins: [serviceNumber],\r\n    props: [\r\n        \"worker\",\r\n        \"showDialog\",\r\n        \"type\",\r\n        \"recordId\",\r\n        \"external\",\r\n        \"document_type_id\",\r\n        \"input_person\",\r\n        \"user_id\",\r\n        \"newTech\"\r\n    ],\r\n    data() {\r\n        return {\r\n            zones: [],\r\n            social_medias: [],\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: this.worker ? \"restaurant/worker/persons\" : \"persons\",\r\n            errors: {},\r\n            api_service_token: false,\r\n            form: {},\r\n            countries: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            locations: [],\r\n            person_types: [],\r\n            identity_document_types: [],\r\n            all_users: []\r\n        };\r\n    },\r\n    async created() {\r\n        console.log(this.newTech, \" a\");\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.api_service_token = response.data.api_service_token;\r\n            this.social_medias = response.data.social_media;\r\n            this.all_users = response.data.users;\r\n            this.countries = response.data.countries;\r\n            this.all_departments = response.data.departments;\r\n            this.all_provinces = response.data.provinces;\r\n            this.zones = response.data.zones;\r\n            this.all_districts = response.data.districts;\r\n            this.identity_document_types =\r\n                response.data.identity_document_types;\r\n            this.locations = response.data.locations;\r\n            this.person_types = response.data.person_types;\r\n        });\r\n    },\r\n    computed: {\r\n        maxLength: function() {\r\n            if (this.form.identity_document_type_id === \"6\") {\r\n                return 11;\r\n            }\r\n            if (this.form.identity_document_type_id === \"1\") {\r\n                return 8;\r\n            }\r\n        }\r\n    },\r\n    methods: {\r\n        nuevoMetodo() {\r\n            let admin = this.all_users.find(user => user.type == \"admin\");\r\n            if (admin) {\r\n                this.form.seller_id = admin.id;\r\n            } else {\r\n                if (this.all_users.length != 0) {\r\n                    this.form.seller_id = this.all_users[0].id;\r\n                }\r\n            }\r\n        },\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                type: this.type,\r\n                identity_document_type_id: \"6\",\r\n                number: \"\",\r\n                name: null,\r\n                trade_name: null,\r\n                country_id: \"PE\",\r\n                department_id: null,\r\n                province_id: null,\r\n                district_id: null,\r\n                address: null,\r\n                telephone: null,\r\n                condition: null,\r\n                state: null,\r\n                email: null,\r\n                perception_agent: false,\r\n                percentage_perception: 0,\r\n                person_type_id: null,\r\n                comment: null,\r\n                addresses: [],\r\n                seller_id: null\r\n            };\r\n        },\r\n        async opened() {\r\n            // this.form.seller_id = this.user_id;\r\n            if (this.external && this.input_person) {\r\n                if (\r\n                    this.form.number.length === 8 ||\r\n                    this.form.number.length === 11\r\n                ) {\r\n                    if (this.api_service_token != false) {\r\n                        await this.$eventHub.$emit(\"enableClickSearch\");\r\n                    } else {\r\n                        this.searchCustomer();\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        create() {\r\n            if (this.external) {\r\n                if (this.document_type_id === \"01\") {\r\n                    this.form.identity_document_type_id = \"6\";\r\n                }\r\n                if (this.document_type_id === \"03\") {\r\n                    this.form.identity_document_type_id = \"1\";\r\n                }\r\n\r\n                if (this.input_person) {\r\n                    this.form.identity_document_type_id = this.input_person\r\n                        .identity_document_type_id\r\n                        ? this.input_person.identity_document_type_id\r\n                        : this.form.identity_document_type_id;\r\n                    this.form.number = this.input_person.number\r\n                        ? this.input_person.number\r\n                        : \"\";\r\n                }\r\n            }\r\n\r\n            if (this.type == undefined) {\r\n                this.titleDialog = this.newTech\r\n                    ? \"Nuevo Técnico\"\r\n                    : \"Nuevo Cliente\";\r\n            }\r\n            if (this.type === \"customers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Cliente\"\r\n                    : \"Nuevo Cliente\";\r\n            }\r\n            if (this.type === \"suppliers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Proveedor\"\r\n                    : \"Nuevo Proveedor\";\r\n            }\r\n\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.filterProvinces();\r\n                        this.filterDistricts();\r\n                    });\r\n            }\r\n        },\r\n        clickAddAddress() {\r\n            /* this.form.more_address.push({\r\n                    location_id: [],\r\n                    address: null,\r\n                })*/\r\n\r\n            this.form.addresses.push({\r\n                id: null,\r\n                country_id: \"PE\",\r\n                location_id: [],\r\n                address: null,\r\n                email: null,\r\n                phone: null,\r\n                main: false\r\n            });\r\n        },\r\n        submit() {\r\n            this.nuevoMetodo();\r\n            if (!this.form.seller_id) {\r\n                this.$toast.error(\"Debe seleccionar un asesor\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"6\" &&\r\n                this.form.number.length != 11\r\n            ) {\r\n                this.$toast.error(\"La longitud del RUC debe ser de 11\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"1\" &&\r\n                this.form.number.length != 8\r\n            ) {\r\n                this.$toast.error(\"La longitud del DNI debe ser de 8\");\r\n                return;\r\n            }\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$emit(\"add_customer\", response.data.id);\r\n                        if (this.external) {\r\n                            this.$eventHub.$emit(\r\n                                \"reloadDataPersons\",\r\n                                response.data.id\r\n                            );\r\n                        } else {\r\n                            this.$eventHub.$emit(\"reloadData\");\r\n                        }\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        console.log(error.response.data.errors);\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        changeIdentityDocType() {\r\n            this.recordId == null ? this.setDataDefaultCustomer() : null;\r\n        },\r\n        setDataDefaultCustomer() {\r\n            if (this.form.identity_document_type_id == \"0\") {\r\n                this.form.number = \"99999999\";\r\n                this.form.name = \"Clientes - Varios\";\r\n            } else {\r\n                this.form.number = \"\";\r\n                this.form.name = null;\r\n            }\r\n        },\r\n        close() {\r\n            this.$eventHub.$emit(\"initInputPerson\");\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        },\r\n        searchCustomer() {\r\n            this.searchServiceNumberByType();\r\n        },\r\n\r\n        searchNumber(data) {\r\n            this.form.district_id = data.ubigeo[2];\r\n            this.filterDistricts();\r\n            this.form.name =\r\n                this.form.identity_document_type_id === \"1\"\r\n                    ? data.nombre_completo\r\n                    : data.nombre_o_razon_social;\r\n            this.form.trade_name =\r\n                this.form.identity_document_type_id === \"6\"\r\n                    ? data.nombre_o_razon_social\r\n                    : \"\";\r\n            this.form.location_id = data.ubigeo;\r\n            this.form.department_id = data.ubigeo ? data.ubigeo[0] : null;\r\n            this.form.province_id = data.ubigeo ? data.ubigeo[1] : null;\r\n            this.form.district_id = data.ubigeo ? data.ubigeo[2] : null;\r\n            this.filterProvinces();\r\n            this.filterDistricts();\r\n            this.form.address = data.direccion;\r\n            this.form.condition = data.condicion;\r\n            this.form.state = data.estado;\r\n        },\r\n        clickRemoveAddress(index) {\r\n            this.form.addresses.splice(index, 1);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/persons/form.vue","<template>\r\n    <el-dialog\r\n        v-loading=\"loading\"\r\n        :visible=\"showDialog\"\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        :title=\"`Detalle ${number}`\"\r\n    >\r\n        <div class=\"card\" v-if=\"items.length != 0\">\r\n            <table class=\"table\">\r\n                <thead>\r\n                    <tr>\r\n                        <th>#</th>\r\n                        <th>Descripción</th>\r\n                        <th class=\"text-right\">Cantidad</th>\r\n                        <th class=\"text-right\">Total</th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(data, idx) in items\" :key=\"idx\">\r\n                        <td>{{ idx + 1 }}</td>\r\n                        <td>{{ data.item.description }}</td>\r\n                        <td class=\"text-right\">{{ Number(data.quantity) }}</td>\r\n                        <td class=\"text-right\">\r\n                            {{ Number(data.total).toFixed(2) }}\r\n                        </td>\r\n                    </tr>\r\n                    <td></td>\r\n                    <td></td>\r\n                    <td class=\"text-right\">Total</td>\r\n                    <td class=\"text-right\">{{ totalItems.toFixed(2) }}</td>\r\n                </tbody>\r\n            </table>\r\n            <span class=\"h3 m-2\">Pagos</span>\r\n            <table class=\"table\">\r\n                <thead>\r\n                    <tr>\r\n                        <th>#</th>\r\n                        <th colspan=\"2\">Método</th>\r\n                        <th class=\"text-right\">Monto</th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(data, idx) in boxes\" :key=\"idx\">\r\n                        <td>{{ idx + 1 }}</td>\r\n                        <td colspan=\"2\">{{ data.method }}</td>\r\n\r\n                        <td class=\"text-right\">\r\n                            {{ Number(data.amount).toFixed(2) }}\r\n                        </td>\r\n                    </tr>\r\n                    <tr>\r\n                        <td></td>\r\n                        <td colspan=\"2\">Total</td>\r\n                        <td class=\"text-right\">{{ totalBoxes.toFixed(2) }}</td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n        </div>\r\n        <div v-else>\r\n            <p>Nota de venta sin productos</p>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"saleNoteId\", \"number\", \"boxes\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            items: [],\r\n            totalItems: 0,\r\n            totalBoxes: 0\r\n        };\r\n    },\r\n    methods: {\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        init() {\r\n            this.totalItems = 0;\r\n            this.totalBoxes = 0;\r\n            this.items = [];\r\n        },\r\n        async open() {\r\n            this.init();\r\n            this.boxes.forEach(box => {\r\n                this.totalBoxes += Number(box.amount);\r\n            });\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/sale-notes/items/${this.saleNoteId}`\r\n                );\r\n                const {\r\n                    data: { items }\r\n                } = response;\r\n                this.items = items;\r\n                this.items.forEach(item => {\r\n                    this.totalItems += Number(item.total);\r\n                });\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/sale_notes/partials/detail.vue","<template>\r\n    <div>\r\n        <el-dialog\r\n            :title=\"titleDialog\"\r\n            :visible=\"showDialog\"\r\n            @open=\"create\"\r\n            width=\"50%\"\r\n            :close-on-click-modal=\"false\"\r\n            :close-on-press-escape=\"false\"\r\n            :show-close=\"false\"\r\n        >\r\n            <div class=\"row\" v-loading=\"loading_documents\">\r\n                <div class=\"col-lg-8\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.document_type_id }\"\r\n                    >\r\n                        <label class=\"control-label\">Tipo comprobante</label>\r\n                        <el-select\r\n                            v-model=\"document.document_type_id\"\r\n                            @change=\"changeDocumentType\"\r\n                            popper-class=\"el-select-document_type\"\r\n                            dusk=\"document_type_id\"\r\n                            class=\"border-left rounded-left border-info\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in document_types\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.description\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"text-danger\"\r\n                            v-if=\"errors.document_type_id\"\r\n                            v-text=\"errors.document_type_id[0]\"\r\n                        ></small>\r\n                        <!-- <el-checkbox  v-model=\"generate_dispatch\">Generar Guía Remisión</el-checkbox> -->\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-4\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.series_id }\"\r\n                    >\r\n                        <label class=\"control-label\">Serie</label>\r\n                        <el-select v-model=\"document.series_id\">\r\n                            <el-option\r\n                                v-for=\"option in series\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.number\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"text-danger\"\r\n                            v-if=\"errors.series_id\"\r\n                            v-text=\"errors.series_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-8\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.document_type_id }\"\r\n                    >\r\n                        <label class=\"control-label\"\r\n                            >Cliente\r\n                            <a\r\n                                href=\"#\"\r\n                                class=\"text-primary\"\r\n                                @click.prevent=\"showDialogNewPerson = true\"\r\n                                >[+ Nuevo]</a\r\n                            >\r\n                        </label>\r\n                        <el-select\r\n                            ref=\"cliente\"\r\n                            v-model=\"document.customer_id\"\r\n                            filterable\r\n                            remote\r\n                            class=\"border-left rounded-left border-info\"\r\n                            popper-class=\"el-select-customers\"\r\n                            dusk=\"customer_id\"\r\n                            placeholder=\"Escriba el nombre o número de documento del cliente\"\r\n                            :remote-method=\"searchRemoteCustomers\"\r\n                            @keyup.enter.native=\"keyupCustomer\"\r\n                            :loading=\"loading_search\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in customers\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.name\"\r\n                            ></el-option>\r\n                        </el-select>\r\n\r\n                        <small\r\n                            class=\"text-danger\"\r\n                            v-if=\"errors.document_type_id\"\r\n                            v-text=\"errors.document_type_id[0]\"\r\n                        ></small>\r\n                        <!-- <el-checkbox  v-model=\"generate_dispatch\">Generar Guía Remisión</el-checkbox> -->\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-4\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.operation_type_id }\"\r\n                    >\r\n                        <label class=\"control-label\">Tipo Operación </label>\r\n                        <el-select\r\n                            v-model=\"document.operation_type_id\"\r\n                            @change=\"changeOperationType\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in operation_types\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.description\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.operation_type_id\"\r\n                            v-text=\"errors.operation_type_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-12\" v-if=\"document.items.length > 0\">\r\n                    <div class=\"row mt-2\">\r\n                        <div class=\"col-md-12\">\r\n                            <h6>Detalle</h6>\r\n                            <div class=\"table-responsive\">\r\n                                <table class=\"table\" width=\"100%\">\r\n                                    <thead>\r\n                                        <tr>\r\n                                            <th>#</th>\r\n                                            <th>Cantidad</th>\r\n                                            <th>producto</th>\r\n                                            <th>Precio</th>\r\n                                            <th>Importe</th>\r\n                                        </tr>\r\n                                    </thead>\r\n                                    <tbody>\r\n                                        <tr\r\n                                            v-for=\"(row,\r\n                                            index) in document.items\"\r\n                                            :key=\"index\"\r\n                                        >\r\n                                            <td>\r\n                                                <button\r\n                                                    type=\"button\"\r\n                                                    class=\"btn btn-sm btn-danger\"\r\n                                                    @click.prevent=\"\r\n                                                        clickRemoveItem(index)\r\n                                                    \"\r\n                                                >\r\n                                                    <i class=\"fa fa-trash\"></i>\r\n                                                </button>\r\n                                            </td>\r\n                                            <td>{{ row.quantity }}</td>\r\n                                            <td>\r\n                                                {{ row.item.description }}\r\n                                                <br /><small>{{\r\n                                                    row.affectation_igv_type\r\n                                                        .description\r\n                                                }}</small>\r\n                                            </td>\r\n                                            <td class=\"text-center\">\r\n                                                {{ row.item.sale_unit_price }}\r\n                                            </td>\r\n                                            <td class=\"text-end\">\r\n                                                {{\r\n                                                    (\r\n                                                        row.quantity *\r\n                                                        row.item.sale_unit_price\r\n                                                    ).toFixed(2)\r\n                                                }}\r\n                                            </td>\r\n                                        </tr>\r\n                                    </tbody>\r\n                                    <tr></tr>\r\n                                </table>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-12\">\r\n                    <div class=\"form-group\">\r\n                        <label class=\"control-label\">Observaciones</label>\r\n                        <el-input\r\n                            type=\"textarea\"\r\n                            autosize\r\n                            v-model=\"document.additional_information\"\r\n                        >\r\n                            <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i\r\n                        ></el-input>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-lg-8 mt-3\">\r\n                    <div\r\n                        class=\"form-group\"\r\n                        :class=\"{ 'has-danger': errors.dipatch_id }\"\r\n                    >\r\n                        <!-- <label class=\"control-label\">Tipo comprobante</label> -->\r\n                        <el-checkbox v-model=\"generate_dispatch\"\r\n                            >Generar Guía Remisión</el-checkbox\r\n                        >\r\n                        <el-select\r\n                            v-model=\"dispatch_id\"\r\n                            popper-class=\"el-select-document_type\"\r\n                            filterable\r\n                            class=\"border-left rounded-left border-info\"\r\n                            v-if=\"generate_dispatch\"\r\n                        >\r\n                            <el-option\r\n                                v-for=\"option in dispatches\"\r\n                                :key=\"option.id\"\r\n                                :value=\"option.id\"\r\n                                :label=\"option.number_full\"\r\n                            ></el-option>\r\n                        </el-select>\r\n                        <small\r\n                            class=\"text-danger\"\r\n                            v-if=\"errors.dipatch_id\"\r\n                            v-text=\"errors.dipatch_id[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <span slot=\"footer\" class=\"dialog-footer\">\r\n                <el-button @click=\"clickClose\">Cerrar</el-button>\r\n                <el-button\r\n                    class=\"submit\"\r\n                    type=\"primary\"\r\n                    @click=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    v-if=\"flag_generate\"\r\n                    >Generar</el-button\r\n                >\r\n            </span>\r\n\r\n            <document-options\r\n                :showDialog.sync=\"showDialogDocumentOptions\"\r\n                :recordId=\"documentNewId\"\r\n                :generatDispatch=\"generate_dispatch\"\r\n                :dispatchId=\"dispatch_id\"\r\n                :isContingency=\"false\"\r\n                :showClose=\"true\"\r\n            >\r\n            </document-options>\r\n            <person-form\r\n                :showDialog.sync=\"showDialogNewPerson\"\r\n                type=\"customers\"\r\n                :external=\"true\"\r\n                :user_id=\"document.user_id\"\r\n                :input_person=\"input_person\"\r\n                :document_type_id=\"document.document_type_id\"\r\n                @add=\"addRowCliente\"\r\n            >\r\n            </person-form>\r\n        </el-dialog>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport DocumentOptions from \"../../documents/partials/options.vue\";\r\nimport PersonForm from \"../../persons/form.vue\";\r\n\r\nexport default {\r\n    components: { DocumentOptions, PersonForm },\r\n\r\n    props: [\"showDialog\", \"recordId\", \"showClose\", \"showGenerate\"],\r\n    data() {\r\n        return {\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"sale-notes\",\r\n            resource_documents: \"documents\",\r\n            errors: {},\r\n            form: {},\r\n            document: {},\r\n            document_types: [],\r\n            all_document_types: [],\r\n            all_series: [],\r\n            all_customers: [],\r\n            series: [],\r\n            generate: false,\r\n            loading_submit: false,\r\n            loading_documents: false,\r\n            showDialogDocumentOptions: false,\r\n            documentNewId: null,\r\n            flag_generate: true,\r\n            dispatches: [],\r\n            generate_dispatch: false,\r\n            dispatch_id: null,\r\n            loading_search: false,\r\n            has_data_detraction: false,\r\n            customers: [],\r\n            operation_types: [],\r\n            input_person: {},\r\n            showDialogNewPerson: false,\r\n            document_type_03_filter: null\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.initDocument();\r\n    },\r\n    methods: {\r\n        initForm() {\r\n            this.generate = this.showGenerate ? true : false;\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                external_id: null,\r\n                identifier: null,\r\n                date_of_issue: null,\r\n                sale_note: null\r\n            };\r\n            this.generate_dispatch = false;\r\n        },\r\n        async changeOperationType() {\r\n            await this.filterCustomers();\r\n            await this.setDataDetraction();\r\n        },\r\n        clickRemoveItem(index) {\r\n            this.document.items.splice(index, 1);\r\n            this.calculateTotal();\r\n        },\r\n        keyupCustomer() {\r\n            if (this.input_person.number) {\r\n                if (!isNaN(parseInt(this.input_person.number))) {\r\n                    switch (this.input_person.number.length) {\r\n                        case 8:\r\n                            this.input_person.identity_document_type_id = \"1\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n\r\n                        case 11:\r\n                            this.input_person.identity_document_type_id = \"6\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n                        default:\r\n                            this.input_person.identity_document_type_id = \"6\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        reloadDataCustomers(customer_id) {\r\n            this.$http\r\n                .get(`/documents/search/customer/${customer_id}`)\r\n                .then(response => {\r\n                    this.searchRemoteCustomers(response.data.customers.name);\r\n                    //this.customers = response.data.customers\r\n                    this.form.customer_id = customer_id;\r\n                });\r\n        },\r\n\r\n        searchRemoteCustomers(input) {\r\n            if (input.length > 0) {\r\n                // if (input!=\"\") {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}&document_type_id=${this.document.document_type_id}&operation_type_id=${this.document.operation_type_id}&seller_id=${this.document.user_id}`;\r\n                this.$http\r\n                    .get(`/${this.resource}/search/customers?${parameters}`)\r\n                    .then(response => {\r\n                        this.customers = response.data.customers;\r\n                        this.loading_search = false;\r\n                        this.input_person.number = null;\r\n                        if (this.customers.length == 0) {\r\n                            this.input_person.number = input;\r\n                            this.filterCustomers();\r\n                        }\r\n                    });\r\n            } else {\r\n                // this.customers = []\r\n                this.filterCustomers();\r\n\r\n                this.input_person.number = null;\r\n            }\r\n\r\n            // this.filterCustomers()\r\n        },\r\n        addRowCliente(data) {\r\n            //console.log(data)\r\n            this.document.customer_id = data.id;\r\n            this.searchRemoteCustomers(data.number);\r\n        },\r\n        filterCustomers() {\r\n            if (\r\n                this.document.operation_type_id === \"0101\" ||\r\n                this.document.operation_type_id === \"1001\"\r\n            ) {\r\n                if (this.document.document_type_id === \"01\") {\r\n                    let customers_alll = _.filter(this.all_customers, {\r\n                        identity_document_type_id: \"6\",\r\n                        seller_id: this.document.user_id\r\n                    });\r\n                    this.customers = customers_alll;\r\n                } else {\r\n                    if (this.document_type_03_filter) {\r\n                        this.customers = _.filter(this.all_customers, c => {\r\n                            return c.identity_document_type_id !== \"6\";\r\n                        });\r\n                    } else {\r\n                        this.customers = this.all_customers;\r\n                    }\r\n                }\r\n            } else {\r\n                this.customers = this.all_customers;\r\n            }\r\n        },\r\n        initDocument() {\r\n            this.document = {\r\n                afectar_caja: false,\r\n                user_id: null,\r\n                payment_condition_id: \"01\",\r\n                document_type_id: null,\r\n                total_rounded: 0,\r\n                total_payment: 0,\r\n                all_customers: [],\r\n                series_id: null,\r\n                establishment_id: null,\r\n                number: \"#\",\r\n                date_of_issue: null,\r\n                time_of_issue: null,\r\n                customer_id: null,\r\n                currency_type_id: null,\r\n                purchase_order: null,\r\n                exchange_rate_sale: 0,\r\n                total_prepayment: 0,\r\n                total_charge: 0,\r\n                total_discount: 0,\r\n                total_exportation: 0,\r\n                total_free: 0,\r\n                total_taxed: 0,\r\n                total_unaffected: 0,\r\n                total_exonerated: 0,\r\n                total_igv: 0,\r\n                total_base_isc: 0,\r\n                total_isc: 0,\r\n                total_base_other_taxes: 0,\r\n                total_other_taxes: 0,\r\n                total_taxes: 0,\r\n                total_value: 0,\r\n                total: 0,\r\n                operation_type_id: \"1001\",\r\n                prepayment_deduction: false,\r\n                date_of_due: null,\r\n                items: [],\r\n                charges: [],\r\n                discounts: [],\r\n                attributes: [],\r\n                guides: [],\r\n                additional_information: null,\r\n                actions: {\r\n                    format_pdf: \"a4\"\r\n                },\r\n                quotation_id: null,\r\n                sale_note_id: null,\r\n                payments: [],\r\n                hotel: {},\r\n                orden_id: null\r\n            };\r\n        },\r\n        resetDocument() {\r\n            this.generate = this.showGenerate ? true : false;\r\n            this.initDocument();\r\n            this.document.document_type_id =\r\n                this.document_types.length > 0\r\n                    ? this.document_types[0].id\r\n                    : null;\r\n            this.changeDocumentType();\r\n        },\r\n        async submit() {\r\n            let filtrar = this;\r\n            let findCustomer = _.find(this.all_customers, {\r\n                id: this.document.customer_id\r\n            });\r\n            if (\r\n                findCustomer.number.length < 11 &&\r\n                this.document.document_type_id == \"01\"\r\n            ) {\r\n                return this.$toast.error(\r\n                    \"Ingrese un numero de Ruc de 11 digitos valido para emitir Factura \"\r\n                );\r\n            }\r\n            if (\r\n                findCustomer.number.length < 8 &&\r\n                this.document.document_type_id == \"03\"\r\n            ) {\r\n                return this.$toast.error(\r\n                    \"Ingrese un numero de DNI de 8 digitos valido para emitir Boleta \"\r\n                );\r\n            }\r\n            if (this.generate_dispatch) {\r\n                if (!this.dispatch_id) {\r\n                    return this.$toast.error(\r\n                        \"Debe seleccionar una guía base\"\r\n                    );\r\n                }\r\n            }\r\n            this.loading_submit = true;\r\n\r\n            this.document.exchange_rate_sale = 1;\r\n\r\n            await this.$http\r\n                .post(`/${this.resource_documents}`, this.document)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.documentNewId = response.data.data.id;\r\n                        this.showDialogDocumentOptions = true;\r\n                        this.$http\r\n                            .get(`/${this.resource}/changed/${this.form.id}`)\r\n                            .then(() => {\r\n                                this.$eventHub.$emit(\"reloadData\");\r\n                                this.flag_generate = false;\r\n                            });\r\n                        this.resetDocument();\r\n\r\n                        // this.clickClose();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        this.$toast.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        async setDataDetraction() {\r\n            if (this.document.operation_type_id === \"1001\") {\r\n                this.showDialogDocumentDetraction = true;\r\n                let legend = await _.find(this.form.legends, { code: \"2006\" });\r\n                if (!legend)\r\n                    this.form.legends.push({\r\n                        code: \"2006\",\r\n                        value: \"Operación sujeta a detracción\"\r\n                    });\r\n                this.form.detraction.bank_account = this.company.detraction_account;\r\n            } else {\r\n                _.remove(this.form.legends, { code: \"2006\" });\r\n                this.document.detraction = {};\r\n            }\r\n        },\r\n        assignDocument() {\r\n            let q = this.form.sale_note;\r\n\r\n            if (q.paid == 1 || q.paid == \"1\") {\r\n                this.document.payment_condition_id = \"01\";\r\n            } else {\r\n                this.document.payment_condition_id = \"02\";\r\n            }\r\n            for (let index = 0; index < q.items.length; index++) {\r\n                q.items[index].item.is_stock = \"No\";\r\n            }\r\n            this.total_plastic_bag_taxes = 0;\r\n            this.document.user_id = q.user_id;\r\n            (this.document.afectar_caja = false),\r\n                (this.document.establishment_id = q.establishment_id);\r\n            this.document.date_of_issue = moment().format(\"YYYY-MM-DD\"); //q.date_of_issue\r\n            this.document.date_of_due = moment().format(\"YYYY-MM-DD\"); //q.date_of_issue\r\n            this.document.time_of_issue = q.time_of_issue;\r\n            this.document.customer_id = q.customer_id;\r\n            this.document.currency_type_id = q.currency_type_id;\r\n            this.document.purchase_order = null;\r\n            this.document.exchange_rate_sale = q.exchange_rate_sale;\r\n            this.document.total_prepayment = q.total_prepayment;\r\n            this.document.total_charge = q.total_charge;\r\n            this.document.total_discount = q.total_discount;\r\n            this.document.total_exportation = q.total_exportation;\r\n            this.document.total_free = q.total_free;\r\n            this.document.total_taxed = q.total_taxed;\r\n            this.document.total_unaffected = q.total_unaffected;\r\n            this.document.total_exonerated = q.total_exonerated;\r\n            this.document.total_igv = q.total_igv;\r\n            this.document.total_base_isc = q.total_base_isc;\r\n            this.document.total_isc = q.total_isc;\r\n            this.document.total_base_other_taxes = q.total_base_other_taxes;\r\n            this.document.total_other_taxes = q.total_other_taxes;\r\n            this.document.total_taxes = q.total_taxes;\r\n            this.document.total_value = q.total_value;\r\n            this.document.total = q.total;\r\n            this.document.operation_type_id = \"0101\";\r\n            this.document.items = q.items;\r\n            this.document.charges = q.charges;\r\n            this.document.discounts = q.discounts;\r\n            this.document.attributes = [];\r\n            this.document.guides = q.guides;\r\n            this.document.additional_information = null;\r\n            this.document.actions = {\r\n                format_pdf: \"a4\"\r\n            };\r\n            this.document.sale_note_id = this.form.id;\r\n            this.document.payments = q.payments;\r\n        },\r\n        calculateTotal() {\r\n            let total_discount = 0;\r\n            let total_charge = 0;\r\n            let total_exportation = 0;\r\n            let total_taxed = 0;\r\n            let total_exonerated = 0;\r\n            let total_unaffected = 0;\r\n            let total_free = 0;\r\n            let total_igv = 0;\r\n            let total_value = 0;\r\n            let total = 0;\r\n            let total_plastic_bag_taxes = 0;\r\n            this.document.items.forEach(row => {\r\n                total_discount += parseFloat(row.total_discount);\r\n                total_charge += parseFloat(row.total_charge);\r\n\r\n                if (row.affectation_igv_type_id === \"10\") {\r\n                    total_taxed += parseFloat(row.total_value);\r\n                }\r\n                if (row.affectation_igv_type_id === \"20\") {\r\n                    total_exonerated += parseFloat(row.total_value);\r\n                }\r\n                if (row.affectation_igv_type_id === \"30\") {\r\n                    total_unaffected += parseFloat(row.total_value);\r\n                }\r\n                if (row.affectation_igv_type_id === \"40\") {\r\n                    total_exportation += parseFloat(row.total_value);\r\n                }\r\n                if (\r\n                    [\"10\", \"20\", \"30\", \"40\"].indexOf(\r\n                        row.affectation_igv_type_id\r\n                    ) < 0\r\n                ) {\r\n                    total_free += parseFloat(row.total_value);\r\n                }\r\n                if (\r\n                    [\"10\", \"20\", \"30\", \"40\"].indexOf(\r\n                        row.affectation_igv_type_id\r\n                    ) > -1\r\n                ) {\r\n                    total_igv += parseFloat(row.total_igv);\r\n                    total += parseFloat(row.total);\r\n                }\r\n                total_value += parseFloat(row.total_value);\r\n                total_plastic_bag_taxes += parseFloat(\r\n                    row.total_plastic_bag_taxes\r\n                );\r\n            });\r\n\r\n            this.document.total_exportation = _.round(total_exportation, 2);\r\n            this.document.total_taxed = _.round(total_taxed, 2);\r\n            this.document.total_exonerated = _.round(total_exonerated, 2);\r\n            this.document.total_unaffected = _.round(total_unaffected, 2);\r\n            this.document.total_free = _.round(total_free, 2);\r\n            this.document.total_igv = _.round(total_igv, 2);\r\n            this.document.total_value = _.round(total_value, 2);\r\n            this.document.total_taxes = _.round(total_igv, 2);\r\n            this.document.total_plastic_bag_taxes = isNaN(\r\n                parseFloat(total_plastic_bag_taxes)\r\n            )\r\n                ? 0\r\n                : total_plastic_bag_taxes;\r\n            this.document.total = _.round(\r\n                total + this.document.total_plastic_bag_taxes,\r\n                2\r\n            );\r\n            // if (this.enabled_discount_global)\r\n            //     this.discountGlobal()\r\n            // if (this.prepayment_deduction)\r\n            //     this.discountGlobalPrepayment()\r\n            // if (this.form.operation_type_id === '1001')\r\n            //     this.changeDetractionType()\r\n            // this.setTotalDefaultPayment()\r\n            this.document.total_rounded = 0;\r\n            this.document.total_payment = 0;\r\n        },\r\n\r\n        async create() {\r\n            this.loading_documents = true;\r\n            await this.$http\r\n                .get(`/${this.resource}/option/tables`)\r\n                .then(response => {\r\n                    this.all_document_types =\r\n                        response.data.document_types_invoice;\r\n                    this.all_series = response.data.series;\r\n                    this.all_customers = response.data.customers;\r\n                    this.operation_types = response.data.operation_types;\r\n                    this.document_type_03_filter =\r\n                        response.data.document_type_03_filter;\r\n                    //this.document.operation_type_id = (this.operation_types.length > 0) ? this.operation_types[0].id : null;\r\n                    // this.document.document_type_id = (this.document_types.length > 0)?this.document_types[0].id:null;\r\n                    // this.changeDocumentType();\r\n                });\r\n\r\n            await this.$http\r\n                .get(`/${this.resource}/record/${this.recordId}`)\r\n                .then(response => {\r\n                    this.form = response.data.data;\r\n                    this.validateIdentityDocumentType();\r\n                    this.assignDocument();\r\n                    this.titleDialog =\r\n                        \"Nota de venta registrada: \" + this.form.identifier;\r\n                    this.searchRemoteCustomers(\r\n                        response.data.data.sale_note.customer.name\r\n                    );\r\n                    this.document.customer_id =\r\n                        response.data.data.sale_note.customer_id;\r\n                    this.document.user_id =\r\n                        response.data.data.sale_note.user_id;\r\n                });\r\n            // await this.$http\r\n            //     .get(`/${this.resource}/dispatches`)\r\n            //     .then(response => {\r\n            //         this.dispatches = response.data;\r\n            //     });\r\n            this.loading_documents = false;\r\n        },\r\n        changeDocumentType() {\r\n            this.filterSeries();\r\n        },\r\n        async validateIdentityDocumentType() {\r\n            // let identity_document_types = ['0','1']\r\n            // if(identity_document_types.includes(this.form.sale_note.customer.identity_document_type_id)){\r\n\r\n            //     this.document_types = _.filter(this.all_document_types,{'id':'03'})\r\n\r\n            // }else{\r\n            this.document_types = this.all_document_types;\r\n\r\n            // }\r\n\r\n            this.document.document_type_id =\r\n                this.document_types.length > 0\r\n                    ? this.document_types[0].id\r\n                    : null;\r\n            await this.changeDocumentType();\r\n        },\r\n        filterSeries() {\r\n            this.document.series_id = null;\r\n            this.series = _.filter(this.all_series, {\r\n                document_type_id: this.document.document_type_id\r\n            });\r\n            this.document.series_id =\r\n                this.series.length > 0 ? this.series[0].id : null;\r\n        },\r\n        clickFinalize() {\r\n            location.href = `/${this.resource}`;\r\n        },\r\n        clickNewQuotation() {\r\n            this.clickClose();\r\n        },\r\n        clickClose() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n            this.resetDocument();\r\n            this.flag_generate = true;\r\n        },\r\n        clickToPrint() {\r\n            window.open(\r\n                `/downloads/saleNote/sale_note/${this.form.external_id}`,\r\n                \"_blank\"\r\n            );\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/sale_notes/partials/option_documents.vue","<template>\r\n    <el-dialog\r\n        :title=\"title\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"getData\"\r\n        width=\"90%\"\r\n        append-to-body\r\n    >\r\n        <div class=\"form-body\">\r\n            <div class=\"row\">\r\n                <div class=\"col-md-12\" v-if=\"records.length > 0\">\r\n                    <div class=\"table-responsive\">\r\n                        <table class=\"table\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>#</th>\r\n                                    <th>Fecha de pago</th>\r\n                                    <th>Método de pago</th>\r\n                                    <th>Destino</th>\r\n                                    <th>Referencia</th>\r\n                                    <th>Archivo</th>\r\n                                    <th class=\"text-end\">Monto</th>\r\n                                    <th></th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                                <tr\r\n                                    v-for=\"(row, index) in records\"\r\n                                    :key=\"index\"\r\n                                >\r\n                                    <template v-if=\"row.id\">\r\n                                        <td>PAGO-{{ row.id }}</td>\r\n                                        <td>{{ row.date_of_payment }}</td>\r\n                                        <td>\r\n                                            {{\r\n                                                row.payment_method_type_description\r\n                                            }}\r\n                                        </td>\r\n                                        <td>\r\n                                            {{ row.destination_description }}\r\n                                        </td>\r\n                                        <td>{{ row.reference }}</td>\r\n                                        <td class=\"text-center\">\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                v-if=\"row.filename\"\r\n                                                class=\"btn waves-effect waves-light btn-sm btn-primary\"\r\n                                                @click.prevent=\"\r\n                                                    clickDownloadFile(\r\n                                                        row.filename\r\n                                                    )\r\n                                                \"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fas fa-file-download\"\r\n                                                ></i>\r\n                                            </button>\r\n                                        </td>\r\n                                        <td class=\"text-end\">\r\n                                            {{ row.payment }}\r\n                                        </td>\r\n                                        <td\r\n                                            class=\"series-table-actions text-end\"\r\n                                        >\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                @click.prevent=\"\r\n                                                    clickDelete(row.id)\r\n                                                \"\r\n                                            >\r\n                                                Eliminar\r\n                                            </button>\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                class=\"btn waves-effect waves-light btn-sm btn-primary\"\r\n                                                @click.prevent=\"\r\n                                                    ClickPrint(row.receipt_link)\r\n                                                \"\r\n                                            >\r\n                                                Imprimir\r\n                                            </button>\r\n                                            <!--<el-button type=\"danger\" icon=\"el-icon-delete\" plain @click.prevent=\"clickDelete(row.id)\"></el-button>-->\r\n                                        </td>\r\n                                    </template>\r\n                                    <template v-else>\r\n                                        <td></td>\r\n                                        <td>\r\n                                            <div\r\n                                                class=\"form-group mb-0\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        row.errors\r\n                                                            .date_of_payment\r\n                                                }\"\r\n                                            >\r\n                                                <el-date-picker\r\n                                                    v-model=\"\r\n                                                        row.date_of_payment\r\n                                                    \"\r\n                                                    type=\"date\"\r\n                                                    :clearable=\"false\"\r\n                                                    format=\"dd/MM/yyyy\"\r\n                                                    value-format=\"yyyy-MM-dd\"\r\n                                                ></el-date-picker>\r\n                                                <small\r\n                                                    class=\"form-control-feedback\"\r\n                                                    v-if=\"\r\n                                                        row.errors\r\n                                                            .date_of_payment\r\n                                                    \"\r\n                                                    v-text=\"\r\n                                                        row.errors\r\n                                                            .date_of_payment[0]\r\n                                                    \"\r\n                                                ></small>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td>\r\n                                            <div\r\n                                                class=\"form-group mb-0\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        row.errors\r\n                                                            .payment_method_type_id\r\n                                                }\"\r\n                                            >\r\n                                                <el-select\r\n                                                    v-model=\"\r\n                                                        row.payment_method_type_id\r\n                                                    \"\r\n                                                >\r\n                                                    <el-option\r\n                                                        v-for=\"option in payment_method_types\"\r\n                                                        :key=\"option.id\"\r\n                                                        :value=\"option.id\"\r\n                                                        :label=\"\r\n                                                            option.description\r\n                                                        \"\r\n                                                    ></el-option>\r\n                                                </el-select>\r\n                                                <small\r\n                                                    class=\"form-control-feedback\"\r\n                                                    v-if=\"\r\n                                                        row.errors\r\n                                                            .payment_method_type_id\r\n                                                    \"\r\n                                                    v-text=\"\r\n                                                        row.errors\r\n                                                            .payment_method_type_id[0]\r\n                                                    \"\r\n                                                ></small>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td>\r\n                                            <div\r\n                                                class=\"form-group mb-0\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        row.errors\r\n                                                            .payment_destination_id\r\n                                                }\"\r\n                                            >\r\n                                                <el-select\r\n                                                    v-model=\"\r\n                                                        row.payment_destination_id\r\n                                                    \"\r\n                                                    filterable\r\n                                                    :disabled=\"\r\n                                                        row.payment_destination_disabled\r\n                                                    \"\r\n                                                >\r\n                                                    <el-option\r\n                                                        v-for=\"option in payment_destinations\"\r\n                                                        :key=\"option.id\"\r\n                                                        :value=\"option.id\"\r\n                                                        :label=\"\r\n                                                            option.description\r\n                                                        \"\r\n                                                    ></el-option>\r\n                                                </el-select>\r\n                                                <small\r\n                                                    class=\"form-control-feedback\"\r\n                                                    v-if=\"\r\n                                                        row.errors\r\n                                                            .payment_destination_id\r\n                                                    \"\r\n                                                    v-text=\"\r\n                                                        row.errors\r\n                                                            .payment_destination_id[0]\r\n                                                    \"\r\n                                                ></small>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td>\r\n                                            <div\r\n                                                class=\"form-group mb-0\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        row.errors.reference\r\n                                                }\"\r\n                                            >\r\n                                                <el-input\r\n                                                    v-model=\"row.reference\"\r\n                                                >\r\n                                                    <i\r\n                                                        slot=\"prefix\"\r\n                                                        class=\"el-icon-edit-outline\"\r\n                                                    ></i\r\n                                                ></el-input>\r\n                                                <small\r\n                                                    class=\"form-control-feedback\"\r\n                                                    v-if=\"row.errors.reference\"\r\n                                                    v-text=\"\r\n                                                        row.errors.reference[0]\r\n                                                    \"\r\n                                                ></small>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td>\r\n                                            <div class=\"form-group mb-0\">\r\n                                                <el-upload\r\n                                                    :data=\"{ index: index }\"\r\n                                                    :headers=\"headers\"\r\n                                                    :multiple=\"false\"\r\n                                                    :on-remove=\"handleRemove\"\r\n                                                    :action=\"\r\n                                                        `/finances/payment-file/upload`\r\n                                                    \"\r\n                                                    :show-file-list=\"true\"\r\n                                                    :file-list=\"fileList\"\r\n                                                    :on-success=\"onSuccess\"\r\n                                                    :limit=\"1\"\r\n                                                >\r\n                                                    <el-button\r\n                                                        slot=\"trigger\"\r\n                                                        type=\"primary\"\r\n                                                        >Seleccione un\r\n                                                        archivo</el-button\r\n                                                    >\r\n                                                </el-upload>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td>\r\n                                            <div\r\n                                                class=\"form-group mb-0\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        row.errors.payment\r\n                                                }\"\r\n                                            >\r\n                                                <el-input\r\n                                                    :readonly=\"row.blocked\"\r\n                                                    v-model=\"row.payment\"\r\n                                                >\r\n                                                    <i\r\n                                                        slot=\"prefix\"\r\n                                                        class=\"el-icon-edit-outline\"\r\n                                                    ></i\r\n                                                ></el-input>\r\n                                                <small\r\n                                                    class=\"form-control-feedback\"\r\n                                                    v-if=\"row.errors.payment\"\r\n                                                    v-text=\"\r\n                                                        row.errors.payment[0]\r\n                                                    \"\r\n                                                ></small>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td\r\n                                            class=\"series-table-actions text-end\"\r\n                                        >\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                class=\"btn waves-effect waves-light btn-sm btn-info\"\r\n                                                @click.prevent=\"\r\n                                                    clickSubmit(index)\r\n                                                \"\r\n                                            >\r\n                                                <i class=\"fa fa-check\"></i>\r\n                                            </button>\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                @click.prevent=\"\r\n                                                    clickCancel(index)\r\n                                                \"\r\n                                            >\r\n                                                <i class=\"fa fa-trash\"></i>\r\n                                            </button>\r\n                                        </td>\r\n                                    </template>\r\n                                </tr>\r\n                            </tbody>\r\n                            <tfoot v-if=\"!document.paid\">\r\n                                <tr>\r\n                                    <td colspan=\"6\" class=\"text-end\">\r\n                                        TOTAL PAGADO\r\n                                    </td>\r\n                                    <td class=\"text-end\">\r\n                                        {{ document.total_paid }}\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                                <tr>\r\n                                    <td colspan=\"6\" class=\"text-end\">\r\n                                        TOTAL A PAGAR\r\n                                    </td>\r\n                                    <td class=\"text-end\">\r\n                                        {{ document.total }}\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                                <tr v-if=\"cancelCredit\">\r\n                                    <td colspan=\"6\" class=\"text-end\">\r\n                                        DESCUENTO\r\n                                    </td>\r\n                                    <td class=\"text-end\">\r\n                                        <el-input-number\r\n                                            @input=\"calculateDiscountCredit\"\r\n                                            v-model=\"creditDiscount\"\r\n                                        >\r\n                                        </el-input-number>\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                                <tr v-if=\"!cancelCredit\">\r\n                                    <td colspan=\"6\" class=\"text-end\">\r\n                                        PENDIENTE DE PAGO\r\n                                    </td>\r\n                                    <td class=\"text-end\">\r\n                                        {{ document.total_difference }}\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                                <tr v-else>\r\n                                    <td colspan=\"6\" class=\"text-end\">\r\n                                        PENDIENTE DE PAGO\r\n                                    </td>\r\n                                    <td class=\"text-end\">\r\n                                        {{ document.total_difference_credit }}\r\n                                    </td>\r\n                                    <td></td>\r\n                                </tr>\r\n                            </tfoot>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n                <div\r\n                    class=\"col-md-12 text-center pt-2\"\r\n                    v-if=\"showAddButton && document.total_difference > 0\"\r\n                >\r\n                    <el-button\r\n                        type=\"primary\"\r\n                        icon=\"el-icon-plus\"\r\n                        @click=\"clickAddRow\"\r\n                        >Nuevo</el-button\r\n                    >\r\n                    <el-button\r\n                        type=\"primary\"\r\n                        icon=\"el-icon-payment\"\r\n                        @click=\"clickAddCancelCredit\"\r\n                    >\r\n                        Cancelar crédito</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport { deletable } from \"../../../mixins/deletable\";\r\n\r\nexport default {\r\n    props: [\"showDialog\", \"documentId\"],\r\n    mixins: [deletable],\r\n    data() {\r\n        return {\r\n            creditDiscount: 0,\r\n            cancelCredit: false,\r\n            title: null,\r\n            resource: \"sale_note_payments\",\r\n            records: [],\r\n            payment_destinations: [],\r\n            payment_method_types: [],\r\n            headers: headers_token,\r\n            index_file: null,\r\n            fileList: [],\r\n            showAddButton: true,\r\n            document: {},\r\n            receipt_link: null\r\n        };\r\n    },\r\n    async created() {\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.payment_destinations = response.data.payment_destinations;\r\n            this.payment_method_types = response.data.payment_method_types;\r\n            //this.initDocumentTypes()\r\n        });\r\n    },\r\n    methods: {\r\n        calculateDiscountCredit() {\r\n            this.document.total_difference_credit =\r\n                this.document.total_difference - this.creditDiscount;\r\n\r\n            this.records[\r\n                this.records.length - 1\r\n            ].payment = this.document.total_difference_credit;\r\n        },\r\n        clickAddCancelCredit() {\r\n            this.records.push({\r\n                id: null,\r\n                date_of_payment: moment().format(\"YYYY-MM-DD\"),\r\n                payment_method_type_id: null,\r\n                payment_destination_id: null,\r\n                reference: null,\r\n                filename: null,\r\n                temp_path: null,\r\n                payment: 0,\r\n                errors: {},\r\n                loading: false,\r\n                blocked: true\r\n            });\r\n            this.cancelCredit = true;\r\n            this.showAddButton = false;\r\n            this.document.total_difference_credit = this.document.total_difference;\r\n        },\r\n        clickDownloadFile(filename) {\r\n            window.open(\r\n                `/finances/payment-file/download-file/${filename}/sale_notes`,\r\n                \"_blank\"\r\n            );\r\n        },\r\n        ClickPrint(receipt_link) {\r\n            window.open(receipt_link, \"_blank\");\r\n        },\r\n        onSuccess(response, file, fileList) {\r\n            // console.log(response, file, fileList)\r\n            this.fileList = fileList;\r\n\r\n            if (response.success) {\r\n                this.index_file = response.data.index;\r\n                this.records[this.index_file].filename = response.data.filename;\r\n                this.records[this.index_file].temp_path =\r\n                    response.data.temp_path;\r\n            } else {\r\n                this.$toast.error(response.message);\r\n            }\r\n\r\n            // console.log(this.records)\r\n        },\r\n        handleRemove(file, fileList) {\r\n            this.records[this.index_file].filename = null;\r\n            this.records[this.index_file].temp_path = null;\r\n            this.fileList = [];\r\n            this.index_file = null;\r\n        },\r\n        initForm() {\r\n            this.records = [];\r\n            this.fileList = [];\r\n            this.showAddButton = true;\r\n            this.cancelCredit = false;\r\n        },\r\n        async getData() {\r\n            this.initForm();\r\n            await this.$http\r\n                .get(`/${this.resource}/document/${this.documentId}`)\r\n                .then(response => {\r\n                    this.document = response.data;\r\n                    this.title =\r\n                        \"Pagos del comprobante: \" +\r\n                        this.document.series +\r\n                        \"-\" +\r\n                        this.document.number;\r\n                });\r\n            await this.$http\r\n                .get(`/${this.resource}/records/${this.documentId}`)\r\n                .then(response => {\r\n                    this.records = response.data.data;\r\n                });\r\n            this.$eventHub.$emit(\"reloadDataUnpaid\");\r\n        },\r\n        clickAddRow() {\r\n            this.records.push({\r\n                id: null,\r\n                date_of_payment: moment().format(\"YYYY-MM-DD\"),\r\n                payment_method_type_id: null,\r\n                payment_destination_id: null,\r\n                reference: null,\r\n                filename: null,\r\n                temp_path: null,\r\n                payment: 0,\r\n                errors: {},\r\n                loading: false\r\n            });\r\n            this.showAddButton = false;\r\n        },\r\n        clickCancel(index) {\r\n            this.records.splice(index, 1);\r\n            this.showAddButton = true;\r\n            this.cancelCredit = false;\r\n            this.fileList = [];\r\n        },\r\n        clickSubmit(index) {\r\n            if (\r\n                this.records[index].payment >\r\n                parseFloat(this.document.total_difference)\r\n            ) {\r\n                this.$toast.error(\r\n                    \"El monto ingresado supera al monto pendiente de pago, verifique.\"\r\n                );\r\n                return;\r\n            }\r\n\r\n            let paid = false;\r\n            if (\r\n                this.records[index].payment ==\r\n                    parseFloat(this.document.total_difference) ||\r\n                this.cancelCredit\r\n            ) {\r\n                paid = true;\r\n            }\r\n\r\n            let form = {\r\n                id: this.records[index].id,\r\n                sale_note_id: this.documentId,\r\n                date_of_payment: this.records[index].date_of_payment,\r\n                payment_method_type_id: this.records[index]\r\n                    .payment_method_type_id,\r\n                payment_destination_id: this.records[index]\r\n                    .payment_destination_id,\r\n                reference: this.records[index].reference,\r\n                filename: this.records[index].filename,\r\n                temp_path: this.records[index].temp_path,\r\n                payment: this.records[index].payment,\r\n                paid: paid,\r\n                creditDiscount: this.creditDiscount\r\n            };\r\n\r\n            this.$http\r\n                .post(`/${this.resource}`, form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.getData();\r\n                        //this.receipt_link=response.data.pdf\r\n                        //this.ClickPrint()\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        this.showAddButton = true;\r\n                        this.cancelCredit = false;\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.records[index].errors = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                });\r\n        },\r\n        // filterDocumentType(row){\r\n        //\r\n        //     if(row.contingency){\r\n        //         this.document_types = _.filter(this.all_document_types, item => (item.id == '01' || item.id =='03'))\r\n        //         row.document_type_id = (this.document_types.length > 0)?this.document_types[0].id:null\r\n        //     }else{\r\n        //         row.document_type_id = null\r\n        //         this.document_types = this.all_document_types\r\n        //     }\r\n        // },\r\n        // initDocumentTypes(){\r\n        //     this.document_types = (this.all_document_types.length > 0) ? this.all_document_types : []\r\n        // },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            // this.initDocumentTypes()\r\n            // this.initForm()\r\n        },\r\n        clickDelete(id) {\r\n            this.destroy(`/${this.resource}/${id}`).then(\r\n                () => {\r\n                    this.getData();\r\n                    this.$eventHub.$emit(\"reloadData\");\r\n                }\r\n                // this.initDocumentTypes()\r\n            );\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/sale_notes/partials/payments.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      directives: [\n        {\n          name: \"loading\",\n          rawName: \"v-loading\",\n          value: _vm.loading,\n          expression: \"loading\"\n        }\n      ],\n      attrs: {\n        visible: _vm.showDialog,\n        title: \"List de créditos\",\n        width: \"70%\"\n      },\n      on: { open: _vm.open, close: _vm.close }\n    },\n    [\n      _c(\n        \"div\",\n        { staticClass: \"row mt-2\" },\n        [\n          _c(\n            \"div\",\n            { staticClass: \"col-md-3\" },\n            [\n              _c(\"label\", { staticClass: \"control-label\" }, [\n                _vm._v(\"Periodo (Fecha de emisión)\")\n              ]),\n              _vm._v(\" \"),\n              _c(\n                \"el-select\",\n                {\n                  on: { change: _vm.changePeriod },\n                  model: {\n                    value: _vm.form.period,\n                    callback: function($$v) {\n                      _vm.$set(_vm.form, \"period\", $$v)\n                    },\n             