A;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"134.js","sourcesContent":["<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\" v-if=\"warehouses\">\r\n                        <table class=\"table\">\r\n                            <thead>\r\n                                <tr>\r\n                                    <th>#</th>\r\n                                    <th>Ubicación</th>\r\n                                    <th class=\"text-right\">Stock</th>\r\n                                </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                                <tr\r\n                                    v-for=\"(row, index) in warehouses\"\r\n                                    :key=\"index\"\r\n                                >\r\n                                    <th>{{ index + 1 }}</th>\r\n                                    <th>{{ row.warehouse_description }}</th>\r\n                                    <th class=\"text-right\">{{ row.stock }}</th>\r\n                                </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right pt-2\">\r\n                <el-button @click.prevent=\"close()\">Cerrar</el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"warehouses\"],\r\n    data() {\r\n        return {\r\n            showImportDialog: false,\r\n            resource: \"items\",\r\n            recordId: null,\r\n            titleDialog: \"Productos\"\r\n        };\r\n    },\r\n    created() {\r\n        console.log(this.typeUser);\r\n    },\r\n    methods: {\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/components/WarehousesDetail.vue","<template>\r\n    <el-dialog :close-on-click-modal=\"false\"\r\n               :title=\"titleDialog\"\r\n               :visible=\"showDialog\"\r\n               append-to-body\r\n               @close=\"close\"\r\n               @open=\"create\">\r\n        <form autocomplete=\"off\"\r\n              @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div :class=\"{'has-danger': errors.address}\"\r\n                             class=\"form-group\">\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"form.address\"></el-input>\r\n                            <small v-if=\"errors.address\"\r\n                                   class=\"form-control-feedback\"\r\n                                   v-text=\"errors.address[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div :class=\"{'has-danger': errors.location_id}\"\r\n                             class=\"form-group\">\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader v-model=\"form.location_id\"\r\n                                         :options=\"locations\"\r\n                                         filterable></el-cascader>\r\n                            <small v-if=\"errors.location_id\"\r\n                                   class=\"form-control-feedback\"\r\n                                   v-text=\"errors.location_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right mt-4\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button :loading=\"loading_submit\"\r\n                           native-type=\"submit\"\r\n                           type=\"primary\">Guardar\r\n                </el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\nexport default {\r\n    name: 'DispatchOriginAddressForm',\r\n    props: ['showDialog', 'recordId', 'external'],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: 'origin_addresses',\r\n            errors: {},\r\n            form: {},\r\n            locations: []\r\n        }\r\n    },\r\n    async created() {\r\n        await this.getTables();\r\n        this.initForm()\r\n    },\r\n    methods: {\r\n        async getTables() {\r\n            await this.$http.get(`/${this.resource}/tables`)\r\n                .then(response => {\r\n                    this.locations = response.data.locations\r\n                })\r\n        },\r\n        initForm() {\r\n            this.errors = {}\r\n            this.form = {\r\n                id: null,\r\n                address: null,\r\n                location_id: [],\r\n                is_default: false,\r\n                is_active: true,\r\n            }\r\n        },\r\n        async create() {\r\n            this.initForm();\r\n            this.titleDialog = (this.recordId) ? 'Editar dirección de partida' : 'Nueva dirección de partida'\r\n            if (this.recordId) {\r\n                await this.$http.get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data\r\n                    })\r\n            }\r\n        },\r\n        async submit() {\r\n            this.loading_submit = true\r\n            await this.$http.post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success(response.data.message)\r\n                        this.$emit('success', response.data.id)\r\n                        this.close()\r\n                    } else {\r\n                        this.$message.error(response.data.message)\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data\r\n                    } else {\r\n                        console.log(error)\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false\r\n                })\r\n        },\r\n        close() {\r\n            this.$emit('update:showDialog', false)\r\n        },\r\n    }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/OriginAddress/Form.vue","<template>\r\n    <div class=\"card mb-0 pt-2 pt-md-0\">\r\n        <div class=\"card-header bg-primary\">\r\n            <h6 class=\"my-0 text-white\">Nueva Guía de Remisión</h6>\r\n        </div>\r\n        <div class=\"card-body\">\r\n            <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n                <div class=\"form-body\">\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.establishment }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Establecimiento<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.establishment_id\"\r\n                                    @change=\"changeEstablishment\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in establishments\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.establishment\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.establishment[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.series }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Serie<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.series\"\r\n                                    :disabled=\"generalDisabledSeries()\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in series\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.number\"\r\n                                        :value=\"option.number\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.series\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.series[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.date_of_issue }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Fecha de emisión<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-date-picker\r\n                                    v-model=\"form.date_of_issue\"\r\n                                    :clearable=\"false\"\r\n                                    type=\"date\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                ></el-date-picker>\r\n                                <small\r\n                                    v-if=\"errors.date_of_issue\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.date_of_issue[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.date_of_shipping\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Fecha de traslado<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-date-picker\r\n                                    v-model=\"form.date_of_shipping\"\r\n                                    :clearable=\"false\"\r\n                                    type=\"date\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                ></el-date-picker>\r\n                                <small\r\n                                    v-if=\"errors.date_of_shipping\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.date_of_shipping[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-4\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.customer_id }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\">\r\n                                    Cliente<span class=\"text-danger\"> *</span>\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"\r\n                                            showDialogNewPerson = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    >\r\n                                </label>\r\n                                <el-select\r\n                                    v-model=\"form.customer_id\"\r\n                                    :loading=\"loading_search\"\r\n                                    :remote-method=\"searchRemoteCustomers\"\r\n                                    filterable\r\n                                    placeholder=\"Escriba el nombre o número de documento del cliente\"\r\n                                    popper-class=\"el-select-customers\"\r\n                                    remote\r\n                                    @change=\"changeCustomer\"\r\n                                    @keyup.enter.native=\"keyupCustomer\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in customers\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.customer_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.customer_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.transport_mode_type_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Modo de traslado<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.transport_mode_type_id\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in transportModeTypes\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.transport_mode_type_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.transport_mode_type_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-4\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.transfer_reason_type_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Motivo de traslado<span\r\n                                        class=\"text-danger\"\r\n                                    >\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.transfer_reason_type_id\"\r\n                                    @change=\"changeTransferReasonType\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in transferReasonTypes\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.transfer_reason_type_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.transfer_reason_type_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <!-- numero de DAM -->\r\n                        <template v-if=\"form.transfer_reason_type_id === '09'\">\r\n                            <div class=\"col-lg-3\">\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger': errors['related.number']\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Número de documento (DAM)\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            content=\"Formato del campo: XXXX-XX-XXX-XXXXXX, Ejemplo: 0001-01-002-001234\"\r\n                                            effect=\"dark\"\r\n                                            placement=\"top\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                        <span class=\"text-danger\"> *</span>\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.related.number\"\r\n                                        placeholder=\"0001-01-002-001234\"\r\n                                    ></el-input>\r\n                                    <small\r\n                                        v-if=\"errors['related.number']\"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"errors['related.number'][0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-lg-3\">\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors['related.document_type_id']\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Tipo documento relacionado<span\r\n                                            class=\"text-danger\"\r\n                                        >\r\n                                            *</span\r\n                                        ></label\r\n                                    >\r\n                                    <el-select\r\n                                        v-model=\"form.related.document_type_id\"\r\n                                        disabled\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"(option,\r\n                                            idx) in related_document_types\"\r\n                                            :key=\"idx\"\r\n                                            :label=\"option.description\"\r\n                                            :value=\"option.id\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        v-if=\"\r\n                                            errors['related.document_type_id']\r\n                                        \"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"\r\n                                            errors[\r\n                                                'related.document_type_id'\r\n                                            ][0]\r\n                                        \"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                        </template>\r\n                        <div\r\n                            :class=\"\r\n                                form.transfer_reason_type_id === '09'\r\n                                    ? 'col-lg-12'\r\n                                    : 'col-lg-6'\r\n                            \"\r\n                        >\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger':\r\n                                        errors.transfer_reason_description\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Descripción de motivo de traslado</label\r\n                                >\r\n                                <el-input\r\n                                    v-model=\"form.transfer_reason_description\"\r\n                                    :rows=\"3\"\r\n                                    maxlength=\"100\"\r\n                                    placeholder=\"Descripción de motivo de traslado...\"\r\n                                    type=\"textarea\"\r\n                                ></el-input>\r\n                                <small\r\n                                    v-if=\"errors.transfer_reason_description\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"\r\n                                        errors.transfer_reason_description[0]\r\n                                    \"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.unit_type_id }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Unidad de medida<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-select v-model=\"form.unit_type_id\">\r\n                                    <el-option\r\n                                        v-for=\"(option, idx) in unitTypes\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.description\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.unit_type_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.unit_type_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.total_weight }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label w-100\"\r\n                                    >Peso total<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                                <el-input-number\r\n                                    class=\"w-100\"\r\n                                    v-model=\"form.total_weight\"\r\n                                    :max=\"9999999999\"\r\n                                    :min=\"0\"\r\n                                    :precision=\"2\"\r\n                                    :step=\"1\"\r\n                                ></el-input-number>\r\n                                <small\r\n                                    v-if=\"errors.total_weight\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.total_weight[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.packages_number\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label w-100\"\r\n                                    >Número de paquetes\r\n                                    <!-- <span class=\"text-danger\"> *</span> -->\r\n                                </label>\r\n                                <el-input-number\r\n                                    class=\"w-100\"\r\n                                    v-model=\"form.packages_number\"\r\n                                    :max=\"9999999999\"\r\n                                    :min=\"0\"\r\n                                    :precision=\"0\"\r\n                                    :step=\"1\"\r\n                                ></el-input-number>\r\n                                <small\r\n                                    v-if=\"errors.packages_number\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.packages_number[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"col-lg-6\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.observations }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Observaciones</label\r\n                                >\r\n                                <el-input\r\n                                    v-model=\"form.observations\"\r\n                                    :rows=\"3\"\r\n                                    maxlength=\"250\"\r\n                                    placeholder=\"Observaciones...\"\r\n                                    type=\"textarea\"\r\n                                ></el-input>\r\n                                <small\r\n                                    v-if=\"errors.observations\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.observations[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <!-- <div class=\"col-lg-2\" v-if=\"!order_form_id\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.order_form_external\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Orden de pedido\r\n                                    <el-tooltip\r\n                                        class=\"item\"\r\n                                        content=\"Pedidos externos\"\r\n                                        effect=\"dark\"\r\n                                        placement=\"top\"\r\n                                    >\r\n                                        <i class=\"fa fa-info-circle\"></i>\r\n                                    </el-tooltip>\r\n                                </label>\r\n                                <el-input\r\n                                    v-model=\"form.order_form_external\"\r\n                                ></el-input>\r\n                                <small\r\n                                    v-if=\"errors.order_form_external\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.order_form_external[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div> -->\r\n                    </div>\r\n                    <div class=\"row\"></div>\r\n                    <div class=\"row\"></div>\r\n                    <hr />\r\n                    <h4>Datos envío</h4>\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-12\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.origin_address_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Punto de partida<span class=\"text-danger\">\r\n                                        *</span\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"\r\n                                            showDialogOriginAddressForm = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.origin_address_id\"\r\n                                    placeholder=\"Seleccionar punto de partida\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in origin_addresses\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.address\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.origin_address_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.origin_address_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                        <!--                        <div class=\"col-lg-5\">-->\r\n                        <!--                            <div :class=\"{'has-danger': errors.origin}\"-->\r\n                        <!--                                 class=\"form-group\">-->\r\n                        <!--                                <label class=\"control-label\">Ubigeo<span class=\"text-danger\"> *</span></label>-->\r\n                        <!--                                <el-cascader v-model=\"origin.location_id\"-->\r\n                        <!--                                             :options=\"locations\"-->\r\n                        <!--                                             filterable></el-cascader>-->\r\n                        <!--                                <small v-if=\"errors.origin\"-->\r\n                        <!--                                       class=\"form-control-feedback\"-->\r\n                        <!--                                       v-text=\"errors.origin.location_id[0]\"></small>-->\r\n                        <!--                            </div>-->\r\n                        <!--                        </div>-->\r\n                        <!--                        <div class=\"col-lg-7\">-->\r\n                        <!--                            <div :class=\"{'has-danger': errors['origin.address']}\"-->\r\n                        <!--                                 class=\"form-group\">-->\r\n                        <!--                                <label class=\"control-label\">Dirección<span class=\"text-danger\"> *</span></label>-->\r\n                        <!--                                <el-input v-model=\"origin.address\"-->\r\n                        <!--                                          :maxlength=\"100\"-->\r\n                        <!--                                          placeholder=\"Dirección...\"></el-input>-->\r\n                        <!--                                <small v-if=\"errors['origin.address']\"-->\r\n                        <!--                                       class=\"form-control-feedback\"-->\r\n                        <!--                                       v-text=\"errors['origin.address'][0]\"></small>-->\r\n                        <!--                            </div>-->\r\n                        <!--                        </div>-->\r\n                    </div>\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-12\">\r\n                            <div\r\n                                :class=\"{\r\n                                    'has-danger': errors.delivery_address_id\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Punto de llegada<span class=\"text-danger\">\r\n                                        *</span\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form.customer_id\"\r\n                                        @click.prevent=\"\r\n                                            showDialogDeliveryAddressForm = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    ></label\r\n                                >\r\n                                <el-select\r\n                                    v-model=\"form.delivery_address_id\"\r\n                                    placeholder=\"Seleccionar punto de llegada\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"(option,\r\n                                        idx) in delivery_addresses\"\r\n                                        :key=\"idx\"\r\n                                        :label=\"option.address\"\r\n                                        :value=\"option.id\"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <small\r\n                                    v-if=\"errors.delivery_address_id\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"errors.delivery_address_id[0]\"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <hr />\r\n                    <h4>Datos modo de traslado</h4>\r\n                    <div class=\"row\">\r\n                        <template v-if=\"form.transport_mode_type_id === '01'\">\r\n                            <div class=\"col-lg-6\">\r\n                                <label class=\"control-label font-bold\">\r\n                                    Datos del transportista\r\n                                    <a\r\n                                        v-if=\"can_add_new_product\"\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"\r\n                                            showDialogDispatcherForm = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    >\r\n                                </label>\r\n                                <span class=\"text-danger\"> *</span>\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger': errors.dispatcher_id\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <el-select\r\n                                        v-model=\"form.dispatcher_id\"\r\n                                        clearable\r\n                                        placeholder=\"Seleccionar transportista\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"(option, idx) in dispatchers\"\r\n                                            :key=\"idx\"\r\n                                            :label=\"\r\n                                                option.number +\r\n                                                    ' - ' +\r\n                                                    option.name +\r\n                                                    ' - ' +\r\n                                                    option.number_mtc\r\n                                            \"\r\n                                            :value=\"option.id\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        v-if=\"errors.dispatcher_id\"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"errors.dispatcher_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                        </template>\r\n                        <template v-if=\"form.transport_mode_type_id === '02'\">\r\n                            <div class=\"col-lg-6\">\r\n                                <label class=\"control-label\">\r\n                                    Datos del conductor\r\n                                    <a\r\n                                        v-if=\"can_add_new_product\"\r\n                                        href=\"#\"\r\n                                        @click.prevent=\"\r\n                                            showDialogDriverForm = true\r\n                                        \"\r\n                                        >[+ Nuevo]</a\r\n                                    >\r\n                                </label>\r\n                                <span class=\"text-danger\"> *</span>\r\n                                <div\r\n                                    :class=\"{ 'has-danger': errors.driver_id }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <el-select\r\n                                        v-model=\"form.driver_id\"\r\n                                        clearable\r\n                                        placeholder=\"Seleccionar conductor\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"(option, idx) in drivers\"\r\n                                            :key=\"idx\"\r\n                                            :label=\"\r\n                                                option.number +\r\n                                                    ' - ' +\r\n                                                    option.name +\r\n                                                    ' - ' +\r\n                                                    option.license\r\n                                            \"\r\n                                            :value=\"option.id\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        v-if=\"errors.dispacher\"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"errors.dispacher[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-lg-3\">\r\n                                <div\r\n                                    :class=\"{\r\n                                        'has-danger': errors.transport_id\r\n                                    }\"\r\n                                    class=\"form-group\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Datos del vehículo\r\n                                        <a\r\n                                            v-if=\"can_add_new_product\"\r\n                                            href=\"#\"\r\n                                            @click.prevent=\"\r\n                                                showDialogTransportForm = true\r\n                                            \"\r\n                                            >[+ Nuevo]</a\r\n                                        >\r\n                                    </label>\r\n                                    <el-select\r\n                                        v-model=\"form.transport_id\"\r\n                                        clearable\r\n                                        placeholder=\"Seleccionar vehículo\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"(option, idx) in transports\"\r\n                                            :key=\"idx\"\r\n                                            :label=\"\r\n                                                option.plate_number +\r\n                                                    ' - ' +\r\n                                                    option.model +\r\n                                                    ' - ' +\r\n                                                    option.brand\r\n                                            \"\r\n                                            :value=\"option.id\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        v-if=\"errors.transport_id\"\r\n                                        class=\"form-control-feedback\"\r\n                                        v-text=\"errors.transport_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-lg-3\">\r\n                                <div class=\"form-group\">\r\n                                    <label class=\"control-label\"\r\n                                        >N° placa semirremolque</label\r\n                                    >\r\n                                    <el-input\r\n                                        v-model=\"\r\n                                            form.secondary_license_plates\r\n                                                .semitrailer\r\n                                        \"\r\n                                    ></el-input>\r\n                                </div>\r\n                            </div>\r\n                        </template>\r\n                    </div>\r\n                    <hr />\r\n                    <div class=\"col-md-12\">\r\n                        <div class=\"table-responsive\">\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>#</th>\r\n                                        <th class=\"font-weight-bold\">Unidad</th>\r\n                                        <th class=\"font-weight-bold\">\r\n                                            Descripción\r\n                                        </th>\r\n                                        <th class=\"text-right font-weight-bold\">\r\n                                            Cantidad\r\n                                        </th>\r\n                                        <th></th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr\r\n                                        v-for=\"(row, index) in form.items\"\r\n                                        :key=\"index\"\r\n                                    >\r\n                                        <td>{{ index + 1 }}</td>\r\n                                        <td>{{ row.unit_type_id }}</td>\r\n                                        <td\r\n                                            v-html=\"setDescriptionOfItem(row)\"\r\n                                            class=\"text-dark\"\r\n                                        ></td>\r\n                                        <td class=\"text-right\">\r\n                                            {{\r\n                                                getFormatQuantity(row.quantity)\r\n                                            }}\r\n                                        </td>\r\n                                        <!-- <td class=\"text-right\">{{ row.quantity }}</td> -->\r\n                                        <td class=\"text-right\">\r\n                                            <button\r\n                                                class=\"btn waves-effect waves-light btn-xs btn-danger\"\r\n                                                type=\"button\"\r\n                                                @click.prevent=\"\r\n                                                    clickRemoveItem(index)\r\n                                                \"\r\n                                            >\r\n                                                x\r\n                                            </button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                                <tfoot>\r\n                                    <!-- <tr>\r\n                                        <td\r\n                                            class=\"text-right hidden-sm-down\"\r\n                                            colspan=\"2\"\r\n                                        >\r\n                                            <label class=\"control-label\">\r\n                                                Producto\r\n                                                <a\r\n                                                    v-if=\"can_add_new_product\"\r\n                                                    href=\"#\"\r\n                                                    @click.prevent=\"\r\n                                                        showDialogNewItem = true\r\n                                                    \"\r\n                                                    >[+ Nuevo]</a\r\n                                                >\r\n                                            </label>\r\n                                        </td>\r\n                                        <td class=\"hidden-sm-down\" colspan=\"2\">\r\n                                            <div class=\"row\">\r\n                                                <div class=\"col-8\">\r\n                                                    <div\r\n                                                        :class=\"{\r\n                                                            'has-danger':\r\n                                                                errors.items\r\n                                                        }\"\r\n                                                        class=\"form-group\"\r\n                                                        id=\"custom-select\"\r\n                                                    >\r\n                                                        <el-input\r\n                                                            id=\"custom-input\"\r\n                                                        >\r\n                                                            <el-select\r\n                                                                v-model=\"\r\n                                                                    current_item\r\n                                                                \"\r\n                                                                id=\"select-width\"\r\n                                                                :loading=\"\r\n                                                                    loading_search\r\n                                                                \"\r\n                                                                :remote-method=\"\r\n                                                                    searchRemoteItems\r\n                                                                \"\r\n                                                                popper-class=\"el-select-items\"\r\n                                                                filterable\r\n                                                                remote\r\n                                                                ref=\"selectItem\"\r\n                                                                slot=\"prepend\"\r\n                                                                @change=\"\r\n                                                                    onChangeItem\r\n                                                                \"\r\n                                                            >\r\n                                                                <el-option\r\n                                                                    v-for=\"(option,\r\n                                                                    idx) in items\"\r\n                                                                    :key=\"idx\"\r\n                                                                    :label=\"\r\n                                                                        option.full_description\r\n                                                                    \"\r\n                                                                    :value=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                ></el-option>\r\n                                                            </el-select>\r\n\r\n                                                            <el-tooltip\r\n                                                                slot=\"append\"\r\n                                                                class=\"item\"\r\n                                                                content=\"Ver Stock del Producto\"\r\n                                                                effect=\"dark\"\r\n                                                                placement=\"bottom\"\r\n                                                            >\r\n                                                                <el-button\r\n                                                                    @click.prevent=\"\r\n                                                                        clickWarehouseDetail()\r\n                                                                    \"\r\n                                                                >\r\n                                                                    <i\r\n                                                                        class=\"fa fa-search\"\r\n                                                                    ></i>\r\n                                                                </el-button>\r\n                                                            </el-tooltip>\r\n                                                        </el-input>\r\n\r\n                                                        <small\r\n                                                            v-if=\"errors.items\"\r\n                                                            class=\"form-control-feedback\"\r\n                                                            v-text=\"\r\n                                                                errors.items[0]\r\n                                                            \"\r\n                                                        ></small>\r\n                                                    </div>\r\n                                                    <template v-if=\"item\">\r\n                                                        <div\r\n                                                            v-if=\"\r\n                                                                item.lots_enabled &&\r\n                                                                    item\r\n                                                                        .lots_group\r\n                                                                        .length >\r\n                                                                        0\r\n                                                            \"\r\n                                                            class=\"col-12 mt-2\"\r\n                                                        >\r\n                                                            <a\r\n                                                                class=\"text-center font-weight-bold text-info\"\r\n                                                                href=\"#\"\r\n                                                                @click.prevent=\"\r\n                                                                    clickLotGroup\r\n                                                                \"\r\n                                                            >\r\n                                                                [&#10004;\r\n                                                                Seleccionar\r\n                                                                lote]\r\n                                                            </a>\r\n                                                        </div>\r\n                                                    </template>\r\n                                                </div>\r\n                                                <div class=\"col-4\">\r\n                                                    <div\r\n                                                        :class=\"{\r\n                                                            'has-danger':\r\n                                                                errors.quantity\r\n                                                        }\"\r\n                                                        class=\"form-group\"\r\n                                                    >\r\n                                                  \r\n                                                        <el-input-number\r\n                                                            v-model=\"quantity\"\r\n                                                            :max=\"99999999\"\r\n                                                            :min=\"min_qty\"\r\n                                                            :precision=\"4\"\r\n                                                            :step=\"1\"\r\n                                                            placeholder=\"Cantidad\"\r\n                                                        ></el-input-number>\r\n                                                        <small\r\n                                                            v-if=\"\r\n                                                                errors.quantity\r\n                                                            \"\r\n                                                            class=\"form-control-feedback\"\r\n                                                            v-text=\"\r\n                                                                errors\r\n                                                                    .quantity[0]\r\n                                                            \"\r\n                                                        ></small>\r\n                                                    </div>\r\n                                                </div>\r\n                                            </div>\r\n                                        </td>\r\n                                        <td class=\"text-right hidden-sm-down\">\r\n                                            <el-button\r\n                                                style=\"width:100%\"\r\n                                                type=\"primary\"\r\n                                                @click=\"addAItemInRow\"\r\n                                                >Agregar\r\n                                            </el-button>\r\n                                        </td>\r\n                                    </tr> -->\r\n                                    <tr>\r\n                                        <td\r\n                                            class=\"text-center hidden-md-up\"\r\n                                            colspan=\"5\"\r\n                                        >\r\n                                            <button\r\n                                                class=\"btn waves-effect waves-light btn-primary\"\r\n                                                type=\"button\"\r\n                                                @click.prevent=\"\r\n                                                    showDialogAddItems = true\r\n                                                \"\r\n                                            >\r\n                                                + Agregar Producto\r\n                                            </button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tfoot>\r\n                            </table>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-lg-12\"></div>\r\n                    <div class=\"form-actions text-right mt-4\">\r\n                        <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                        <el-button\r\n                            v-if=\"form.items.length > 0\"\r\n                            :loading=\"loading_submit\"\r\n                            native-type=\"submit\"\r\n                            type=\"primary\"\r\n                            >Generar\r\n                        </el-button>\r\n                    </div>\r\n                </div>\r\n            </form>\r\n        </div>\r\n\r\n        <person-form\r\n            :external=\"true\"\r\n            :showDialog.sync=\"showDialogNewPerson\"\r\n            :input_person=\"input_person\"\r\n            type=\"customers\"\r\n        ></person-form>\r\n\r\n        <driver-form\r\n            :showDialog.sync=\"showDialogDriverForm\"\r\n            @success=\"successDriver\"\r\n        ></driver-form>\r\n\r\n        <dispatcher-form\r\n            :showDialog.sync=\"showDialogDispatcherForm\"\r\n            @success=\"successDispatcher\"\r\n        ></dispatcher-form>\r\n\r\n        <transport-form\r\n            :showDialog.sync=\"showDialogTransportForm\"\r\n            @success=\"successTransport\"\r\n        ></transport-form>\r\n\r\n        <origin-address-form\r\n            :showDialog.sync=\"showDialogOriginAddressForm\"\r\n            @success=\"successOriginAddress\"\r\n        ></origin-address-form>\r\n\r\n        <delivery-address-form\r\n            :showDialog.sync=\"showDialogDeliveryAddressForm\"\r\n            title=\"Nuevo punto de llegada\"\r\n            :person-id=\"form.customer_id\"\r\n            @success=\"successDeliveryAddress\"\r\n        ></delivery-address-form>\r\n\r\n        <items\r\n            :dialogVisible.sync=\"showDialogAddItems\"\r\n            @addItem=\"addItem\"\r\n        ></items>\r\n\r\n        <dispatch-finish\r\n            :recordId=\"recordId\"\r\n            :showClose=\"false\"\r\n            :send-sunat=\"send_sunat\"\r\n            :showDialog.sync=\"showDialogFinish\"\r\n        ></dispatch-finish>\r\n        <item-form\r\n            :external=\"true\"\r\n            :showDialog.sync=\"showDialogNewItem\"\r\n        ></item-form>\r\n        <lots-group\r\n            v-if=\"item\"\r\n            :lotsGroup=\"item.lots_group\"\r\n            :quantity=\"quantity\"\r\n            :showDialog.sync=\"showDialogLots\"\r\n            @addRowLotGroup=\"addRowLotGroup\"\r\n        >\r\n        </lots-group>\r\n\r\n        <warehouses-detail\r\n            :showDialog.sync=\"showWarehousesDetail\"\r\n            :warehouses=\"warehousesDetail\"\r\n        >\r\n        </warehouses-detail>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport PersonForm from \"../persons/form.vue\";\r\nimport Items from \"./items.vue\";\r\nimport itemForm from \"../items/form.vue\";\r\nimport LotsGroup from \"../documents/partials/lots_group.vue\";\r\nimport DriverForm from \"./drivers/form.vue\";\r\nimport DispatcherForm from \"./dispatchers/form.vue\";\r\nimport TransportForm from \"./transports/form.vue\";\r\nimport OriginAddressForm from \"./OriginAddress/Form\";\r\nimport DeliveryAddressForm from \"./partials/DispatchAddressForm\";\r\n\r\nimport DispatchFinish from \"./partials/finish\";\r\nimport { mapActions, mapState } from \"vuex/dist/vuex.mjs\";\r\nimport WarehousesDetail from \"@components/WarehousesDetail.vue\";\r\nimport { setDefaultSeriesByMultipleDocumentTypes } from \"@mixins/functions\";\r\n\r\nexport default {\r\n    props: [\r\n        \"pos\",\r\n        \"parentTable\",\r\n        \"parentId\",\r\n        \"document\",\r\n        \"documentItems\",\r\n        \"order_form_id\",\r\n        \"configuration\",\r\n        \"authUser\"\r\n    ],\r\n    components: {\r\n        itemForm,\r\n        LotsGroup,\r\n        PersonForm,\r\n        Items,\r\n        DispatchFinish,\r\n        WarehousesDetail,\r\n        DriverForm,\r\n        DispatcherForm,\r\n        TransportForm,\r\n        OriginAddressForm,\r\n        DeliveryAddressForm\r\n    },\r\n    mixins: [setDefaultSeriesByMultipleDocumentTypes],\r\n    computed: {\r\n        ...mapState([\"config\", \"item\", \"items\", \"all_items\"])\r\n    },\r\n    data() {\r\n        return {\r\n            can_add_new_product: false,\r\n            showDialogNewItem: false,\r\n            showDialogAddItems: false,\r\n            showDialogFinish: false,\r\n            showDialogNewPerson: false,\r\n            showDialogDriverForm: false,\r\n            showDialogTransportForm: false,\r\n            showDialogDispatcherForm: false,\r\n            showDialogOriginAddressForm: false,\r\n            showDialogDeliveryAddressForm: false,\r\n            IdLoteSelected: false,\r\n            showDialogLots: false,\r\n            min_qty: 0.0001,\r\n            input_person: {},\r\n            identityDocumentTypes: [],\r\n            transferReasonTypes: [],\r\n            related_document_types: [],\r\n            transportModeTypes: [],\r\n            resource: \"dispatches\",\r\n            loading_submit: false,\r\n            establishments: [],\r\n            drivers: [],\r\n            driver: null,\r\n            dispatchers: [],\r\n            dispatcher: null,\r\n            countries: [],\r\n            seriesAll: [],\r\n            unitTypes: [],\r\n            all_customers: [],\r\n            loading_search: false,\r\n            search_item_by_barcode: false,\r\n            customers: [],\r\n            code: null,\r\n            locations: [],\r\n            series: [],\r\n            current_item: null,\r\n            quantity: 1,\r\n            errors: {},\r\n            form: {},\r\n            recordId: null,\r\n            company: {},\r\n            customerAddresses: [],\r\n            showWarehousesDetail: false,\r\n            warehousesDetail: [],\r\n            transports: [],\r\n            origin: null,\r\n            delivery: null,\r\n            delivery_addresses: [],\r\n            origin_addresses: [],\r\n            send_sunat: false\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.loadConfiguration();\r\n        this.$store.commit(\"setConfiguration\", this.configuration);\r\n        this.canCreateProduct();\r\n    },\r\n    async mounted() {\r\n        const itemsFromSummary = localStorage.getItem(\"items\");\r\n        const payload = {};\r\n        if (itemsFromSummary) {\r\n            const items = JSON.parse(itemsFromSummary);\r\n            payload.itemIds = items.map(i => i.id);\r\n        }\r\n        await this.$http\r\n            .post(`/${this.resource}/tables`, payload)\r\n            .then(response => {\r\n                this.company = response.data.company;\r\n                this.identityDocumentTypes =\r\n                    response.data.identityDocumentTypes;\r\n                this.transferReasonTypes = response.data.transferReasonTypes;\r\n                this.related_document_types =\r\n                    response.data.related_document_types;\r\n                this.transportModeTypes = response.data.transportModeTypes;\r\n                this.establishments = response.data.establishments;\r\n                this.unitTypes = response.data.unitTypes;\r\n                this.all_customers = [];\r\n                this.countries = response.data.countries;\r\n                this.locations = response.data.locations;\r\n                this.seriesAll = response.data.series;\r\n                this.drivers = response.data.drivers;\r\n                this.dispatchers = response.data.dispatchers;\r\n                this.transports = response.data.transports;\r\n                if (itemsFromSummary) {\r\n                    this.onLoadItemsFromSummary(\r\n                        response.data.itemsFromSummary,\r\n                        JSON.parse(itemsFromSummary)\r\n                    );\r\n                }\r\n            });\r\n\r\n        if (this.parentId) {\r\n            this.form = Object.assign({}, this.form, this.document);\r\n            await this.reloadDataCustomers(this.form.customer_id);\r\n            await this.getDeliveryAddresses(this.form.customer_id);\r\n            await this.changeEstablishment();\r\n            if (this.parentTable !== \"dispatches\") {\r\n                this.setDefaults();\r\n            }\r\n        } else {\r\n            this.searchRemoteCustomers(\"\");\r\n            if (this.establishments.length > 0) {\r\n                this.form.establishment_id = _.head(this.establishments).id;\r\n            }\r\n            await this.changeEstablishment();\r\n            this.changeSeries();\r\n            this.setDefaults();\r\n        }\r\n        this.$eventHub.$on(\"reloadDataPersons\", customer_id => {\r\n            this.reloadDataCustomers(customer_id);\r\n        });\r\n        this.$eventHub.$on(\"initInputPerson\", () => {\r\n            this.initInputPerson();\r\n        });\r\n    },\r\n    methods: {\r\n        ...mapActions([\"loadItems\", \"loadConfiguration\"]),\r\n        initForm() {\r\n            this.errors = {};\r\n            let customer_id = parseInt(this.config.establishment.customer_id);\r\n            let establishment_id = parseInt(this.config.establishment.id);\r\n            if (isNaN(customer_id)) customer_id = null;\r\n            if (isNaN(establishment_id)) establishment_id = null;\r\n            this.form = {\r\n                id: null,\r\n                establishment_id: establishment_id,\r\n                document_type_id: \"09\",\r\n                series: null,\r\n                number: \"#\",\r\n                date_of_issue: moment().format(\"YYYY-MM-DD\"),\r\n                time_of_issue: moment().format(\"HH:mm:ss\"),\r\n                date_of_shipping: moment().format(\"YYYY-MM-DD\"),\r\n                customer_id: customer_id,\r\n                observations: \"\",\r\n                transport_mode_type_id: \"02\",\r\n                transfer_reason_type_id: \"01\",\r\n                transfer_reason_description: null,\r\n                transshipment_indicator: false,\r\n                port_code: null,\r\n                unit_type_id: \"KGM\",\r\n                total_weight: 1,\r\n                packages_number: 1,\r\n                container_number: null,\r\n                dispatcher_id: null,\r\n                dispatcher: {},\r\n                driver_id: null,\r\n                driver: {},\r\n                transport_id: null,\r\n                transport: {},\r\n                items: [],\r\n                reference_order_form_id: null,\r\n                // license_plate: null,\r\n                secondary_license_plates: {\r\n                    semitrailer: null\r\n                },\r\n                related: {},\r\n                order_form_external: null,\r\n                terms_condition: null,\r\n                origin_address_id: null,\r\n                delivery_address_id: null\r\n            };\r\n        },\r\n        setDescriptionOfItem(item) {\r\n            console.log(this.config.show_pdf_name);\r\n            console.log(item.item == undefined);\r\n            if (this.config.show_pdf_name) {\r\n                if (\r\n                    item.item != undefined &&\r\n                    item.item.name_product_pdf != undefined\r\n                ) {\r\n                    if (\r\n                        item.item.name_product_pdf !== \"\" &&\r\n                        !_.isNull(item.item.name_product_pdf)\r\n                    ) {\r\n                        return item.item.name_product_pdf;\r\n                    }\r\n                }\r\n                if (item.name_product_pdf != undefined) {\r\n                    if (\r\n                        item.name_product_pdf !== \"\" &&\r\n                        !_.isNull(item.name_product_pdf)\r\n                    ) {\r\n                        return item.name_product_pdf;\r\n                    }\r\n                }\r\n            }\r\n            return item.description;\r\n        },\r\n        setDefaults() {\r\n            if (this.origin_addresses.length > 0) {\r\n                this.form.origin_address_id = _.head(this.origin_addresses).id;\r\n            }\r\n            if (this.drivers.length > 0) {\r\n                let driver = _.find(this.drivers, { is_default: true });\r\n                this.form.driver_id = driver\r\n                    ? driver.id\r\n                    : _.head(this.drivers).id;\r\n            }\r\n            if (this.transports.length > 0) {\r\n                let transport = _.find(this.transports, { is_default: true });\r\n                this.form.transport_id = transport\r\n                    ? transport.id\r\n                    : _.head(this.transports).id;\r\n            }\r\n            if (this.dispatchers.length > 0) {\r\n                let dispatcher = _.find(this.dispatchers, { is_default: true });\r\n                this.form.dispatcher_id = dispatcher\r\n                    ? dispatcher.id\r\n                    : _.head(this.dispatchers).id;\r\n            }\r\n        },\r\n        clickWarehouseDetail() {\r\n            if (!this.current_item) {\r\n                return this.$message.error(\"Seleccione un producto\");\r\n            }\r\n            const item = _.find(this.items, { id: this.current_item });\r\n            this.warehousesDetail = item.warehouses;\r\n            this.showWarehousesDetail = true;\r\n        },\r\n        changeTransferReasonType() {\r\n            if (this.form.transfer_reason_type_id === \"09\") {\r\n                this.form.related = {\r\n                    number: null,\r\n                    document_type_id: \"01\"\r\n                };\r\n                this.form.customer_id = null;\r\n                this.delivery = {\r\n                    country_id: \"PE\",\r\n                    location_id: [],\r\n                    address: null\r\n                };\r\n            } else {\r\n                this.form.related = {};\r\n                this.delivery.country_id = \"PE\";\r\n            }\r\n            this.searchRemoteCustomers(\"\");\r\n        },\r\n        getFormatQuantity(quantity) {\r\n            return _.round(quantity, 4);\r\n        },\r\n        canCreateProduct() {\r\n            if (this.config.typeUser === \"admin\" || \"superadmin\") {\r\n                this.can_add_new_product = true;\r\n            } else if (\r\n                this.config.typeUser === \"seller\" &&\r\n                this.config.seller_can_create_product !== undefined\r\n            ) {\r\n                this.can_add_new_product = this.config.seller_can_create_product;\r\n            }\r\n            return this.can_add_new_product;\r\n        },\r\n        getAllItems() {\r\n            this.$http.post(`/${this.resource}/tables`).then(response => {\r\n                this.all_items = this.items;\r\n                this.$store.commit(\"setItems\", response.data.items);\r\n                this.$store.commit(\"setAllItems\", response.data.items);\r\n            });\r\n        },\r\n        addRowLotGroup(id) {\r\n            this.IdLoteSelected = id;\r\n        },\r\n        clickLotGroup() {\r\n            this.showDialogLots = true;\r\n        },\r\n        async searchRemoteItems(input) {\r\n            if (input.length > 2) {\r\n                this.loading_search = true;\r\n                const params = {\r\n                    input: input,\r\n                    search_by_barcode: this.search_item_by_barcode ? 1 : 0\r\n                };\r\n                await this.$http\r\n                    .get(`/documents/search-items`, { params })\r\n                    .then(response => {\r\n                        // this.items = response.data.items\r\n                        this.$store.commit(\"setItems\", response.data.items);\r\n                        this.loading_search = false;\r\n                        // this.enabledSearchItemsBarcode()\r\n                        if (this.items.length == 0) {\r\n                            this.filterItems();\r\n                        }\r\n                    });\r\n            } else {\r\n                await this.filterItems();\r\n            }\r\n        },\r\n        onChangeItem() {\r\n            this.IdLoteSelected = null;\r\n            this.$store.commit(\r\n                \"setItem\",\r\n                this.items.find(it => it.id == this.current_item)\r\n            );\r\n        },\r\n        filterItems() {\r\n            this.$store.commit(\"setItems\", this.all_items);\r\n        },\r\n        addAItemInRow() {\r\n            this.errors = {};\r\n            if (this.item.lots_enabled) {\r\n                if (!this.IdLoteSelected)\r\n                    return this.$message.error(\"Debe seleccionar un lote.\");\r\n            }\r\n\r\n            if (this.current_item != null && this.quantity != null) {\r\n                this.quantity = Math.abs(this.quantity);\r\n                if (isNaN(this.quantity)) {\r\n                    this.quantity = 1;\r\n                }\r\n                const item = this.items.find(\r\n                    item => item.id == this.current_item\r\n                );\r\n                item.IdLoteSelected = this.IdLoteSelected;\r\n\r\n                this.addItem({\r\n                    item: item,\r\n                    quantity: this.quantity\r\n                });\r\n                this.$store.commit(\"setItem\", {});\r\n                this.quantity = 1;\r\n                this.focusDescription();\r\n                return null;\r\n            }\r\n\r\n            if (this.current_item == null) {\r\n                this.$set(this.errors, \"items\", [\"Seleccione el producto\"]);\r\n            }\r\n\r\n            if (this.quantity == null) {\r\n                this.$set(this.errors, \"quantity\", [\"Digite la cantidad\"]);\r\n            }\r\n\r\n            this.IdLoteSelected = null;\r\n        },\r\n        async reloadDataCustomers(customer_id) {\r\n            await this.$http\r\n                .get(`/documents/search/customer/${customer_id}`)\r\n                .then(response => {\r\n                    this.customers = response.data.customers;\r\n                    // this.form.customer_id = customer_id\r\n                });\r\n        },\r\n        async changeCustomer() {\r\n            await this.getDeliveryAddresses(this.form.customer_id);\r\n            if (this.delivery_addresses.length > 0) {\r\n                this.form.delivery_address_id = _.head(\r\n                    this.delivery_addresses\r\n                ).id;\r\n            }\r\n        },\r\n        onLoadItemsFromSummary(items, itemsFromStorage) {\r\n            items.map(it => {\r\n                const quantityByItems = _.sumBy(\r\n                    itemsFromStorage.filter(i => i.id == it.id),\r\n                    function(row) {\r\n                        return parseFloat(row.quantity);\r\n                    }\r\n                );\r\n                if (quantityByItems) {\r\n                    this.addItem({\r\n                        item: it,\r\n                        quantity: quantityByItems\r\n                    });\r\n                }\r\n            });\r\n            localStorage.removeItem(\"items\");\r\n        },\r\n        searchRemoteCustomers(input) {\r\n            this.loading_search = true;\r\n            let identity_document_type_id = [\"6\", \"4\", \"1\", \"0\"];\r\n            if (this.form.transfer_reason_type_id === \"09\") {\r\n                identity_document_type_id = [\"0\"];\r\n            }\r\n            this.$http\r\n                .post(`/store/get_customers`, {\r\n                    identity_document_type_id: identity_document_type_id,\r\n                    input: input\r\n                })\r\n                .then(response => {\r\n                    this.customers = response.data.customers;\r\n                    this.loading_search = false;\r\n                    this.input_person.number =\r\n                        this.customers.length == 0 ? input : null;\r\n                });\r\n        },\r\n        filterCustomers() {\r\n            if (this.form.document_type_id === \"01\") {\r\n                this.customers = _.filter(this.all_customers, {\r\n                    identity_document_type_id: \"6\"\r\n                });\r\n            } else {\r\n                if (this.document_type_03_filter) {\r\n                    this.customers = _.filter(this.all_customers, c => {\r\n                        return c.identity_document_type_id !== \"6\";\r\n                    });\r\n                } else {\r\n                    this.customers = this.all_customers;\r\n                }\r\n            }\r\n        },\r\n        setDefaultCustomer() {\r\n            if (this.config.establishment.customer_id) {\r\n                let temp_customers = this.customers;\r\n                let customer_id = this.config.establishment.customer_id;\r\n                let custom = temp_customers.find(l => l.id == customer_id);\r\n                if (custom === undefined) {\r\n                    this.$http\r\n                        .get(`/${this.resource}/search/customer/${customer_id}`)\r\n                        .then(response => {\r\n                            let data_customer = response.data.customers;\r\n                            temp_customers = temp_customers.push(\r\n                                ...data_customer\r\n                            );\r\n                        });\r\n                    temp_customers = this.customers.filter(\r\n                        (item, index, self) =>\r\n                            index === self.findIndex(t => t.id === item.id)\r\n                    );\r\n                    this.customers = temp_customers;\r\n                }\r\n                let alt = _.find(this.customers, { id: customer_id });\r\n                if (alt !== undefined) {\r\n                    this.form.customer_id = customer_id;\r\n                    this.changeCustomer();\r\n                }\r\n            }\r\n        },\r\n        async changeEstablishment() {\r\n            if (this.form.establishment_id) {\r\n                this.series = _.filter(this.seriesAll, {\r\n                    establishment_id: this.form.establishment_id,\r\n                    document_type_id: this.form.document_type_id\r\n                });\r\n                await this.getOriginAddresses(this.form.establishment_id);\r\n            }\r\n        },\r\n        changeSeries() {\r\n            this.form.series = null;\r\n            this.setDefaultSeries();\r\n            //this.generalSetDefaultSerieByDocumentType('09');\r\n        },\r\n        setDefaultSeries() {\r\n            let series_id = parseInt(this.config.user.serie);\r\n            if (isNaN(series_id)) series_id = null;\r\n            let searchSeries = _.find(this.series, {\r\n                establishment_id: this.form.establishment_id,\r\n                document_type_id: this.form.document_type_id,\r\n                id: series_id\r\n            });\r\n            if (searchSeries !== undefined && searchSeries.length > 0) {\r\n                this.form.series = searchSeries.number;\r\n            }\r\n        },\r\n        addItem(form) {\r\n            let it = form.item;\r\n            let qty = form.quantity;\r\n            let exist = this.form.items.find(item => item.id == it.id);\r\n            let attributes = null;\r\n            if (it.attributes) {\r\n                attributes = it.attributes;\r\n                this.incrementValueAttr(form);\r\n            }\r\n            if (exist) {\r\n                exist.quantity += form.quantity;\r\n                return;\r\n            }\r\n            let lot_group = null;\r\n            if (it.IdLoteSelected) {\r\n                lot_group = it.lots_group.find(l => l.id == it.IdLoteSelected);\r\n            }\r\n            this.form.items.push({\r\n                attributes: attributes,\r\n                description: it.description,\r\n                internal_id: it.internal_id,\r\n                quantity: form.quantity,\r\n                item_id: it.id,\r\n                unit_type_id: it.unit_type_id,\r\n                id: it.id,\r\n                IdLoteSelected: it.IdLoteSelected || \"\",\r\n                lot_group: lot_group || null\r\n            });\r\n        },\r\n        keyupCustomer() {\r\n            if (this.input_person.number) {\r\n                if (!isNaN(parseInt(this.input_person.number))) {\r\n                    switch (this.input_person.number.length) {\r\n                        case 8:\r\n                            this.input_person.identity_document_type_id = \"1\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n                        case 11:\r\n                            this.input_person.identity_document_type_id = \"6\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n                        default:\r\n                            this.input_person.identity_document_type_id = \"6\";\r\n                            this.showDialogNewPerson = true;\r\n                            break;\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        decrementValueAttr(form) {\r\n            let it = form;\r\n            let attrib = it.attributes;\r\n            let qty = parseFloat(it.quantity);\r\n            this.form.packages_number -= qty;\r\n            let total_weight = 0;\r\n            if (attrib) {\r\n                for (const [key, value] of Object.entries(attrib)) {\r\n                    if (key === \"attributes\" && value !== null) {\r\n                        let attr = JSON.parse(value);\r\n                        if (attr !== null) {\r\n                            attr.forEach(attr => {\r\n                                if (attr.attribute_type_id === \"5032\") {\r\n                                    total_weight -=\r\n                                        parseFloat(attr.value) * qty;\r\n                                }\r\n                            });\r\n                        }\r\n                    }\r\n                }\r\n            }\r\n            this.form.total_weight += total_weight;\r\n        },\r\n        incrementValueAttr(form) {\r\n            let qty = parseFloat(form.quantity);\r\n            let it = form.item;\r\n            let attrib = it.attributes;\r\n            this.form.packages_number += qty;\r\n            let total_weight = 0;\r\n            if (attrib) {\r\n                for (const [key, value] of Object.entries(attrib)) {\r\n                    if (key === \"attributes\" && value !== null) {\r\n                        let attr = JSON.parse(value);\r\n                        if (attr !== null) {\r\n                            attr.forEach(attr => {\r\n                                if (attr.attribute_type_id === \"5032\") {\r\n                                    total_weight +=\r\n                                        parseFloat(attr.value) * qty;\r\n                                }\r\n                            });\r\n                        }\r\n                    }\r\n                }\r\n            }\r\n            this.form.total_weight += total_weight;\r\n        },\r\n        clickRemoveItem(index) {\r\n            this.decrementValueAttr(this.form.items[index]);\r\n            this.form.items.splice(index, 1);\r\n        },\r\n        async submit() {\r\n            if (this.config.affect_all_documents) {\r\n                this.form.terms_condition = this.config.terms_condition_sale;\r\n            }\r\n            if (this.form.transport_mode_type_id === \"02\") {\r\n                this.form.dispatcher_id = null;\r\n                this.form.dispatcher = null;\r\n                if (!this.form.driver_id) {\r\n                    return this.$message.error(\"El conductor es requerido\");\r\n                }\r\n                if (!this.form.transport_id) {\r\n                    return this.$message.error(\"El vehículo es requerido\");\r\n                }\r\n                this.form.driver = _.find(this.drivers, {\r\n                    id: this.form.driver_id\r\n                });\r\n                this.form.transport = _.find(this.transports, {\r\n                    id: this.form.transport_id\r\n                });\r\n                // this.form.license_plate = this.form.transport.plate_number;\r\n\r\n                if (\r\n                    this.form.driver.identity_document_type_id === \"\" ||\r\n                    _.isNull(this.form.driver.identity_document_type_id)\r\n                ) {\r\n                    return this.$message.error(\r\n                        \"El tipo de documento del conductor es requerido\"\r\n                    );\r\n                }\r\n                if (\r\n                    this.form.driver.number === \"\" ||\r\n                    _.isNull(this.form.driver.number)\r\n                ) {\r\n                    return this.$message.error(\r\n                        \"El número del conductor es requerido\"\r\n                    );\r\n                }\r\n                if (\r\n                    this.form.driver.name === \"\" ||\r\n                    _.isNull(this.form.driver.name)\r\n                ) {\r\n                    return this.$message.error(\r\n                        \"El nombre del conductor es requerido\"\r\n                    );\r\n                }\r\n                if (\r\n                    this.form.driver.license === \"\" ||\r\n                    _.isNull(this.form.driver.license)\r\n                ) {\r\n                    return this.$message.error(\r\n                        \"La licencia del conductor es requerido\"\r\n                    );\r\n                }\r\n                // if (this.form.license_plate === '' || _.isNull(this.form.license_plate)) {\r\n                //     return this.$message.error('El número de placa es requerido')\r\n                // }\r\n            }\r\n            if (this.form.transport_mode_type_id === \"01\") {\r\n               