                       this.$message.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        changeIdentityDocType() {\r\n            // (this.recordId == null) ? this.setDataDefaultCustomer() : null\r\n        },\r\n        setDataDefaultCustomer() {\r\n            // if(this.form.identity_document_type_id == '0'){\r\n            //     this.form.number = '99999999'\r\n            //     this.form.name = \"Clientes - Varios\"\r\n            // }else{\r\n            //     this.form.number = ''\r\n            //     this.form.name = null\r\n            // }\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        },\r\n        searchCustomer() {\r\n            this.searchServiceNumberByType();\r\n        },\r\n        searchNumber(data) {\r\n            this.form.name =\r\n                this.form.identity_document_type_id === \"1\"\r\n                    ? data.nombre_completo\r\n                    : data.nombre_o_razon_social;\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/drivers/form.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"dialogVisible\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        @close=\"close\"\r\n        top=\"8vh\"\r\n    >\r\n        <div class=\"form-body\">\r\n            <div class=\"row\">\r\n                <div class=\"col-md-6\">\r\n                    <div\r\n                        class=\"form-group\"\r\n    