on=\"4\"\r\n                            :step=\"1\"\r\n                            :min=\"0.01\"\r\n                            :max=\"99999999\"\r\n                        ></el-input-number>\r\n                        <small\r\n                            class=\"form-control-feedback\"\r\n                            v-if=\"errors.quantity\"\r\n                            v-text=\"errors.quantity[0]\"\r\n                        ></small>\r\n                    </div>\r\n                </div>\r\n                <template v-if=\"item\">\r\n                    <div\r\n                        class=\"col-12 mt-2\"\r\n                        v-if=\"item.lots_enabled && item.lots_group.length > 0\"\r\n                    >\r\n                        <a\r\n                            href=\"#\"\r\n                            class=\"text-center font-weight-bold text-info\"\r\n                            @click.prevent=\"clickLotGroup\"\r\n                            >[&#10004; Seleccionar lote]</a\r\n                        >\r\n                    </div>\r\n                </template>\r\n            </div>\r\n        </div>\r\n        <span slot=\"footer\" class=\"dialog-footer\">\r\n            <el-button @click.prevent=\"close\">Cerrar</el-button>\r\n            <el-button type=\"primary\" @click=\"clickAddItem\">Agregar</el-button>\r\n        </span>\r\n\r\n        <item-form\r\n            :showDialog.sync=\"showDialogNewItem\"\r\n            :external=\"true\"\r\n        ></item-form>\r\n\r\n        <lots-group\r\n            v-if=\"item\"\r\n            :quantity=\"form.quantity\"\r\n            :showDialog.sync=\"showDialogLots\"\r\n            :lotsGroup=\"item.lots_group\"\r\n            @addRowLotGroup=\"addRowLotGroup\"\r\n        >\r\n        </lots-group>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport itemForm from \"../items/form.vue\";\r\nimport LotsGroup from \"../documents/partials/lots_group.vue\";\r\n\r\nexport default {\r\n    componen