.form = {};\r\n                this.item = null;\r\n                return;\r\n            }\r\n\r\n            if (this.form.item == null)\r\n                this.$set(this.errors, \"items\", [\"Seleccione el producto\"]);\r\n\r\n            if (this.form.quantity == null)\r\n                this.$set(this.errors, \"quantity\", [\"Digite la cantidad\"]);\r\n\r\n            this.form.IdLoteSelected = null;\r\n        },\r\n        filterItems() {\r\n            this.items = this.all_items;\r\n        },\r\n        async searchRemoteItems(input) {\r\n            if (input.length > 2) {\r\n                this.loading_search = true;\r\n                const params = {\r\n                    input: input,\r\n                    search_by_barcode: this.search_item_by_barcode ? 1 : 0\r\n                };\r\n                await this.$http\r\n                    .get(`/documents/search-items`, { params })\r\n                    .then(response => {\r\n                        this.items = response.data.items;\r\n                        this.loading_search = false;\r\n                        // this.enabledSearchItemsBarcode()\r\n                        if (this.items.length == 0) {\r\n                            this.filterItems();\r\n                        }\r\n                    });\r\n            } else {\r\n                await this.filterItems();\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/items.vue","<template>\r\n    <el-dialog :close-on-click-modal=\"false\"\r\n               :title=\"titleDialog\"\r\n               :visible=\"showDialog\"\r\n               append-to-body\r\n               @close=\"clickClose\"\r\n               @open=\"create\">\r\n        <form autocomplete=\"off\"\r\n              @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <di