ubmit\"\r\n                           type=\"primary\">Guardar\r\n                </el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\nexport default {\r\n    name: 'DispatchAddressForm',\r\n    props: ['showDialog', 'personId',  'title'],\r\n    data() {\r\n        return {\r\n            loadingSearch: false,\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: 'dispatch_addresses',\r\n            errors: {},\r\n            form: {},\r\n            locations: []\r\n        }\r\n    },\r\n    async created() {\r\n        await this.getTables();\r\n        this.initForm()\r\n    },\r\n    methods: {\r\n        async getTables() {\r\n            await this.$http.get(`/${this.resource}/tables`)\r\n                .then(response => {\r\n                    this.locations = response.data.locations\r\n                })\r\n        },\r\n        initForm() {\r\n            this.errors = {}\r\n            this.form = {\r\n                id: null,\r\n                person_id: this.personId,\r\n                address: null,\r\n                location_id: [],\r\n                is_default: false,\r\n                is_active: true,\r\n            }\r\n        },\r\n        async create() {\r\n            this.titleDialog = this.title;\r\n            this.initForm();\r\n        },\r\n        async submit() {\r\n            this.loading_submit = true\r\n            await this.$http.post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$emit('success', response.data.id)\r\n                        this.clickClose()\r\n                    } else {\r\n                        this.$message.error(response.data.message)\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data\r\n                    } else {\r\n                        console.log(error)\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false\r\n                })\r\n        },\r\n        async clickSearch() {\r\n            this.loadingSearch = true;\r\n            await this.$http.get(`/dispatch_addresses/search/${this.personId}`)\r\n                .then(response => {\r\n                    let res = response.data;\r\n                    if (res.success) {\r\n                        this.form.address = res.data.address\r\n                        this.form.location_id = res.data.location_id\r\n                    } else {\r\n                        this.$message.error(res.message)\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    console.log(error.response)\r\n                })\r\n                .finally(() => {\r\n                    this.loadingSearch = false\r\n                })\r\n        },\r\n        clickClose() {\r\n            this.$emit('update:showDialog', false)\r\n        },\r\n    }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/partials/DispatchAddressForm.vue","<template>\r\n    <el-dialog :title=\"titleDialog\"\r\n               :visible=\"showDialog\"\r\n               append-to-body\r\n               width=\"30%\"\r\n               :close-on-click-modal=\"false\"\r\n               :close-on-press-escape=\"false\"\r\n               :show-close=\"false\"\r\n               @open=\"create\">\r\n        <div v-if=\"form.response_message\"\r\n             class=\"row mb-4\">\r\n            <div class=\"col-md-12\">\r\n                <el-alert\r\n                    :title=\"form.response_message\"\r\n                    :type=\"form.response_type\"\r\n                    show-icon>\r\n                </el-alert>\r\n            </div>\r\n        </div>\r\n        <div v-if=\"sendSunat\">\r\n            <div>Enviando comprobante a sunat</div>\r\n            <div>{{ response_sunat_send.message }}</div>\r\n            <template v-if=\"response_sunat_send.success\">\r\n                <div>Consultando ticket a sunat</div>\r\n                <template v-if=\"response_sunat_status_ticket\">\r\n                    <div>{{ response_sunat_status_ticket.message }}</div>\r\n                    <div v-if=\"!response_sunat_status_ticket.success\">\r\n                        <el-button class=\"list\"\r\n                                   @click=\"clickStatusTicket\">Consultar ticket\r\n                        </el-button>\r\n                    </div>\r\n                </template>\r\n            </template>\r\n        </div>\r\n\r\n        <div v-if=\"form.send_to_pse\" class=\"row\">\r\n            <div v-if=\"form.response_signature_pse\"\r\n                 class=\"col-lg-12 col-md-12 col-sm-12\">\r\n                <el-alert :title=\"`Firma Xml PSE: ${form.response_signature_pse}`\"\r\n                          show-icon\r\n                          type=\"success\"></el-alert>\r\n            </div>\r\n            <div v-if=\"form.response_send_cdr_pse\"\r\n                 class=\"col-lg-12 col-md-12 col-sm-12 mt-3\">\r\n                <el-alert :title=\"`Envio CDR PSE: ${form.response_send_cdr_pse}`\"\r\n                          show-icon\r\n                          type=\"success\"></el-alert>\r\n            </div>\r\n        </div>\r\n\r\n        <template v-if=\"(response_sunat_status_ticket && response_sunat_status_ticket.success) || !sendSunat\">\r\n            <div class=\"row\">\r\n                <div class=\"col-lg-6 col-md-6 col-sm-6 text-center font-weight-bold mt-3\">\r\n                    <button class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                            type=\"button\"\r\n                            @click=\"clickDownload('a4')\">\r\n                        <i class=\"fa fa-file-alt\"></i>\r\n                    </button>\r\n                    <p>Descargar A4</p>\r\n                </div>\r\n                <div class=\"col-lg-6 col-md-6 col-sm-6 text-center font-weight-bold mt-3\">\r\n                    <button class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                            type=\"button\"\r\n                            @click=\"clickDownload('ticket')\">\r\n                        <i class=\"fa fa-file-alt\"></i>\r\n                    </button>\r\n                    <p>80MM</p>\r\n                </div>\r\n                <div class=\"col-lg-6 col-md-6 col-sm-6 text-center font-weight-bold mt-3\">\r\n                    <button class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                            type=\"button\"\r\n                            @click=\"clickDownload('ticket_58')\">\r\n                        <i class=\"fa fa-file-alt\"></i>\r\n                    </button>\r\n                    <p>58MM</p>\r\n                </div>\r\n                <div v-if=\"sendSunat\" class=\"col-lg-6 col-md-6 col-sm-6 text-center font-weight-bold mt-3\">\r\n                    <button class=\"btn btn-lg btn-info waves-effect waves-light\"\r\n                            type=\"button\"\r\n                            @click=\"clickDownloadCdr()\">\r\n                        <i class=\"fa fa-file-download\"></i>\r\n                    </button>\r\n                    <p>Descargar CDR</p>\r\n                </div>\r\n            </div>\r\n            <div class=\"row mt-3\">\r\n                <div class=\"col-md-12\">\r\n                    <el-input v-model=\"form.customer_email\">\r\n                        <el-button slot=\"append\"\r\n                                   :loading=\"loading\"\r\n                                   icon=\"el-icon-message\"\r\n                                   @click=\"clickSendEmail\">Enviar\r\n                        </el-button>\r\n                    </el-input>\r\n                    <small v-if=\"errors.customer_email\"\r\n                           class=\"form-control-feedback\"\r\n                           v-text=\"errors.customer_email[0]\"></small>\r\n                </div>\r\n            </div>\r\n            <div class=\"row mt-3\">\r\n                <div class=\"col-md-12\">\r\n                    <el-input v-model=\"form.customer_telephone\">\r\n                        <template slot=\"prepend\">+51</template>\r\n                        <el-button slot=\"append\"\r\n                                   @click=\"clickSendWhatsapp\">Enviar\r\n                            <el-tooltip class=\"item\"\r\n                                        content=\"Es necesario tener aperturado Whatsapp web\"\r\n                                        effect=\"dark\"\r\n                                        placement=\"top-start\">\r\n                                <i class=\"fab fa-whatsapp\"></i>\r\n                            </el-tooltip>\r\n                        </el-button>\r\n                    </el-input>\r\n                    <small v-if=\"errors.customer_telephone\"\r\n                           class=\"form-control-feedback\"\r\n                           v-text=\"errors.customer_telephone[0]\"></small>\r\n                </div>\r\n            </div>\r\n        </template>\r\n\r\n        <span slot=\"footer\"\r\n              v-if=\"!loading_sunat_send\"\r\n              class=\"dialog-footer\">\r\n            <template v-if=\"showClose\">\r\n                <el-button @click=\"clickClose\">Cerrar</el-button>\r\n            </template>\r\n            <template v-else>\r\n                <el-button class=\"list\"\r\n                           @click=\"clickFinalize\">Ir al listado</el-button>\r\n                <el-button type=\"primary\"\r\n                           @click=\"clickNewDocument\">{{ text_button }}</el-button>\r\n            </template>\r\n        </span>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: ['showDialog',\r\n        'recordId',\r\n        'sendSunat',\r\n        'showClose'\r\n    ],\r\n    name: 'DispatchFinish',\r\n    data() {\r\n        return {\r\n            titleDialog: null,\r\n            loading: false,\r\n            loading_sunat_send: false,\r\n            loading_sunat_send_response: false,\r\n            loading_sunat_status_ticket: false,\r\n            loading_sunat_status_ticket_response: false,\r\n            resource: 'dispatches',\r\n            errors: {},\r\n            form: {},\r\n            company: {},\r\n            locked_emission: {},\r\n            text_button: null,\r\n            response_sunat_send: {},\r\n            response_sunat_status_ticket: {},\r\n        }\r\n    },\r\n    async created() {\r\n        this.initForm()\r\n        this.text_button = 'Nueva guía'\r\n    },\r\n    methods: {\r\n        initForm() {\r\n            this.loading_sunat_send = false;\r\n            this.errors = {};\r\n            this.form = {\r\n                customer_email: null,\r\n                download_external_pdf: null,\r\n                external_id: null,\r\n                number: null,\r\n                id: null,\r\n                response_message: null,\r\n                response_type: null,\r\n                customer_telephone: null,\r\n                message_text: null,\r\n                download_cdr: null,\r\n                state_type_id: '05',\r\n                has_cdr: true,\r\n                send_to_pse: false,\r\n                response_signature_pse: null,\r\n                response_send_cdr_pse: null,\r\n            }\r\n            this.locked_emission = {\r\n                success: true,\r\n                message: null\r\n            }\r\n            this.company = {\r\n                soap_type_id: null,\r\n            }\r\n            this.response_sunat_send = {\r\n                'success': false,\r\n                message: null\r\n            }\r\n            this.response_sunat_status_ticket = null\r\n        },\r\n        clickDownload(format = 'a4') {\r\n            if ((this.form && this.form.external_id)) {\r\n                window.open(`/print/dispatch/${this.form.external_id}/${format}`, '_blank');\r\n            }\r\n        },\r\n        clickSendWhatsapp() {\r\n            if (!this.form.customer_telephone) {\r\n                return this.$message.error('El número es obligatorio')\r\n            }\r\n            window.open(`https://wa.me/51${this.form.customer_telephone}?text=${this.form.message_text}`, '_blank');\r\n        },\r\n        clickDownloadCdr() {\r\n            window.open(this.form.download_cdr, '_blank');\r\n        },\r\n        timeout(ms) {\r\n            return new Promise(resolve => setTimeout(resolve, ms));\r\n        },\r\n        async create() {\r\n            this.initForm();\r\n            this.loading_sunat_send = true;\r\n            await this.$http.get(`/${this.resource}/record/${this.recordId}`).then(response => {\r\n                this.form = response.data.data;\r\n                this.titleDialog = 'Guía: ' + this.form.number;\r\n            });\r\n            if (this.sendSunat) {\r\n                await this.$http.get(`/service/dispatch/send/${this.form.external_id}`)\r\n                    .then(response => {\r\n                        this.response_sunat_send = response.data;\r\n                    });\r\n\r\n                if (this.response_sunat_send.success) {\r\n                    await this.timeout(3000);\r\n                    await this.clickStatusTicket();\r\n                }\r\n            }\r\n            this.loading_sunat_send = false;\r\n        },\r\n        clickPrint(format) {\r\n            window.open(`/${this.resource}/print/${this.form.external_id}/${format}`, '_blank');\r\n        },\r\n        clickSendEmail() {\r\n            this.loading = true\r\n            this.$http.post(`/${this.resource}/email`, {\r\n                customer_email: this.form.customer_email,\r\n                id: this.form.id\r\n            })\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$message.success('El correo fue enviado satisfactoriamente')\r\n                    } else {\r\n                        this.$message.error('Error al enviar el correo')\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors\r\n                    } else {\r\n                        this.$message.error(error.response.data.message)\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading = false\r\n                })\r\n        },\r\n        clickFinalize() {\r\n            if (this.form.document_type_id === '31') {\r\n                location.href = `/dispatch_carrier`\r\n            } else {\r\n                location.href = `/${this.resource}`\r\n            }\r\n        },\r\n        clickNewDocument() {\r\n            if (this.form.document_type_id === '31') {\r\n                location.href = `/dispatch_carrier/create`\r\n            } else {\r\n                location.href = `/${this.resource}/create`\r\n            }\r\n            // this.clickClose()\r\n        },\r\n        clickClose() {\r\n            this.$emit('update:showDialog', false);\r\n        },\r\n        async clickStatusTicket() {\r\n            await this.$http.get(`/service/dispatch/status_ticket/${this.form.external_id}`)\r\n                .then(response => {\r\n                    this.response_sunat_status_ticket = response.data;\r\n                });\r\n        }\r\n    }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/partials/finish.vue","<template>\r\n  <el-dialog :close-on-click-modal=\"false\"\r\n             :title=\"titleDialog\"\r\n             :visible=\"showDialog\"\r\n             append-to-body\r\n             @close=\"close\"\r\n             @open=\"create\">\r\n    <form autocomplete=\"off\"\r\n          @submit.prevent=\"submit\">\r\n      <div class=\"form-body\">\r\n        <div class=\"row\">\r\n          <div class=\"col-md-6\">\r\n            <div :class=\"{'has-danger': errors.plate_number}\"\r\n                 class=\"form-group\">\r\n              <label class=\"control-label\">Nro. de Placa <span class=\"text-danger\">*</span></label>\r\n              <el-input v-model=\"form.plate_number\"\r\n                        dusk=\"name\"></el-input>\r\n              <small v-if=\"errors.plate_number\"\r\n                     class=\"form-control-feedback\"\r\n                     v-text=\"errors.plate_number[0]\"></small>\r\n            </div>\r\n          </div>\r\n          <div class=\"col-md-6\">\r\n            <div :class=\"{'has-danger': errors.model}\"\r\n                 class=\"form-group\">\r\n              <label class=\"control-label\">Modelo</label>\r\n              <el-input v-model=\"form.model\"></el-input>\r\n              <small v-if=\"errors.model\"\r\n                     class=\"form-control-feedback\"\r\n                     v-text=\"errors.model[0]\"></small>\r\n            </div>\r\n          </div>\r\n          <div class=\"col-md-6\">\r\n            <div :class=\"{'has-danger': errors.brand}\"\r\n                 class=\"form-group\">\r\n              <label class=\"control-label\">Marca</label>\r\n              <el-input v-model=\"form.brand\"></el-input>\r\n              <small v-if=\"errors.brand\"\r\n                     class=\"form-control-feedback\"\r\n                     v-text=\"errors.brand[0]\"></small>\r\n            </div>\r\n          </div>\r\n          <div class=\"col-md-6\">\r\n            <div class=\"form-group\" style=\"margin-top: 32px;\">\r\n              <el-switch v-model=\"form.is_default\"\r\n                         active-text=\"Predeterminado\"\r\n                         inactive-text=\"\"></el-switch>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div class=\"form-actions text-right mt-4\">\r\n        <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n        <el-button :loading=\"loading_submit\"\r\n                   native-type=\"submit\"\r\n                   type=\"primary\">Guardar\r\n        </el-button>\r\n      </div>\r\n    </form>\r\n  </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\nexport default {\r\n  name: 'DispatchTransportForm',\r\n  props: ['showDialog', 'recordId', 'external'],\r\n  data() {\r\n    return {\r\n      loading_submit: false,\r\n      titleDialog: null,\r\n      resource: 'transports',\r\n      errors: {},\r\n      form: {},\r\n    }\r\n  },\r\n  created() {\r\n    this.initForm()\r\n  },\r\n  methods: {\r\n    initForm() {\r\n      this.errors = {}\r\n      this.form = {\r\n        id: null,\r\n        plate_number: null,\r\n        model: null,\r\n        brand: null,\r\n        is_default: false,\r\n        is_active: true,\r\n      }\r\n    },\r\n    async create() {\r\n      this.initForm();\r\n      this.titleDialog = (this.recordId) ? 'Editar Vehículo' : 'Nuevo Vehículo'\r\n      if (this.recordId) {\r\n        await this.$http.get(`/${this.resource}/record/${this.recordId}`)\r\n            .then(response => {\r\n              this.form = response.data.data\r\n            })\r\n      }\r\n    },\r\n    async submit() {\r\n      this.loading_submit = true\r\n      await this.$http.post(`/${this.resource}`, this.form)\r\n          .then(response => {\r\n            if (response.data.success) {\r\n              this.$message.success(response.data.message)\r\n              this.$emit('success', response.data.id)\r\n              this.close()\r\n            } else {\r\n              this.$message.error(response.data.message)\r\n            }\r\n          })\r\n          .catch(error => {\r\n            if (error.response.status === 422) {\r\n              this.errors = error.response.data\r\n            } else {\r\n              console.log(error)\r\n            }\r\n          })\r\n          .then(() => {\r\n            this.loading_submit = false\r\n          })\r\n    },\r\n    close() {\r\n      this.$emit('update:showDialog', false)\r\n    },\r\n  }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/transports/form.vue","<template>\r\n  <el-dialog\r\n    :title=\"titleDialog\"\r\n    width=\"40%\"\r\n    :visible=\"showDialog\"\r\n    @open=\"create\"\r\n    :close-on-click-modal=\"false\"\r\n    :close-on-press-escape=\"false\"\r\n    append-to-body\r\n    :show-close=\"false\"\r\n  >\r\n    <div class=\"form-body\">\r\n      <div class=\"row\">\r\n        <div class=\"col-lg-12 col-md-12\">\r\n          <table class=\"table\">\r\n            <thead>\r\n              <tr>\r\n                <th>Seleccionado</th>\r\n                <th>codigo</th>\r\n                <th>Cantidad</th>\r\n                <th class>Fecha vencimiento</th>\r\n              </tr>\r\n            </thead>\r\n            <tbody>\r\n              <tr v-for=\"(row, index) in lots_group\" :key=\"index\" v-show=\"row.quantity > 0\">\r\n                <th align=\"center\">\r\n                  <el-checkbox\r\n                    :disabled=\"row.quantity  < 1\"\r\n                    v-model=\"row.checked\"\r\n                    @change=\"changeSelect(index, row.id, row.quantity)\"\r\n                  ></el-checkbox>\r\n                </th>\r\n                <th>{{ row.code }}</th>\r\n                <th class>{{ row.quantity }}</th>\r\n                <th class>{{ row.date_of_due }}</th>\r\n              </tr>\r\n            </tbody>\r\n          </table>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n   <div class=\"form-actions text-end pt-2 pb-2\">\r\n      <el-button @click.prevent=\"close()\">Cerrar</el-button>\r\n      <el-button type=\"primary\" @click=\"submit\">Guardar</el-button>\r\n    </div>\r\n  </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n  props: [\"showDialog\", \"lots_group\", \"stock\", \"recordId\", \"quantity\"],\r\n  data() {\r\n    return {\r\n      titleDialog: \"Lotes\",\r\n      loading: false,\r\n      errors: {},\r\n      form: {},\r\n      states: [\"Activo\", \"Inactivo\", \"Desactivado\", \"Voz\", \"M2m\"],\r\n      idSelected: null\r\n    };\r\n  },\r\n  async created() {\r\n    // await this.$http.get(`/pos/payment_tables`)\r\n    //     .then(response => {\r\n    //         this.payment_method_types = response.data.payment_method_types\r\n    //         this.cards_brand = response.data.cards_brand\r\n    //         this.clickAddLot()\r\n    //     })\r\n  },\r\n  methods: {\r\n    changeSelect(index, id, quantity_lot) {\r\n        \r\n      if (this.quantity > quantity_lot) {\r\n\r\n        this.lots_group[index].checked = false;\r\n       \r\n      } else {\r\n        this.lots_group.forEach(row => {\r\n          row.checked = false;\r\n        });\r\n\r\n        this.lots_group[index].checked = true;\r\n\r\n        this.idSelected = id;\r\n      }\r\n    },\r\n    handleSelectionChange(val) {\r\n      //this.$refs.multipleTable.clearSelection();\r\n      let row = val[val.length - 1];\r\n      this.multipleSelection = [row];\r\n    },\r\n    create() {},\r\n\r\n    async submit() {\r\n      await this.$emit(\"addRowLotGroup\", this.idSelected);\r\n      await this.$emit(\"update:showDialog\", false);\r\n    },\r\n\r\n    clickCancel(item) {\r\n      //this.lots.splice(index, 1);\r\n      item.deleted = true;\r\n      this.$emit(\"addRowLotGroup\", this.lots);\r\n    },\r\n\r\n    async clickCancelSubmit() {\r\n      this.$emit(\"addRowLotGroup\", []);\r\n      await this.$emit(\"update:showDialog\", false);\r\n    },\r\n    close() {\r\n      this.$emit(\"update:showDialog\", false);\r\n    }\r\n  }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/quotations/partials/lots_group.vue","<template>\r\n    <el-dialog\r\n        width=\"65%\"\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        :close-on-click-modal=\"false\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <el-tabs tab-position=\"top\">\r\n                    <el-tab-pane label=\"General\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.internal_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Código Interno\r\n                                        <el-tooltip\r\n                                            class=\"item\"\r\n                                            effect=\"dark\"\r\n                                            content=\"Código interno de la empresa para el control de sus productos\"\r\n                                            placement=\"top-start\"\r\n                                        >\r\n                                            <i class=\"fa fa-info-circle\"></i>\r\n                                        </el-tooltip>\r\n                                    </label>\r\n                                    <el-input\r\n                                        ref=\"internal_id\"\r\n                                        v-model=\"form.internal_id\"\r\n                                        dusk=\"internal_id\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.internal_id\"\r\n                                        v-text=\"errors.internal_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-6\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.description\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Nombre<span class=\"text-danger\"\r\n                                            >*</span\r\n                                        ></label\r\n                                    >\r\n                                    <el-input\r\n                                        v-model=\"form.description\"\r\n                                        dusk=\"description\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i>\r\n                                    </el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.description\"\r\n                                        v-text=\"errors.description[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.second_name\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Nombre secundario\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.second_name\"\r\n                                        dusk=\"second_name\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.second_name\"\r\n                                        v-text=\"errors.second_name[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.category_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">\r\n                                        Categoría\r\n                                    </label>\r\n\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == false\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"form_category.add = true\"\r\n                                    >\r\n                                        [ + Nuevo]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"saveCategory()\"\r\n                                    >\r\n                                        [ + Guardar]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-danger\"\r\n                                        @click=\"form_category.add = false\"\r\n                                    >\r\n                                        [ Cancelar]</a\r\n                                    >\r\n                                    <el-input\r\n                                        v-if=\"form_category.add == true\"\r\n                                        v-model=\"form_category.name\"\r\n                                        dusk=\"item_code\"\r\n                                        style=\"margin-bottom:1.5%;\"\r\n    