\n                                <th>Ubicación</th>\r\n                                <th class=\"text-end\">Stock</th>\r\n                            </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                            <tr v-for=\"row in form.warehouses\">\r\n                                <th>{{ row.warehouse_description }}</th>\r\n                                <th class=\"text-end\">{{ row.stock }}</th>\r\n                            </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>-->\r\n                        </div>\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-12\">\r\n                                <h6 class=\"separator-title\">\r\n                                    Campos adicionales\r\n                                </h6>\r\n                            </div>\r\n                            <div class=\"row col-md-12\">\r\n                                <div class=\"col-md-3\">\r\n                                    <div class=\"form-group\">\r\n                                        <label class=\"control-label\"\r\n                                            >Imágen\r\n                                            <span class=\"text-danger\"></span\r\n                                        ></label>\r\n                                        <el-upload\r\n                                            class=\"avatar-uploader\"\r\n                                            :data=\"{ type: 'items' }\"\r\n                                            :headers=\"headers\"\r\n                                            :action=\"`/${resource}/uploads`\"\r\n                                            :show-file-list=\"false\"\r\n                                            :on-success=\"onSuccess\"\r\n                                        >\r\n                                            <img\r\n                                                v-if=\"form.image_url\"\r\n                                                :src=\"form.image_url\"\r\n                                                class=\"avatar\"\r\n                                            />\r\n                                            <i\r\n                                                v-else\r\n                                                class=\"el-icon-plus avatar-uploader-icon\"\r\n                                            ></i>\r\n                                        </el-upload>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"col-md-9\">\r\n                                    <div class=\"row\">\r\n                                        <div class=\"col-md-6\">\r\n                                            <div\r\n                                                class=\"form-group\"\r\n                                                :class=\"{\r\n                                                    'has-danger':\r\n                                                        errors.brand_id\r\n                                                }\"\r\n                                            >\r\n                                                <label class=\"control-label\">\r\n                                                    Marca\r\n                                                </label>\r\n\r\n                                                <a\r\n                                                    href=\"#\"\r\n                                                    v-if=\"\r\n                                                        form_brand.add == false\r\n                                                    \"\r\n                                                    class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"\r\n                                                        form_brand.add = true\r\n                                                    \"\r\n                                                >\r\n                                                    [ + Nuevo]</a\r\n                                                >\r\n                                                <a\r\n                                                    href=\"#\"\r\n                                                    v-if=\"\r\n                                                        form_brand.add == true\r\n                                                    \"\r\n                                                    class=\"control-label font-weight-bold text-info\"\r\n                                                    @click=\"saveBrand()\"\r\n                                                >\r\n                                                    [ + Guardar]</a\r\n                                                >\r\n                                                <a\r\n                                                    href=\"#\"\r\n                                                    v-if=\"\r\n                                                        form_brand.add == true\r\n                                                    \"\r\n                                                    class=\"control-label font-weight-bold text-danger\"\r\n                                                    @click=\"\r\n                                                        form_brand.add = false\r\n                                                    \"\r\n                                                >\r\n                                                    [ Cancelar]</a\r\n                                                >\r\n                                                <el-input\r\n                                                    v-if=\"\r\n                                                        form_brand.add == true\r\n                                                    \"\r\n                                                    v-model=\"form_brand.name\"\r\n                                                    dusk=\"item_code\"\r\n                                                    style=\"margin-bottom:1.5%;\"\r\n                                                >\r\n                                                    <i\r\n                                                        slot=\"prefix\"\r\n                                                        class=\"el-icon-edit-outline\"\r\n                                                    ></i\r\n                                                ></el-input>\r\n\r\n                                                <el-select\r\n                                                    v-if=\"\r\n                                                        form_brand.add == false\r\n                                                    \"\r\n                                                    v-model=\"form.brand_id\"\r\n                                                    filterable\r\n                                                    clearable\r\n                                                >\r\n                                                    <el-option\r\n                                                        v-for=\"option in brands\"\r\n                                                        :key=\"option.id\"\r\n                                                        :value=\"option.id\"\r\n                                                        :label=\"option.name\"\r\n                                                    ></el-option>\r\n                                                </el-select>\r\n                                                <small\r\n                                                    class=\"text-danger\"\r\n                                                    v-if=\"errors.brand_id\"\r\n               