                                        <div\r\n                                            v-if=\"form.attributes.length > 0\"\r\n                                            class=\"col-md-12\"\r\n                                        >\r\n                                            <div class=\"table-responsive\">\r\n                                                <table class=\"table\">\r\n                                                    <thead>\r\n                                                        <tr>\r\n                                                            <th>Tipo</th>\r\n                                                            <th>Descripción</th>\r\n                                                            <th></th>\r\n                                                        </tr>\r\n                                                    </thead>\r\n                                                    <tbody>\r\n                                                        <tr\r\n                                                            v-for=\"(row,\r\n                                                            index) in form.attributes\"\r\n                                                            :key=\"index\"\r\n                                                        >\r\n                                                            <td>\r\n                                                                <el-select\r\n                                                                    v-model=\"\r\n                                                                        row.attribute_type_id\r\n                                                                    \"\r\n                                                                    filterable\r\n                                                                    @change=\"\r\n                                                                        changeAttributeType(\r\n                    