                                                         slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"\r\n                                                            ></i\r\n                                                        ></el-input>\r\n\r\n                                                        <!-- <td class=\"text-center\">\r\n                                                        Precio\r\n                                                        {{ row.price_default }}\r\n                                                    </td> -->\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select\r\n                                                            clearable\r\n                                                            v-model=\"\r\n                                                                row.warehouse_id\r\n                                                            \"\r\n                                                        >\r\n                                                            <el-option\r\n                                                                v-for=\"w in warehouses\"\r\n                                                                :key=\"w.id\"\r\n                                                                :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"\r\n                                                            ></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox\r\n                                                            v-model=\"\r\n                                                                row.selected\r\n                                                            \"\r\n                                                            @change=\"\r\n                                                                selectedMax(\r\n                                                                    index\r\n                                                                )\r\n                                                            \"\r\n                                                        ></el-checkbox>\r\n                                                    </td>\r\n\r\n                                                    <td\r\n                                                        class=\"series-table-actions text-end\"\r\n                                                    >\r\n                                                        <button\r\n                                                            type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickDelete(\r\n                                                                    row.id\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                class=\"fa fa-trash\"\r\n                                                            ></i>\r\n                                                        </button>\r\n                                                    </td>\r\n                                                </template>\r\n                                                <template v-else>\r\n                                                    <td>\r\n                                                        <div class=\"form-group\">\r\n                                                            <el-select\r\n                                                                v-model=\"\r\n                                                                    row.unit_type_id\r\n                                                                \"\r\n                                                                dusk=\"item_unit_type.unit_type_id\"\r\n                                                            >\r\n                                                                <el-option\r\n                                                                    v-for=\"option in unit_types\"\r\n                                                                    :key=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :value=\"\r\n                                                                        option.id\r\n                                                                    \"\r\n                                                                    :label=\"\r\n                                                                        option.description\r\n                                                                    \"\r\n                                                                ></el-option>\r\n                                                            </el-select>\r\n                                                        </div>\r\n                                        