                  class=\"form-group\"\r\n                            :class=\"{\r\n                                'has-danger': errors.identity_document_type_id\r\n                            }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Tipo Doc. Identidad\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.identity_document_type_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-identity_document_type\"\r\n                                dusk=\"identity_document_type_id\"\r\n                                @change=\"changeIdentityDocType\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in identity_document_types\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.identity_document_type_id\"\r\n                                v-text=\"errors.identity_document_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.number }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Número\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n\r\n                            <div v-if=\"api_service_token != false\">\r\n                                <x-input-service\r\n                                    :identity_document_type_id=\"\r\n                                        form.identity_document_type_id\r\n                                    \"\r\n                                    v-model=\"form.number\"\r\n                                    @search=\"searchNumber\"\r\n                                ></x-input-service>\r\n                            </div>\r\n                            <div v-else>\r\n                                <el-input\r\n                                    v-model=\"form.number\"\r\n                                    :maxlength=\"maxLength\"\r\n                                    dusk=\"number\"\r\n                                >\r\n                                    <template\r\n                                        v-if=\"\r\n                                            form.identity_document_type_id ===\r\n                                                '6' ||\r\n                                                form.identity_document_type_id ===\r\n                                                    '1'\r\n                                        \"\r\n                                    >\r\n                                        <el-button\r\n                                            type=\"primary\"\r\n                                            slot=\"append\"\r\n                                            :loading=\"loading_search\"\r\n                                            icon=\"el-icon-search\"\r\n                                            @click.prevent=\"searchCustomer\"\r\n                                        >\r\n                                        </el-button>\r\n                                    </template>\r\n                                    <i\r\n                                        slot=\"prefix\"\r\n                                        class=\"el-icon-edit-outline\"\r\n                                    ></i\r\n                                ></el-input>\r\n                            </div>\r\n\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.number\"\r\n                                v-text=\"errors.number[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-input v-model=\"form.name\" dusk=\"name\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.name\"\r\n                                v-text=\"errors.name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.trade_name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre comercial</label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.trade_name\"\r\n                                dusk=\"trade_name\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.trade_name\"\r\n                                v-text=\"errors.trade_name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <!-- <div class=\"row\" v-if=\"type === 'customers'\">\r\n                    <div class=\"col-md-4\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.person_type_id}\">\r\n                            <label class=\"control-label\">Tipo de cliente</label>\r\n                            <el-select v-model=\"form.person_type_id\" filterable  >\r\n                                <el-option v-for=\"option in person_types\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"text-danger\" v-if=\"errors.person_type_id\" v-text=\"errors.person_type_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div class=\"form-group\"  >\r\n                            <label class=\"control-label\">Comentario</label>\r\n                            <el-input v-model=\"form.comment\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div> -->\r\n\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select\r\n                                v-model=\"form.country_id\"\r\n                                filterable\r\n                                dusk=\"country_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.department_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Departamento</label>\r\n                            <el-select\r\n                                v-model=\"form.department_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                                popper-class=\"el-select-departments\"\r\n                                dusk=\"department_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_departments\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.department_id\"\r\n                                v-text=\"errors.department_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Provincia</label>\r\n                            <el-select\r\n                                v-model=\"form.province_id\"\r\n                                filterable\r\n                                @change=\"filterDistrict\"\r\n                                popper-class=\"el-select-provinces\"\r\n                                dusk=\"province_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in provinces\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.province_id\"\r\n                                v-text=\"errors.province_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Distrito</label>\r\n                            <el-select\r\n                                v-model=\"form.district_id\"\r\n                                filterable\r\n                                popper-class=\"el-select-districts\"\r\n                                dusk=\"district_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in districts\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.district_id\"\r\n                                v-text=\"errors.district_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"form.address\" dusk=\"address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <!-- create a select with options of zones -->\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.client_zone_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Zona</label>\r\n                            <el-select\r\n                                v-model=\"form.client_zone_id\"\r\n                                filterable\r\n                                dusk=\"client_zone_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in zones\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.client_zone_id\"\r\n                                v-text=\"errors.client_zone_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.telephone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"form.telephone\" dusk=\"telephone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.telephone\"\r\n                                v-text=\"errors.telephone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"form.email\" dusk=\"email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\" v-if=\"form.state\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Estado del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.state == 'ACTIVO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\" v-if=\"form.condition\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Condición del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.condition == 'HABIDO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row mt-2\" v-if=\"type === 'suppliers'\">\r\n                    <div class=\"col-md-6 center-el-checkbox\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.perception_agent }\"\r\n                        >\r\n                            <el-checkbox v-model=\"form.perception_agent\"\r\n                                >¿Es agente de percepción?</el-checkbox\r\n                            ><br />\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.perception_agent\"\r\n                                v-text=\"errors.perception_agent[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-md-6\"\r\n                        v-if=\"type === 'suppliers'\"\r\n                        v-show=\"form.perception_agent\"\r\n                    >\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Porcentaje de percepción</label\r\n                            >\r\n\r\n                            <el-input v-model=\"form.percentage_perception\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div\r\n                    class=\"row m-t-10\"\r\n                    v-for=\"(row, index) in form.addresses\"\r\n                    :key=\"index\"\r\n                >\r\n                    <div class=\"col-md-12\">\r\n                        <label class=\"control-label\" v-if=\"index === 0\">\r\n                            Dirección principal\r\n                        </label>\r\n                        <label class=\"control-label\" v-else>\r\n                            Dirección secundaria # {{ index }}\r\n                            <el-button\r\n                                size=\"mini\"\r\n                                icon=\"el-icon-minus\"\r\n                                @click.prevent=\"clickRemoveAddress(index)\"\r\n                                class=\"btn-default-danger\"\r\n                                >Eliminar dirección</el-button\r\n                            >\r\n                        </label>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select v-model=\"row.country_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.location_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader\r\n                                :options=\"locations\"\r\n                                v-model=\"row.location_id\"\r\n                                :clearable=\"true\"\r\n                                filterable\r\n                            ></el-cascader>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.location_id\"\r\n                                v-text=\"errors.location_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"row.address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.phone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"row.phone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.phone\"\r\n                                v-text=\"errors.phone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"row.email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    