                </div> -->\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport { serviceNumber } from \"../../mixins/functions\";\r\n\r\nexport default {\r\n    mixins: [serviceNumber],\r\n    props: [\r\n        \"worker\",\r\n        \"showDialog\",\r\n        \"type\",\r\n        \"recordId\",\r\n        \"external\",\r\n        \"document_type_id\",\r\n        \"input_person\",\r\n        \"user_id\",\r\n        \"newTech\"\r\n    ],\r\n    data() {\r\n        return {\r\n            zones: [],\r\n            social_medias: [],\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: this.worker ? \"restaurant/worker/persons\" : \"persons\",\r\n            errors: {},\r\n            api_service_token: false,\r\n            form: {},\r\n            countries: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            locations: [],\r\n            person_types: [],\r\n            identity_document_types: [],\r\n            all_users: []\r\n        };\r\n    },\r\n    async created() {\r\n        console.log(this.newTech, \" a\");\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.api_service_token = response.data.api_service_token;\r\n            this.social_medias = response.data.social_media;\r\n            this.all_users = response.data.users;\r\n            this.countries = response.