type === \"suppliers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Proveedor\"\r\n                    : \"Nuevo Proveedor\";\r\n            }\r\n\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.filterProvinces();\r\n                        this.filterDistricts();\r\n                    });\r\n            }\r\n        },\r\n        clickAddAddress() {\r\n            /* this.form.more_address.push({\r\n                    location_id: [],\r\n                    address: null,\r\n                })*/\r\n\r\n            this.form.addresses.push({\r\n                id: null,\r\n                country_id: \"PE\",\r\n                location_id: [],\r\n                address: null,\r\n                email: null,\r\n                phone: null,\r\n                main: false\r\n            });\r\n        },\r\n        submit() {\r\n            this.nuevoMetodo();\r\n            if (!this.form.seller_id) {\r\n                this.$toast.error(\"Debe seleccionar un asesor\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"6\" &&\r\n                this.form.number.length != 11\r\n            ) {\r\n                this.$toast.error(\"La longitud del RUC debe ser de 11\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"1\" &&\r\n                this.form.number.length != 8\r\n            ) {\r\n                this.$toast.error(\"La longitud del DNI debe ser de 8\");\r\n                return;\r\n            }\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .the