                                  'has-danger':\r\n                                        errors.transfer_reason_description\r\n                                }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Descripción de motivo de traslado</label\r\n                                >\r\n                                <el-input\r\n                                    v-model=\"form.transfer_reason_description\"\r\n                                    :rows=\"3\"\r\n                                    maxlength=\"100\"\r\n                                    placeholder=\"Descripción de motivo de traslado...\"\r\n                                    type=\"textarea\"\r\n                                ></el-input>\r\n                                <small\r\n                                    v-if=\"errors.transfer_reason_description\"\r\n                                    class=\"form-control-feedback\"\r\n                                    v-text=\"\r\n                                        errors.transfer_reason_description[0]\r\n                                    \"\r\n                                ></small>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"row\">\r\n                        <div class=\"col-lg-2\">\r\n                            <div\r\n                                :class=\"{ 'has-danger': errors.unit_type_id }\"\r\n                                class=\"form-group\"\r\n                            >\r\n                                <label class=\"control-label\"\r\n                                    >Unidad de medida<span class=\"text-danger\">\r\n                                        *</span\r\n                                    ></label\r\n                                >\r\n                   