ext=\"Predeterminado\"\r\n                         inactive-text=\"\"></el-switch>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n      <div class=\"form-actions text-right mt-4\">\r\n        <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n        <el-button :loading=\"loading_submit\"\r\n                   native-type=\"submit\"\r\n                   type=\"primary\">Guardar\r\n        </el-button>\r\n      </div>\r\n    </form>\r\n  </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\nexport default {\r\n  name: 'DispatchTransportForm',\r\n  props: ['showDialog', 'recordId', 'external'],\r\n  data() {\r\n    return {\r\n      loading_submit: false,\r\n      titleDialog: null,\r\n      resource: 'transports',\r\n      errors: {},\r\n      form: {},\r\n    }\r\n  },\r\n  created() {\r\n    this.initForm()\r\n  },\r\n  methods: {\r\n    initForm() {\r\n      this.errors = {}\r\n      this.form = {\r\n        id: null,\r\n        plate_number: null,\r\n        model: null,\r\n        brand: null,\r\n        is_default: false,\r\n        is_active: true,\r\n      }\r\n    },\r\n    async create() {\r\n      this.initForm();\r\n      this.titleDialog = (this.recordId) ? 'Editar Vehículo' : 'Nuevo Vehículo'\r\n      if (this.recordId) {\r\n        await this.$http.get(`/${this.resource}/record/${this.recordId}`)\r\n            .then(response => {\r\n              this.form = response.data.data\r\n            })\r\n      }\r\n    },\r\n    async submit() {\r\n      this.loading_submit = true\r\n      await this.$http.post(`/${this.resource}`, this.form)\r\n          .then(response => {\r\n            if (response.data.success) {\r\n              this.$message.success(response.data.message)\r\n              this.$emit('success', response.data.id)\r\n              this.close()\r\n            } else {\r\n              this.$message.error(response.data.message)\r\n            }\r\n          })\r\n          .catch(error => {\r\n            if (error.response.status === 422) {\r\n              this.errors = error.response.data\r\n            } else {\r\n              console.log(error)\r\n            }\r\n          })\r\n          .then(() => {\r\n            this.loading_submit = false\r\n          })\r\n    },\r\n    close() {\r\n      this.$emit('update:showDialog', false)\r\n    },\r\n  }\r\n}\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/dispatches/transports/form.vue","<template>\r\n  <el-dialog\r\n    :title=\"titleDialog\"\r\n    width=\"40%\"\r\n    :visible=\"showDialog\"\r\n    @open=\"create\"\r\n    :close-on-click-modal=\"false\"\r\n    :close-on-press-escape=\"false\"\r\n    append-to-body\r\n    :show-close=\"false\"\r\n  >\r\n    <div class=\"form-body\">\r\n      <div class=\"row\">\r\n        <div class=\"col-lg-12 col-md-12\">\r\n          <table class=\"table\">\r\n            <thead>\r\n              <tr>\r\n                <th>Seleccionado</th>\r\n                <th>codigo</th>\r\n                <th>Cantidad</th>\r\n                <th class>Fecha vencimiento</th>\r\n              </tr>\r\n            </thead>\r\n            <tbody>\r\n              <tr v-for=\"(row, index) in lots_group\" :key=\"index\" v-show=\"row.quantity > 0\">\r\n                <th align=\"center\">\r\n                  <el-checkbox\r\n                    :disabled=\"row.quantity  < 1\"\r\n                    v-model=\"row.checked\"\r\n                    @change=\"changeSelect(index, row.id, row.quantity)\"\r\n                  ></el-checkbox>\r\n                </th>\r\n                <th>{{ row.code }}</th>\r\n                <th class>{{ row.quantity }}</th>\r\n                <th class>{{ row.date_of_due }}</th>\r\n              </tr>\r\n            </tbody>\r\n          </table>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n   <div class=\"form-actions text-end pt-2 pb-2\">\r\n      <el-button @click.prevent=\"close()\">Cerrar</el-button>\r\n      <el-button type=\"primary\" @click=\"submit\">Guardar</el-button>\r\n    </div>\r\n  </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n  props: [\"showDialog\", \"lots_group\", \"stock\", \"recordId\", \"quantity\"],\r\n  data() {\r\n    return {\r\n      titleDialog: \"Lotes\",\r\n      loading: false,\r\n      errors: {},\r\n      form: {},\r\n      states: [\"Activo\", \"Inactivo\", \"Desactivado\", \"Voz\", \"M2m\"],\r\n      idSelected: null\r\n    };\r\n  },\r\n  async created() {\r\n    // await this.$http.get(`/pos/payment_tables`)\r\n    //     .then(response => {\r\n    //         this.payment_method_types = response.data.payment_method_types\r\n    //         this.cards_brand = response.data.cards_brand\r\n    //         this.clickAddLot()\r\n    //     })\r\n  },\r\n  methods: {\r\n    changeSelect(index, id, quantity_lot) {\r\n        \r\n      if (this.quantity > quantity_lot) {\r\n\r\n        this.lots_group[index].checked = false;\r\n       \r\n      } else {\r\n        this.lots_group.forEach(row => {\r\n          row.checked = false;\r\n        });\r\n\r\n        this.lots_group[index].checked = true;\r\n\r\n        this.idSelected = id;\r\n      }\r\n    },\r\n    handleSelectionChange(val) {\r\n      //this.$refs.multipleTable.clearSelection();\r\n      let row = val[val.length - 1];\r\n      this.multipleSelection = [row];\r\n    },\r\n    create() {},\r\n\r\n    async submit() {\r\n      await this.$emit(\"addRowLotGroup\", this.idSelected);\r\n      await this.$emit(\"update:showDialog\", false);\r\n    },\r\n\r\n    clickCancel(item) {\r\n      //this.lots.splice(index, 1);\r\n      item.deleted = true;\r\n      this.$emit(\"addRowLotGroup\", this.lots);\r\n    },\r\n\r\n    async clickCancelSubmit() {\r\n      this.$emit(\"addRowLotGroup\", []);\r\n      await this.$emit(\"update:showDialog\", false);\r\n    },\r\n    close() {\r\n      this.$emit(\"update:showDialog\", false);\r\n    }\r\n  }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER