     </el-tab-pane>\r\n                    <el-tab-pane\r\n                        v-if=\"form.unit_type_id != 'ZZ'\"\r\n                        label=\"Almacenes\"\r\n                    >\r\n                        <div class=\"row\">\r\n                            <div class=\"col-12\">\r\n                                <h5 class=\"separator-title mt-0\">\r\n                                    Precios por almacén\r\n                                </h5>\r\n                                <table>\r\n                                    <tbody>\r\n                                        <tr\r\n                                            v-for=\"w in form.warehouse_prices\"\r\n                                            :key=\"w.id\"\r\n                                        >\r\n                                            <td width=\"80%\">\r\n                                                <h3>{{ w.warehouse }}</h3>\r\n                                            </td>\r\n                                            <td>\r\n                                                <el-input\r\n                                                    v-model=\"w.price\"\r\n                                                    @input=\"$forceUpdate()\"\r\n                                                    placeholder=\"Precio de almacen\"\r\n                                                >\r\n                                                </el-input>\r\n                                            </td>\r\n                                        </tr>\r\n                                    </tbody>\r\n                                </table>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane label=\"Lista de Precios\">\r\n                        <div class=\"row\">\r\n                            <div\r\n                                v-show=\"form.unit_type_id != 'ZZ'\"\r\n              