"\r\n                                v-text=\"errors.client_zone_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.telephone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"form.telephone\" dusk=\"telephone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.telephone\"\r\n                                v-text=\"errors.telephone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"form.email\" dusk=\"email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\" v-if=\"form.state\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Estado del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.state == 'ACTIVO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.state}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\" v-if=\"form.condition\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Condición del Contribuyente</label\r\n                            >\r\n                            <template v-if=\"form.condition == 'HABIDO'\">\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"success\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-alert\r\n                                    :title=\"`${form.condition}`\"\r\n                                    type=\"error\"\r\n                                    show-icon\r\n                                    :closable=\"false\"\r\n                                ></el-alert>\r\n                            </template>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row mt-2\" v-if=\"type === 'suppliers'\">\r\n                    <div class=\"col-md-6 center-el-checkbox\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.perception_agent }\"\r\n                        >\r\n                            <el-checkbox v-model=\"form.perception_agent\"\r\n                                >¿Es agente de percepción?</el-checkbox\r\n                            ><br />\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.perception_agent\"\r\n                                v-text=\"errors.perception_agent[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-md-6\"\r\n                        v-if=\"type === 'suppliers'\"\r\n                        v-show=\"form.perception_agent\"\r\n                    >\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\"\r\n                                >Porcentaje de percepción</label\r\n                            >\r\n\r\n                            <el-input v-model=\"form.percentage_perception\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n\r\n                <div\r\n                    class=\"row m-t-10\"\r\n                    v-for=\"(row, index) in form.addresses\"\r\n                    :key=\"index\"\r\n                >\r\n                    <div class=\"col-md-12\">\r\n                        <label class=\"control-label\" v-if=\"index === 0\">\r\n                            Dirección principal\r\n                        </label>\r\n                        <label class=\"control-label\" v-else>\r\n                            Dirección secundaria # {{ index }}\r\n                            <el-button\r\n                                size=\"mini\"\r\n                                icon=\"el-icon-minus\"\r\n                                @click.prevent=\"clickRemoveAddress(index)\"\r\n                                class=\"btn-default-danger\"\r\n                                >Eliminar dirección</el-button\r\n                            >\r\n                        </label>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select v-model=\"row.country_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.location_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Ubigeo</label>\r\n                            <el-cascader\r\n                                :options=\"locations\"\r\n                                v-model=\"row.location_id\"\r\n                                :clearable=\"true\"\r\n                                filterable\r\n                            ></el-cascader>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.location_id\"\r\n                                v-text=\"errors.location_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección</label>\r\n                            <el-input v-model=\"row.address\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.phone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"row.phone\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.phone\"\r\n                                v-text=\"errors.phone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo electrónico</label\r\n                            >\r\n                            <el-input v-model=\"row.email\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <!-- <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Llegó de</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Cat Vip</label>\r\n                        <el-select clearable v-model=\"form.social_media_id\">\r\n                            <el-option\r\n                                v-for=\"(dta, idx) in social_medias\"\r\n                                :key=\"idx\"\r\n                                :label=\"dta.description\"\r\n                                :value=\"dta.id\"\r\n                            >\r\n                            </el-option>\r\n                        </el-select>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <label class=\"control-label\">Mensualidad</label>\r\n                        <el-input clearable v-model=\"form.vip_amount\" />\r\n                    </div>\r\n                </div> -->\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport { serviceNumber } from \"../../mixins/functions\";\r\n\r\nexport default {\r\n    mixins: [serviceNumber],\r\n    props: [\r\n        \"worker\",\r\n        \"showDialog\",\r\n        \"type\",\r\n        \"recordId\",\r\n        \"external\",\r\n        \"document_type_id\",\r\n        \"input_person\",\r\n        \"user_id\",\r\n        \"newTech\"\r\n    ],\r\n    data() {\r\n        return {\r\n            zones: [],\r\n            social_medias: [],\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: this.worker ? \"restaurant/worker/persons\" : \"persons\",\r\n            errors: {},\r\n            api_service_token: false,\r\n            form: {},\r\n            countries: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            locations: [],\r\n            person_types: [],\r\n            identity_document_types: [],\r\n            all_users: []\r\n        };\r\n    },\r\n    async created() {\r\n        console.log(this.newTech, \" a\");\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.api_service_token = response.data.api_service_token;\r\n            this.social_medias = response.data.social_media;\r\n            this.all_users = response.data.users;\r\n            this.countries = response.data.countries;\r\n            this.all_departments = response.data.departments;\r\n            this.all_provinces = response.data.provinces;\r\n            this.zones = response.data.zones;\r\n            this.all_districts = response.data.districts;\r\n            this.identity_document_types =\r\n                response.data.identity_document_types;\r\n            this.locations = response.data.locations;\r\n            this.person_types = response.data.person_types;\r\n        });\r\n    },\r\n    computed: {\r\n        maxLength: function() {\r\n            if (this.form.identity_document_type_id === \"6\") {\r\n                return 11;\r\n            }\r\n            if (this.form.identity_document_type_id === \"1\") {\r\n                return 8;\r\n            }\r\n        }\r\n    },\r\n    methods: {\r\n        nuevoMetodo() {\r\n            let admin = this.all_users.find(user => user.type == \"admin\");\r\n            if (admin) {\r\n                this.form.seller_id = admin.id;\r\n            } else {\r\n                if (this.all_users.length != 0) {\r\n                    this.form.seller_id = this.all_users[0].id;\r\n                }\r\n            }\r\n        },\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                type: this.type,\r\n                identity_document_type_id: \"6\",\r\n                number: \"\",\r\n                name: null,\r\n                trade_name: null,\r\n                country_id: \"PE\",\r\n                department_id: null,\r\n                province_id: null,\r\n                district_id: null,\r\n                address: null,\r\n                telephone: null,\r\n                condition: null,\r\n                state: null,\r\n                email: null,\r\n                perception_agent: false,\r\n                percentage_perception: 0,\r\n                person_type_id: null,\r\n                comment: null,\r\n                addresses: [],\r\n                seller_id: null\r\n            };\r\n        },\r\n        async opened() {\r\n            // this.form.seller_id = this.user_id;\r\n            if (this.external && this.input_person) {\r\n                if (\r\n                    this.form.number.length === 8 ||\r\n                    this.form.number.length === 11\r\n                ) {\r\n                    if (this.api_service_token != false) {\r\n                        await this.$eventHub.$emit(\"enableClickSearch\");\r\n                    } else {\r\n                        this.searchCustomer();\r\n                    }\r\n                }\r\n            }\r\n        },\r\n        create() {\r\n            if (this.external) {\r\n                if (this.document_type_id === \"01\") {\r\n                    this.form.identity_document_type_id = \"6\";\r\n                }\r\n                if (this.document_type_id === \"03\") {\r\n                    this.form.identity_document_type_id = \"1\";\r\n                }\r\n\r\n                if (this.input_person) {\r\n                    this.form.identity_document_type_id = this.input_person\r\n                        .identity_document_type_id\r\n                        ? this.input_person.identity_document_type_id\r\n                        : this.form.identity_document_type_id;\r\n                    this.form.number = this.input_person.number\r\n                        ? this.input_person.number\r\n                        : \"\";\r\n                }\r\n            }\r\n\r\n            if (this.type == undefined) {\r\n                this.titleDialog = this.newTech\r\n                    ? \"Nuevo Técnico\"\r\n                    : \"Nuevo Cliente\";\r\n            }\r\n            if (this.type === \"customers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Cliente\"\r\n                    : \"Nuevo Cliente\";\r\n            }\r\n            if (this.type === \"suppliers\") {\r\n                this.titleDialog = this.recordId\r\n                    ? \"Editar Proveedor\"\r\n                    : \"Nuevo Proveedor\";\r\n            }\r\n\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.filterProvinces();\r\n                        this.filterDistricts();\r\n                    });\r\n            }\r\n        },\r\n        clickAddAddress() {\r\n            /* this.form.more_address.push({\r\n                    location_id: [],\r\n                    address: null,\r\n                })*/\r\n\r\n            this.form.addresses.push({\r\n                id: null,\r\n                country_id: \"PE\",\r\n                location_id: [],\r\n                address: null,\r\n                email: null,\r\n                phone: null,\r\n                main: false\r\n            });\r\n        },\r\n        submit() {\r\n            this.nuevoMetodo();\r\n            if (!this.form.seller_id) {\r\n                this.$toast.error(\"Debe seleccionar un asesor\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"6\" &&\r\n                this.form.number.length != 11\r\n            ) {\r\n                this.$toast.error(\"La longitud del RUC debe ser de 11\");\r\n                return;\r\n            }\r\n            if (\r\n                this.form.identity_document_type_id == \"1\" &&\r\n                this.form.number.length != 8\r\n            ) {\r\n                this.$toast.error(\"La longitud del DNI debe ser de 8\");\r\n                return;\r\n            }\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$emit(\"add_customer\", response.data.id);\r\n                        if (this.external) {\r\n                            this.$eventHub.$emit(\r\n                                \"reloadDataPersons\",\r\n                                response.data.id\r\n                            );\r\n                        } else {\r\n                            this.$eventHub.$emit(\"reloadData\");\r\n                        }\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        console.log(error.response.data.errors);\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        changeIdentityDocType() {\r\n            this.recordId == null ? this.setDataDefaultCustomer() : null;\r\n        },\r\n        setDataDefaultCustomer() {\r\n            if (this.form.identity_document_type_id == \"0\") {\r\n                this.form.number = \"99999999\";\r\n                this.form.name = \"Clientes - Varios\";\r\n            } else {\r\n                this.form.number = \"\";\r\n                this.form.name = null;\r\n            }\r\n        },\r\n        close() {\r\n            this.$eventHub.$emit(\"initInputPerson\");\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        },\r\n        searchCustomer() {\r\n            this.searchServiceNumberByType();\r\n        },\r\n\r\n        searchNumber(data) {\r\n            this.form.district_id = data.ubigeo[2];\r\n            this.filterDistricts();\r\n            this.form.name =\r\n                this.form.identity_document_type_id === \"1\"\r\n                    ? data.nombre_completo\r\n                    : data.nombre_o_razon_social;\r\n            this.form.trade_name =\r\n                this.form.identity_document_type_id === \"6\"\r\n                    ? data.nombre_o_razon_social\r\n                    : \"\";\r\n            this.form.location_id = data.ubigeo;\r\n            this.form.department_id = data.ubigeo ? data.ubigeo[0] : null;\r\n            this.form.province_id = data.ubigeo ? data.ubigeo[1] : null;\r\n            this.form.district_id = data.ubigeo ? data.ubigeo[2] : null;\r\n            this.filterProvinces();\r\n            this.filterDistricts();\r\n            this.form.address = data.direccion;\r\n            this.form.condition = data.condicion;\r\n            this.form.state = data.estado;\r\n        },\r\n        clickRemoveAddress(index) {\r\n            this.form.addresses.splice(index, 1);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/persons/form.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      attrs: {\n        title: _vm.titleDialog,\n        visible: _vm.dialogVisible,\n        \"append-to-body\": \"\",\n        top: \"8vh\"\n      },\n      on: { open: _vm.create, close: _vm.close }\n    },\n    [\n      _c(\"div\", { staticClass: \"form-body\" }, [\n        _c(\n          \"div\",\n          { staticClass: \"row\" },\n          [\n            _c(\"div\", { staticClass: \"col-md-6\" }, [\n              _c(\n                \"div\",\n                {\n                  staticClass: \"form-group\",\n                  class: { \"has-danger\": _vm.errors.items }\n  